	private function get_ajcore_table_inventory() {
		global $wpdb;

		$tables = array();
		foreach ( array( 'aj_forms_', 'aj_portal_', 'aj_crm_', 'aj_auto_', 'aj_auth_' ) as $prefix ) {
			$matches = $wpdb->get_col( $wpdb->prepare( 'SHOW TABLES LIKE %s', $wpdb->esc_like( $wpdb->prefix . $prefix ) . '%' ) );
			$tables = array_merge( $tables, (array) $matches );
		}
		$tables = array_values( array_filter( array_map( 'sanitize_text_field', (array) $tables ) ) );
		$tables = array_values( array_unique( $tables ) );
		sort( $tables );

		$inventory = array();
		foreach ( $tables as $table ) {
			$inventory[] = array(
				'table' => $table,
				'rows'  => absint( $wpdb->get_var( "SELECT COUNT(*) FROM {$table}" ) ),
			);
		}

		return $inventory;
	}

	private function get_portal_product_catalog_settings( $stripe_product_id ) {
		$wpdb = $this->get_pdb();

		$stripe_product_id = sanitize_text_field( (string) $stripe_product_id );
		if ( '' === $stripe_product_id ) {
			return null;
		}

		return $wpdb->get_row(
			$wpdb->prepare(
				"SELECT * FROM {$this->get_portal_product_catalog_table()} WHERE stripe_product_id = %s LIMIT 1",
				$stripe_product_id
			)
		);
	}

	private function upsert_portal_product_catalog_settings( $stripe_product_id, $settings ) {
		$wpdb = $this->get_pdb();

		$stripe_product_id = sanitize_text_field( (string) $stripe_product_id );
		if ( '' === $stripe_product_id || ! is_array( $settings ) ) {
			return false;
		}

		$allowed_duplicate_behaviors = array( 'no_duplicates', 'allow_duplicate', 'custom_request', 'upgrade' );
		$visibility = isset( $settings['visibility'] ) && 'visible' === sanitize_key( (string) $settings['visibility'] ) ? 'visible' : 'hidden';
		$duplicate_behavior = isset( $settings['duplicate_behavior'] ) ? sanitize_key( (string) $settings['duplicate_behavior'] ) : 'no_duplicates';
		if ( ! in_array( $duplicate_behavior, $allowed_duplicate_behaviors, true ) ) {
			$duplicate_behavior = 'no_duplicates';
		}

		$price_settings = isset( $settings['price_settings'] ) && is_array( $settings['price_settings'] ) ? $settings['price_settings'] : array();
		$clean_price_settings = array();
		foreach ( $price_settings as $price_id => $price_setting ) {
			$price_id = sanitize_text_field( (string) $price_id );
			if ( '' === $price_id || ! is_array( $price_setting ) ) {
				continue;
			}
			$requires_price_id = isset( $price_setting['requires_price_id'] ) ? sanitize_text_field( (string) $price_setting['requires_price_id'] ) : '';
			$dependency_note   = isset( $price_setting['dependency_note'] ) ? sanitize_textarea_field( (string) $price_setting['dependency_note'] ) : '';
			if ( '' === $requires_price_id && '' === $dependency_note ) {
				continue;
			}
			$clean_price_settings[ $price_id ] = array(
				'requires_price_id' => $requires_price_id,
				'dependency_note'   => $dependency_note,
			);
		}

		$product_type = isset( $settings['product_type'] ) && 'reservation' === sanitize_key( (string) $settings['product_type'] ) ? 'reservation' : 'normal';

		$data = array(
			'stripe_product_id'                   => $stripe_product_id,
			'visibility'                          => $visibility,
			'custom_label'                        => isset( $settings['custom_label'] ) ? sanitize_text_field( (string) $settings['custom_label'] ) : '',
			'sort_order'                          => isset( $settings['sort_order'] ) ? intval( $settings['sort_order'] ) : 0,
			'description_override'                => isset( $settings['description_override'] ) ? sanitize_textarea_field( (string) $settings['description_override'] ) : '',
			'duplicate_behavior'                  => $duplicate_behavior,
			'upgrade_from_product_id'             => isset( $settings['upgrade_from_product_id'] ) ? sanitize_text_field( (string) $settings['upgrade_from_product_id'] ) : '',
			'custom_request_title'                => isset( $settings['custom_request_title'] ) ? sanitize_text_field( (string) $settings['custom_request_title'] ) : '',
			'custom_request_message'              => isset( $settings['custom_request_message'] ) ? sanitize_textarea_field( (string) $settings['custom_request_message'] ) : '',
			'custom_request_button_label'         => isset( $settings['custom_request_button_label'] ) ? sanitize_text_field( (string) $settings['custom_request_button_label'] ) : '',
			'price_settings'                      => ! empty( $clean_price_settings ) ? wp_json_encode( $clean_price_settings ) : '',
			'product_type'                        => $product_type,
			'reservation_resource_id'             => isset( $settings['reservation_resource_id'] ) ? absint( $settings['reservation_resource_id'] ) : 0,
			'reservation_resource_key'            => isset( $settings['reservation_resource_key'] ) ? sanitize_key( (string) $settings['reservation_resource_key'] ) : '',
			'reservation_business_hours_price_id' => isset( $settings['reservation_business_hours_price_id'] ) ? sanitize_text_field( (string) $settings['reservation_business_hours_price_id'] ) : '',
			'reservation_after_hours_price_id'    => isset( $settings['reservation_after_hours_price_id'] ) ? sanitize_text_field( (string) $settings['reservation_after_hours_price_id'] ) : '',
			'reservation_duration_minutes'        => isset( $settings['reservation_duration_minutes'] ) ? absint( $settings['reservation_duration_minutes'] ) : 60,
			'reservation_buffer_before_minutes'   => isset( $settings['reservation_buffer_before_minutes'] ) ? absint( $settings['reservation_buffer_before_minutes'] ) : 0,
			'reservation_buffer_after_minutes'    => isset( $settings['reservation_buffer_after_minutes'] ) ? absint( $settings['reservation_buffer_after_minutes'] ) : 0,
			'reservation_min_duration_minutes'    => isset( $settings['reservation_min_duration_minutes'] ) ? absint( $settings['reservation_min_duration_minutes'] ) : 60,
			'reservation_max_duration_minutes'    => isset( $settings['reservation_max_duration_minutes'] ) ? absint( $settings['reservation_max_duration_minutes'] ) : 60,
			'reservation_zoho_calendar_uid'       => isset( $settings['reservation_zoho_calendar_uid'] ) ? sanitize_text_field( (string) $settings['reservation_zoho_calendar_uid'] ) : '',
			'reservation_zoho_calendar_id'        => isset( $settings['reservation_zoho_calendar_id'] ) ? sanitize_text_field( (string) $settings['reservation_zoho_calendar_id'] ) : '',
			'reservation_zoho_resource_uid'       => isset( $settings['reservation_zoho_resource_uid'] ) ? sanitize_text_field( (string) $settings['reservation_zoho_resource_uid'] ) : '',
			'reservation_zoho_schedule_url'       => isset( $settings['reservation_zoho_schedule_url'] ) ? esc_url_raw( (string) $settings['reservation_zoho_schedule_url'] ) : '',
			'reservation_zoho_freebusy_url'       => isset( $settings['reservation_zoho_freebusy_url'] ) ? esc_url_raw( (string) $settings['reservation_zoho_freebusy_url'] ) : '',
		);

		$base_formats = array( '%s', '%s', '%s', '%d', '%s', '%s', '%s', '%s', '%s', '%s', '%s' );
		$res_formats  = array( '%s', '%d', '%s', '%s', '%s', '%d', '%d', '%d', '%d', '%d', '%s', '%s', '%s', '%s', '%s' );
		$formats = array_merge( $base_formats, $res_formats );

		$existing_id = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT id FROM {$this->get_portal_product_catalog_table()} WHERE stripe_product_id = %s LIMIT 1",
				$stripe_product_id
			)
		);

		if ( $existing_id ) {
			return false !== $wpdb->update(
				$this->get_portal_product_catalog_table(),
				$data,
				array( 'id' => absint( $existing_id ) ),
				$formats,
				array( '%d' )
			);
		}

		return false !== $wpdb->insert(
			$this->get_portal_product_catalog_table(),
			$data,
			$formats
		);
	}

	private function backup_ajcore_tables() {
		global $wpdb;

		$this->ensure_portal_schema();

		$inventory = $this->get_ajcore_table_inventory();
		$upload_dir = wp_upload_dir();
		if ( ! empty( $upload_dir['error'] ) ) {
			return new WP_Error( 'backup_upload_dir_failed', $upload_dir['error'] );
		}

		$backup_dir = trailingslashit( $upload_dir['basedir'] ) . 'ajcore-backups';
		if ( ! wp_mkdir_p( $backup_dir ) ) {
			return new WP_Error( 'backup_dir_failed', __( 'Could not create AJ Core backup directory.', 'ajforms' ) );
		}

		if ( ! file_exists( trailingslashit( $backup_dir ) . 'index.php' ) ) {
			file_put_contents( trailingslashit( $backup_dir ) . 'index.php', "<?php\n// Silence is golden.\n" );
		}
		if ( ! file_exists( trailingslashit( $backup_dir ) . '.htaccess' ) ) {
			file_put_contents( trailingslashit( $backup_dir ) . '.htaccess', "Deny from all\n" );
		}

		$backup = array(
			'created_at' => current_time( 'mysql' ),
			'site_url'   => home_url( '/' ),
			'tables'     => array(),
		);

		foreach ( $inventory as $item ) {
			$table = $item['table'];
			$backup['tables'][ $table ] = array(
				'row_count' => absint( $item['rows'] ),
				'columns'   => $wpdb->get_results( "SHOW COLUMNS FROM {$table}", ARRAY_A ),
				'rows'      => $wpdb->get_results( "SELECT * FROM {$table}", ARRAY_A ),
			);
		}

		$filename = 'ajcore-tables-backup-' . gmdate( 'Ymd-His' ) . '-' . wp_generate_password( 8, false, false ) . '.json';
		$path = trailingslashit( $backup_dir ) . $filename;
		$written = file_put_contents( $path, wp_json_encode( $backup, JSON_PRETTY_PRINT ) );
		if ( false === $written ) {
			return new WP_Error( 'backup_write_failed', __( 'Could not write AJ Core portal backup file.', 'ajforms' ) );
		}

		$this->log_portal_event(
			'ajcore_tables_backed_up',
			array(
				'source'   => 'sync_center',
				'severity' => 'info',
				'details'  => array(
					'file' => $filename,
					'tables' => wp_list_pluck( $inventory, 'table' ),
				),
			)
		);

		return array(
			'file' => $filename,
			'path' => $path,
		);
	}

	private function reset_portal_sync_cache() {
		$wpdb = $this->get_pdb();

		$this->ensure_portal_schema();

		$plan = $this->get_portal_master_reset_plan();
		$tables = array();
		foreach ( $plan['cleared_tables'] as $item ) {
			if ( $this->get_portal_ledger_table() !== $item['table'] ) {
				$tables[] = $item['table'];
			}
		}

		$deleted = 0;
		$ledger_table = $this->get_portal_ledger_table();
		$generated_ledger_source_types = $plan['generated_ledger_source_types'];
		$ledger_placeholders = implode( ',', array_fill( 0, count( $generated_ledger_source_types ), '%s' ) );
		$deleted += absint( $wpdb->get_var( $wpdb->prepare( "SELECT COUNT(*) FROM {$ledger_table} WHERE source_type IN ({$ledger_placeholders})", $generated_ledger_source_types ) ) );
		$ledger_result = $wpdb->query( $wpdb->prepare( "DELETE FROM {$ledger_table} WHERE source_type IN ({$ledger_placeholders})", $generated_ledger_source_types ) );
		if ( false === $ledger_result ) {
			return new WP_Error( 'portal_reset_failed', sprintf( __( 'Could not reset table %s.', 'ajforms' ), $ledger_table ) );
		}

		foreach ( $tables as $table ) {
			$count = $wpdb->get_var( "SELECT COUNT(*) FROM {$table}" );
			$result = $wpdb->query( "DELETE FROM {$table}" );
			if ( false === $result ) {
				return new WP_Error( 'portal_reset_failed', sprintf( __( 'Could not reset table %s.', 'ajforms' ), $table ) );
			}
			$deleted += absint( $count );
		}

		delete_option( 'ajcore_portal_sync_last_run' );
		delete_option( 'ajforms_last_portal_db_error' );

		return $deleted;
	}

	private function get_portal_sync_message( $message, $stats = array() ) {
		$stats = is_array( $stats ) ? $stats : array();

		return wp_json_encode(
			array(
				'summary' => sanitize_textarea_field( (string) $message ),
				'stats'   => $stats,
			)
		);
	}

	private function decode_portal_sync_message( $message ) {
		$decoded = ! empty( $message ) ? json_decode( (string) $message, true ) : array();
		if ( is_array( $decoded ) && isset( $decoded['summary'] ) ) {
			return $decoded;
		}

		return array(
			'summary' => (string) $message,
			'stats'   => array(),
		);
	}

	private function write_portal_sync_log( $run_key, $source, $job_name, $status, $records_synced = 0, $message = '', $log_id = 0 ) {
		$wpdb = $this->get_pdb();

		$data = array(
			'run_key'        => sanitize_text_field( (string) $run_key ),
			'source'         => sanitize_key( (string) $source ),
			'job_name'       => sanitize_key( (string) $job_name ),
			'status'         => sanitize_key( (string) $status ),
			'records_synced' => absint( $records_synced ),
			'message'        => sanitize_textarea_field( (string) $message ),
			'created_by'     => get_current_user_id(),
		);
		$formats = array( '%s', '%s', '%s', '%s', '%d', '%s', '%d' );

		if ( $log_id ) {
			$data['finished_at'] = current_time( 'mysql' );
			$formats[] = '%s';
			$wpdb->update( $this->get_portal_sync_logs_table(), $data, array( 'id' => absint( $log_id ) ), $formats, array( '%d' ) );
			return absint( $log_id );
		}

		$data['started_at'] = current_time( 'mysql' );
		$formats[] = '%s';
		$wpdb->insert( $this->get_portal_sync_logs_table(), $data, $formats );

		return (int) $wpdb->insert_id;
	}

	private function get_stripe_event_object_id( $event ) {
		$object = ! empty( $event['data']['object'] ) && is_array( $event['data']['object'] ) ? $event['data']['object'] : array();

		return ! empty( $object['id'] ) ? sanitize_text_field( (string) $object['id'] ) : '';
	}

	private function get_stripe_event_account_id( $event ) {
		if ( ! empty( $event['account'] ) ) {
			return sanitize_text_field( (string) $event['account'] );
		}
		if ( ! empty( $event['context'] ) ) {
			return sanitize_text_field( (string) $event['context'] );
		}

		return '';
	}

	private function get_processed_stripe_event( $event_id ) {
		$wpdb = $this->get_pdb();

		$event_id = sanitize_text_field( (string) $event_id );
		if ( '' === $event_id ) {
			return null;
		}

		return $wpdb->get_row(
			$wpdb->prepare(
				"SELECT * FROM {$this->get_portal_stripe_events_table()} WHERE event_id = %s LIMIT 1",
				$event_id
			)
		);
	}

	private function record_stripe_event_received( $event ) {
		$wpdb = $this->get_pdb();

		$event_id = ! empty( $event['id'] ) ? sanitize_text_field( (string) $event['id'] ) : '';
		if ( '' === $event_id ) {
			return new WP_Error( 'missing_event_id', __( 'Stripe event ID is missing.', 'ajforms' ) );
		}

		$event_type     = ! empty( $event['type'] ) ? sanitize_text_field( (string) $event['type'] ) : '';
		$livemode       = ! empty( $event['livemode'] ) ? 1 : 0;
		$stripe_account = $this->get_stripe_event_account_id( $event );
		$object_id      = $this->get_stripe_event_object_id( $event );
		$existing       = $this->get_processed_stripe_event( $event_id );

		if ( $existing ) {
			$wpdb->update(
				$this->get_portal_stripe_events_table(),
				array(
					'attempts'  => (int) $existing->attempts + 1,
					'raw_event' => wp_json_encode( $event ),
				),
				array( 'event_id' => $event_id ),
				array( '%d', '%s' ),
				array( '%s' )
			);
			return $this->get_processed_stripe_event( $event_id );
		}

		$wpdb->insert(
			$this->get_portal_stripe_events_table(),
			array(
				'event_id'          => $event_id,
				'event_type'        => $event_type,
				'livemode'          => $livemode,
				'stripe_account'    => $stripe_account,
				'object_id'         => $object_id,
				'processing_status' => 'received',
				'first_seen_at'     => current_time( 'mysql' ),
				'processed_at'      => null,
				'attempts'          => 1,
				'last_error'        => '',
				'raw_event'         => wp_json_encode( $event ),
			),
			array( '%s', '%s', '%d', '%s', '%s', '%s', '%s', '%s', '%d', '%s', '%s' )
		);

		return $this->get_processed_stripe_event( $event_id );
	}

	private function mark_stripe_event_processing( $event_id ) {
		$wpdb = $this->get_pdb();

		return $wpdb->update(
			$this->get_portal_stripe_events_table(),
			array( 'processing_status' => 'processing' ),
			array( 'event_id' => sanitize_text_field( (string) $event_id ) ),
			array( '%s' ),
			array( '%s' )
		);
	}

	private function mark_stripe_event_processed( $event_id ) {
		$wpdb = $this->get_pdb();

		return $wpdb->update(
			$this->get_portal_stripe_events_table(),
			array(
				'processing_status' => 'processed',
				'processed_at'      => current_time( 'mysql' ),
				'last_error'        => '',
			),
			array( 'event_id' => sanitize_text_field( (string) $event_id ) ),
			array( '%s', '%s', '%s' ),
			array( '%s' )
		);
	}

	private function mark_stripe_event_failed( $event_id, $error_message ) {
		$wpdb = $this->get_pdb();

		return $wpdb->update(
			$this->get_portal_stripe_events_table(),
			array(
				'processing_status' => 'failed',
				'processed_at'      => current_time( 'mysql' ),
				'last_error'        => sanitize_textarea_field( (string) $error_message ),
			),
			array( 'event_id' => sanitize_text_field( (string) $event_id ) ),
			array( '%s', '%s', '%s' ),
			array( '%s' )
		);
	}

	private function fetch_current_stripe_webhook_object( $type, $object, $secret_key ) {
		$object_id = ! empty( $object['id'] ) ? sanitize_text_field( (string) $object['id'] ) : '';
		if ( '' === $object_id ) {
			return $object;
		}

		if ( 0 === strpos( $type, 'checkout.session.' ) ) {
			$session = $this->stripe_api_get( 'checkout/sessions/' . rawurlencode( $object_id ), $secret_key );
			if ( is_wp_error( $session ) ) {
				return $session;
			}

			return $this->enrich_checkout_session_with_line_items( $session, $secret_key );
		}

		if ( 0 === strpos( $type, 'invoice.' ) ) {
			return $this->stripe_api_get( 'invoices/' . rawurlencode( $object_id ), $secret_key );
		}

		if ( 0 === strpos( $type, 'customer.subscription.' ) ) {
			return $this->stripe_api_get(
				'subscriptions/' . rawurlencode( $object_id ),
				$secret_key,
				array( 'expand[]' => 'items.data.price' )
			);
		}

		if ( 0 === strpos( $type, 'charge.' ) ) {
			return $this->stripe_api_get( 'charges/' . rawurlencode( $object_id ), $secret_key );
		}

		return $object;
	}

	private function get_scalar_stripe_id( $value, $prefix = '' ) {
		if ( is_array( $value ) && ! empty( $value['id'] ) ) {
			$value = $value['id'];
		}

		$value = is_scalar( $value ) ? sanitize_text_field( (string) $value ) : '';
		if ( '' !== $prefix && 0 !== strpos( $value, $prefix ) ) {
			return '';
		}

		return $value;
	}

	private function get_deferred_one_time_price_ids_from_checkout_session( $session ) {
		$metadata = ! empty( $session['metadata'] ) && is_array( $session['metadata'] ) ? $session['metadata'] : array();
		$raw      = ! empty( $metadata['ajcore_one_time_price_ids'] ) ? sanitize_text_field( (string) $metadata['ajcore_one_time_price_ids'] ) : '';
		if ( '' === $raw ) {
			return array();
		}

		return array_values(
			array_filter(
				array_unique(
					array_map(
						'sanitize_text_field',
						array_map( 'trim', explode( ',', $raw ) )
					)
				)
			)
		);
	}

	private function get_deferred_one_time_payment_method_from_subscription( $subscription_id, $customer_id, $secret_key ) {
		$subscription_id = sanitize_text_field( (string) $subscription_id );
		$customer_id     = sanitize_text_field( (string) $customer_id );
		if ( '' === $subscription_id ) {
			return '';
		}

		$subscription = $this->stripe_api_get(
			'subscriptions/' . rawurlencode( $subscription_id ),
			$secret_key,
			array( 'expand[]' => 'latest_invoice.payment_intent' )
		);
		if ( is_wp_error( $subscription ) ) {
			return '';
		}

		$payment_method = $this->get_scalar_stripe_id( isset( $subscription['default_payment_method'] ) ? $subscription['default_payment_method'] : '', 'pm_' );
		if ( '' !== $payment_method ) {
			return $payment_method;
		}

		$latest_invoice = ! empty( $subscription['latest_invoice'] ) && is_array( $subscription['latest_invoice'] ) ? $subscription['latest_invoice'] : array();
		$payment_intent = ! empty( $latest_invoice['payment_intent'] ) && is_array( $latest_invoice['payment_intent'] ) ? $latest_invoice['payment_intent'] : array();
		$payment_method = $this->get_scalar_stripe_id( isset( $payment_intent['payment_method'] ) ? $payment_intent['payment_method'] : '', 'pm_' );
		if ( '' !== $payment_method ) {
			return $payment_method;
		}

		$latest_invoice_id = empty( $latest_invoice ) && ! empty( $subscription['latest_invoice'] ) ? $this->get_scalar_stripe_id( $subscription['latest_invoice'], 'in_' ) : '';
		if ( '' !== $latest_invoice_id ) {
			$invoice = $this->stripe_api_get(
				'invoices/' . rawurlencode( $latest_invoice_id ),
				$secret_key,
				array( 'expand[]' => 'payment_intent' )
			);
			if ( ! is_wp_error( $invoice ) && ! empty( $invoice['payment_intent'] ) && is_array( $invoice['payment_intent'] ) ) {
				$payment_method = $this->get_scalar_stripe_id( isset( $invoice['payment_intent']['payment_method'] ) ? $invoice['payment_intent']['payment_method'] : '', 'pm_' );
				if ( '' !== $payment_method ) {
					return $payment_method;
				}
			}
		}

		if ( '' !== $customer_id ) {
			$customer = $this->stripe_api_get( 'customers/' . rawurlencode( $customer_id ), $secret_key );
			if ( ! is_wp_error( $customer ) && ! empty( $customer['invoice_settings']['default_payment_method'] ) ) {
				return $this->get_scalar_stripe_id( $customer['invoice_settings']['default_payment_method'], 'pm_' );
			}
		}

		return '';
	}

	private function create_deferred_one_time_service_snapshots_from_checkout( $session, $payment_intent, $price_ids ) {
		$count       = 0;
		$customer_id = ! empty( $session['customer'] ) && is_scalar( $session['customer'] ) ? sanitize_text_field( (string) $session['customer'] ) : '';
		$currency    = ! empty( $payment_intent['currency'] ) ? strtolower( sanitize_key( (string) $payment_intent['currency'] ) ) : ( ! empty( $session['currency'] ) ? strtolower( sanitize_key( (string) $session['currency'] ) ) : 'usd' );
		$status      = ! empty( $payment_intent['status'] ) ? sanitize_key( (string) $payment_intent['status'] ) : 'succeeded';
		$parent      = array(
			'id'             => ! empty( $session['id'] ) ? sanitize_text_field( (string) $session['id'] ) : '',
			'customer'       => $customer_id,
			'payment_intent' => ! empty( $payment_intent['id'] ) ? sanitize_text_field( (string) $payment_intent['id'] ) : '',
			'status'         => in_array( $status, array( 'succeeded', 'processing' ), true ) ? $status : 'paid',
			'payment_status' => 'succeeded' === $status ? 'paid' : $status,
			'currency'       => $currency,
			'livemode'       => ! empty( $payment_intent['livemode'] ) || ! empty( $session['livemode'] ),
			'metadata'       => ! empty( $session['metadata'] ) && is_array( $session['metadata'] ) ? $session['metadata'] : array(),
		);

		foreach ( $price_ids as $price_id ) {
			$price_id = sanitize_text_field( (string) $price_id );
			if ( '' === $price_id ) {
				continue;
			}

			$product = $this->get_portal_product_by_price_id( $price_id );
			if ( ! $product ) {
				continue;
			}

			$item_currency = ! empty( $product->currency ) ? strtolower( sanitize_key( (string) $product->currency ) ) : $currency;
			$amount_minor  = $this->stripe_decimal_to_minor_units( isset( $product->price_amount ) ? (float) $product->price_amount : 0, $item_currency );
			$item          = array(
				'price'        => array(
					'id'          => $price_id,
					'currency'    => $item_currency,
					'unit_amount' => $amount_minor,
					'product'     => array(
						'id'   => ! empty( $product->stripe_product_id ) ? sanitize_text_field( (string) $product->stripe_product_id ) : '',
						'name' => ! empty( $product->name ) ? sanitize_text_field( (string) $product->name ) : '',
					),
				),
				'quantity'     => 1,
				'amount_total' => $amount_minor,
				'currency'     => $item_currency,
				'description'  => ! empty( $product->name ) ? sanitize_text_field( (string) $product->name ) : $price_id,
			);

			$count += $this->maybe_create_portal_service_snapshot_from_line_item( $item, $parent, 'checkout_session' ) ? 1 : 0;
		}

		if ( $count && '' !== $customer_id ) {
			$this->backfill_portal_ledger_service_charges_from_snapshots( $customer_id );
		}

		return $count;
	}

	private function maybe_charge_deferred_one_time_items_for_checkout_session( $session, $secret_key ) {
		if ( empty( $session['id'] ) || empty( $session['subscription'] ) || empty( $session['customer'] ) ) {
			return 0;
		}

		$price_ids = $this->get_deferred_one_time_price_ids_from_checkout_session( $session );
		if ( empty( $price_ids ) ) {
			return 0;
		}

		global $wpdb;

		$session_id  = sanitize_text_field( (string) $session['id'] );
		$customer_id = $this->get_scalar_stripe_id( $session['customer'], 'cus_' );
		if ( '' === $customer_id ) {
			return new WP_Error( 'missing_customer', __( 'Unable to charge one-time cart items because the checkout session customer is missing.', 'ajforms' ) );
		}
		$existing    = $wpdb->get_var(
			$wpdb->prepare(
				"SELECT id FROM {$this->get_portal_ledger_table()} WHERE source_object_id = %s OR metadata LIKE %s LIMIT 1",
				'mixed_one_time_' . $session_id,
				'%' . $wpdb->esc_like( $session_id ) . '%ajcore_mixed_one_time_payment%'
			)
		);
		if ( $existing ) {
			return 0;
		}

		$metadata = ! empty( $session['metadata'] ) && is_array( $session['metadata'] ) ? $session['metadata'] : array();
		$amount   = ! empty( $metadata['ajcore_one_time_amount'] ) ? absint( $metadata['ajcore_one_time_amount'] ) : 0;
		$currency = ! empty( $metadata['ajcore_one_time_currency'] ) ? strtolower( sanitize_key( (string) $metadata['ajcore_one_time_currency'] ) ) : ( ! empty( $session['currency'] ) ? strtolower( sanitize_key( (string) $session['currency'] ) ) : 'usd' );
		if ( $amount <= 0 ) {
			foreach ( $price_ids as $price_id ) {
				$product = $this->get_portal_product_by_price_id( $price_id );
				if ( $product ) {
					$currency = ! empty( $product->currency ) ? strtolower( sanitize_key( (string) $product->currency ) ) : $currency;
					$amount  += $this->stripe_decimal_to_minor_units( isset( $product->price_amount ) ? (float) $product->price_amount : 0, $currency );
				}
			}
		}
		if ( $amount <= 0 ) {
			return 0;
		}

		$subscription_id = $this->get_scalar_stripe_id( $session['subscription'], 'sub_' );
		if ( '' === $subscription_id ) {
			return new WP_Error( 'missing_subscription', __( 'Unable to charge one-time cart items because the checkout session subscription is missing.', 'ajforms' ) );
		}
		$payment_method = $this->get_deferred_one_time_payment_method_from_subscription( $subscription_id, $customer_id, $secret_key );
		if ( '' === $payment_method ) {
			return new WP_Error( 'missing_payment_method', __( 'Unable to charge one-time cart items because Stripe did not expose the subscription payment method yet.', 'ajforms' ) );
		}

		$product_names = array();
		foreach ( $price_ids as $price_id ) {
			$product = $this->get_portal_product_by_price_id( $price_id );
			if ( $product ) {
				$label = ! empty( $product->custom_label ) ? sanitize_text_field( (string) $product->custom_label ) : ( ! empty( $product->name ) ? sanitize_text_field( (string) $product->name ) : '' );
				if ( '' !== $label && ! in_array( $label, $product_names, true ) ) {
					$product_names[] = $label;
				}
			}
		}
		$description = ! empty( $product_names ) ? implode( ', ', $product_names ) : sprintf( __( 'One-time items from checkout %s', 'ajforms' ), $session_id );
		$payment_intent = $this->stripe_api_request(
			'payment_intents',
			$secret_key,
			array(
				'amount'                       => $amount,
				'currency'                     => $currency,
				'customer'                     => $customer_id,
				'payment_method'              => $payment_method,
				'confirm'                     => 'true',
				'off_session'                 => 'true',
				'description'                 => $description,
				'metadata[source]'            => 'ajcore_mixed_one_time_payment',
				'metadata[checkout_session_id]' => $session_id,
				'metadata[subscription_id]'    => $subscription_id,
				'metadata[stripe_customer_id]' => $customer_id,
				'metadata[price_ids]'          => implode( ',', $price_ids ),
			)
		);
		if ( is_wp_error( $payment_intent ) ) {
			return $payment_intent;
		}

		$payment_intent_id = ! empty( $payment_intent['id'] ) ? sanitize_text_field( (string) $payment_intent['id'] ) : '';
		$status            = ! empty( $payment_intent['status'] ) ? sanitize_key( (string) $payment_intent['status'] ) : '';
		$amount_decimal    = $this->stripe_amount_to_decimal( $amount, $currency );
		$charge_id         = ! empty( $payment_intent['latest_charge'] ) ? $this->get_scalar_stripe_id( $payment_intent['latest_charge'], 'ch_' ) : '';
		$now               = current_time( 'mysql' );

		if ( '' !== $payment_intent_id ) {
			$this->upsert_portal_record(
				$this->get_portal_stripe_transactions_table(),
				array(
					'stripe_object_id'   => $payment_intent_id,
					'object_type'        => 'payment_intent',
					'stripe_customer_id' => $customer_id,
					'invoice_id'         => '',
					'payment_intent_id'  => $payment_intent_id,
					'charge_id'          => $charge_id,
					'description'        => __( 'One-time cart payment', 'ajforms' ),
					'amount'             => $amount_decimal,
					'currency'           => $currency,
					'status'             => $status,
					'transaction_date'   => $now,
					'due_date'           => null,
					'raw_data'           => wp_json_encode( $payment_intent ),
					'livemode'           => ! empty( $payment_intent['livemode'] ) ? 1 : $this->get_current_stripe_livemode(),
					'synced_at'          => $now,
				),
				array( '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%f', '%s', '%s', '%s', '%s', '%s', '%d', '%s' ),
				'stripe_object_id'
			);
			$this->upsert_portal_record(
				$this->get_portal_ledger_table(),
				array(
					'stripe_customer_id' => $customer_id,
					'source_object_id'   => 'mixed_one_time_' . $session_id,
					'source_type'        => 'payment_intent',
					'ledger_date'        => $now,
					'description'        => __( 'Payment', 'ajforms' ),
					'amount'             => $amount_decimal,
					'currency'           => $currency,
					'status'             => $status,
					'invoice_id'         => '',
					'payment_intent_id'  => $payment_intent_id,
					'charge_id'          => $charge_id,
					'metadata'           => wp_json_encode( array( 'source' => 'ajcore_mixed_one_time_payment', 'checkout_session_id' => $session_id, 'price_ids' => $price_ids ) ),
					'created_at'         => $now,
				),
				array( '%s', '%s', '%s', '%s', '%s', '%f', '%s', '%s', '%s', '%s', '%s', '%s', '%s' ),
				'source_object_id'
			);
		}

		$snapshot_count = $this->create_deferred_one_time_service_snapshots_from_checkout( $session, $payment_intent, $price_ids );
		$this->log_portal_event(
			'mixed_cart_one_time_payment_created',
			array(
				'source'             => 'webhook',
				'stripe_customer_id' => $customer_id,
				'details'            => array(
					'checkout_session_id' => $session_id,
					'subscription_id'     => $subscription_id,
					'payment_intent_id'   => $payment_intent_id,
					'amount'              => $amount_decimal,
					'currency'            => $currency,
					'price_ids'           => $price_ids,
					'snapshots'           => $snapshot_count,
				),
			)
		);

		return 1 + absint( $snapshot_count );
	}

	private function get_checkout_session_metadata_value( $session, $key ) {
		if ( ! is_array( $session ) || empty( $key ) ) {
			return '';
		}

		if ( ! empty( $session['metadata'] ) && is_array( $session['metadata'] ) && isset( $session['metadata'][ $key ] ) && is_scalar( $session['metadata'][ $key ] ) ) {
			return sanitize_text_field( (string) $session['metadata'][ $key ] );
		}

		return '';
	}

	private function process_portal_upgrade_checkout_session( $session, $secret_key, $source = 'webhook' ) {
		global $wpdb;

		if ( ! is_array( $session ) ) {
			return 0;
		}

		$is_upgrade = '1' === $this->get_checkout_session_metadata_value( $session, 'ajcore_upgrade' );
		$old_subscription_id = $this->get_checkout_session_metadata_value( $session, 'ajcore_upgrade_from_subscription_id' );
		if ( ! $is_upgrade || '' === $old_subscription_id || 0 !== strpos( $old_subscription_id, 'sub_' ) ) {
			return 0;
		}

		$status         = ! empty( $session['status'] ) ? sanitize_key( (string) $session['status'] ) : '';
		$payment_status = ! empty( $session['payment_status'] ) ? sanitize_key( (string) $session['payment_status'] ) : '';
		if ( ! in_array( $status, array( 'complete', 'completed' ), true ) && 'paid' !== $payment_status ) {
			return 0;
		}

		$new_subscription_id = '';
		if ( ! empty( $session['subscription'] ) ) {
			if ( is_array( $session['subscription'] ) && ! empty( $session['subscription']['id'] ) ) {
				$new_subscription_id = sanitize_text_field( (string) $session['subscription']['id'] );
			} elseif ( is_string( $session['subscription'] ) ) {
				$new_subscription_id = sanitize_text_field( (string) $session['subscription'] );
			}
		}
		if ( '' !== $new_subscription_id && $new_subscription_id === $old_subscription_id ) {
			return new WP_Error( 'invalid_upgrade_subscription', __( 'Upgrade checkout returned the same subscription as the source subscription.', 'ajforms' ) );
		}

		$old_subscription = $this->stripe_api_get( 'subscriptions/' . rawurlencode( $old_subscription_id ), $secret_key );
		if ( is_wp_error( $old_subscription ) ) {
			return $old_subscription;
		}

		$old_status = ! empty( $old_subscription['status'] ) ? sanitize_key( (string) $old_subscription['status'] ) : '';
		if ( ! in_array( $old_status, array( 'canceled', 'cancelled' ), true ) ) {
			$cancel_result = $this->stripe_api_request( 'subscriptions/' . rawurlencode( $old_subscription_id ), $secret_key, array(), 'DELETE' );
			if ( is_wp_error( $cancel_result ) ) {
				return $cancel_result;
			}
		}

		$wpdb->update(
			$this->get_portal_stripe_subscriptions_table(),
			array(
				'status'    => 'canceled',
				'synced_at' => current_time( 'mysql' ),
			),
			array( 'stripe_subscription_id' => $old_subscription_id ),
			array( '%s', '%s' ),
			array( '%s' )
		);
		$wpdb->update(
			$this->get_portal_service_snapshots_table(),
			array(
				'status'     => 'canceled',
				'updated_at' => current_time( 'mysql' ),
			),
			array( 'subscription_id' => $old_subscription_id ),
			array( '%s', '%s' ),
			array( '%s' )
		);

		$this->log_portal_event(
			'portal_service_upgraded',
			array(
				'source'             => sanitize_key( (string) $source ),
				'stripe_customer_id' => ! empty( $session['customer'] ) && is_string( $session['customer'] ) ? sanitize_text_field( (string) $session['customer'] ) : '',
				'details'            => array(
					'checkout_session_id'       => ! empty( $session['id'] ) ? sanitize_text_field( (string) $session['id'] ) : '',
					'from_subscription_id'      => $old_subscription_id,
					'to_subscription_id'        => $new_subscription_id,
					'from_product_id'           => $this->get_checkout_session_metadata_value( $session, 'ajcore_upgrade_from_product_id' ),
					'to_product_id'             => $this->get_checkout_session_metadata_value( $session, 'ajcore_upgrade_to_product_id' ),
					'to_price_id'               => $this->get_checkout_session_metadata_value( $session, 'ajcore_upgrade_to_price_id' ),
				),
			)
		);

		return 1;
	}

	public function finalize_mixed_checkout_session_by_id( $session_id, $source = 'manual' ) {
		$this->ensure_portal_schema();

		$session_id = sanitize_text_field( (string) $session_id );
		$source     = sanitize_key( (string) $source );
		if ( 0 !== strpos( $session_id, 'cs_' ) ) {
			return new WP_Error( 'invalid_checkout_session', __( 'Invalid checkout session.', 'ajforms' ) );
		}

		$secret_key = $this->get_stripe_secret_key_for_portal();
		if ( '' === $secret_key ) {
			return new WP_Error( 'missing_stripe_key', __( 'Stripe secret key is required.', 'ajforms' ) );
		}

		$session = $this->stripe_api_get(
			'checkout/sessions/' . rawurlencode( $session_id ),
			$secret_key,
			array(
				'expand[]' => 'subscription',
			)
		);
		if ( is_wp_error( $session ) ) {
			$this->log_portal_event(
				'mixed_cart_one_time_payment_failed',
				array(
					'severity' => 'error',
					'source'   => $source,
					'details'  => array(
						'checkout_session_id' => $session_id,
						'error'               => $session->get_error_message(),
					),
				)
			);
			return $session;
		}

		$session = $this->enrich_checkout_session_with_line_items( $session, $secret_key );
		$result  = $this->maybe_charge_deferred_one_time_items_for_checkout_session( $session, $secret_key );
		if ( is_wp_error( $result ) ) {
			$this->log_portal_event(
				'mixed_cart_one_time_payment_failed',
				array(
					'severity' => 'error',
					'source'   => $source,
					'details'  => array(
						'checkout_session_id' => $session_id,
						'error'               => $result->get_error_message(),
					),
				)
			);
			return $result;
		}

		$upgrade_result = $this->process_portal_upgrade_checkout_session( $session, $secret_key, $source );
		if ( is_wp_error( $upgrade_result ) ) {
			$this->log_portal_event(
				'portal_service_upgrade_failed',
				array(
					'severity' => 'error',
					'source'   => $source,
					'details'  => array(
						'checkout_session_id' => $session_id,
						'error'               => $upgrade_result->get_error_message(),
					),
				)
			);
			return $upgrade_result;
		}

		if ( $result > 0 ) {
			$this->log_portal_event(
				'mixed_cart_one_time_payment_finalized',
				array(
					'source'  => $source,
					'details' => array(
						'checkout_session_id' => $session_id,
						'result'              => $result,
					),
				)
			);
		}

		return absint( $result ) + absint( $upgrade_result );
	}

	public function run_portal_sync_job( $source = 'manual', $requested_jobs = array(), $run_key = '' ) {
		$this->ensure_portal_schema();

		$secret_key = $this->get_stripe_secret_key_for_portal();
		if ( '' === $secret_key ) {
			return new WP_Error( 'missing_stripe_key', __( 'Stripe secret key is required.', 'ajforms' ) );
		}

		$available_jobs = $this->get_portal_sync_jobs();
		$sync_settings = $this->get_portal_sync_settings();
		$jobs = ! empty( $requested_jobs ) ? array_values( array_intersect( array_map( 'sanitize_key', (array) $requested_jobs ), array_keys( $available_jobs ) ) ) : $sync_settings['jobs'];
		if ( empty( $jobs ) ) {
			$jobs = array_keys( $available_jobs );
		}

		// Callers that need to poll for completion (e.g. an async manual trigger) pass their own
		// run_key so they can query the logs table for it; everyone else (cron) gets one generated.
		$run_key = '' !== $run_key ? sanitize_text_field( (string) $run_key ) : wp_generate_uuid4();
		$total   = 0;
		$errors  = array();

		foreach ( $jobs as $job ) {
			$label  = isset( $available_jobs[ $job ] ) ? $available_jobs[ $job ] : $job;
			$log_id = $this->write_portal_sync_log( $run_key, $source, $job, 'started', 0, sprintf( __( '%s sync started.', 'ajforms' ), $label ) );
			$this->reset_portal_sync_stats();
			$this->portal_sync_current_log_id  = $log_id;
			$this->portal_sync_current_run_key = $run_key;
			$this->portal_sync_current_job     = $job;
			$result = null;

			if ( 'products' === $job ) {
				$result = $this->sync_portal_stripe_products( $secret_key );
			} elseif ( 'customers' === $job ) {
				$result = $this->sync_portal_stripe_customers( $secret_key );
			} elseif ( 'subscriptions' === $job ) {
				$result = $this->sync_portal_stripe_subscriptions( $secret_key );
			} elseif ( 'transactions' === $job ) {
				$result = $this->sync_portal_stripe_transactions( $secret_key );
			}

			if ( is_wp_error( $result ) ) {
				$errors[] = $label . ': ' . $result->get_error_message();
				$this->increment_portal_sync_stat( 'failed' );
				$this->write_portal_sync_log( $run_key, $source, $job, 'failed', 0, $this->get_portal_sync_message( $result->get_error_message(), $this->portal_sync_stats ), $log_id );
				$this->portal_sync_current_log_id  = 0;
				$this->portal_sync_current_run_key = '';
				$this->portal_sync_current_job     = '';
				continue;
			}

			$count = absint( $result );
			$total += $count;
			$reconciliation = $this->get_portal_sync_reconciliation();
			$this->portal_sync_stats['unmatched_payments'] = $reconciliation['unmatched_payments'];
			$this->portal_sync_stats['unmatched_refunds']  = $reconciliation['unmatched_refunds'];
			$this->portal_sync_stats['missing_users']      = $reconciliation['missing_users'];
			foreach ( $reconciliation['key_warnings'] as $warning ) {
				$this->add_portal_sync_warning( $warning );
			}
			$this->write_portal_sync_log( $run_key, $source, $job, 'success', $count, $this->get_portal_sync_message( sprintf( __( '%1$s sync completed. %2$d records refreshed.', 'ajforms' ), $label, $count ), $this->portal_sync_stats ), $log_id );
			$this->portal_sync_current_log_id  = 0;
			$this->portal_sync_current_run_key = '';
			$this->portal_sync_current_job     = '';
		}

		if ( ! empty( $errors ) ) {
			return new WP_Error( 'portal_sync_failed', implode( ' | ', $errors ) );
		}

		update_option( 'ajcore_portal_sync_last_run', current_time( 'mysql' ), false );
		delete_option( 'ajforms_last_portal_db_error' );

		return $total;
	}

	public function run_scheduled_portal_sync_job() {
		$settings = $this->get_portal_sync_settings();
		if ( empty( $settings['enabled'] ) ) {
			return;
		}

		if ( function_exists( 'ajcore_is_stripe_sync_owner' ) && ! ajcore_is_stripe_sync_owner() ) {
			return;
		}

		$this->run_portal_sync_job( 'cron', $settings['jobs'] );
	}

	/**
	 * Runs a manually-triggered sync in the background via a one-off WP-Cron event, rather than
	 * inline within the HTTP request that triggered it — a real Stripe sync (especially the
	 * "transactions" job, which pages through the full invoice/charge history) can easily take
	 * longer than a typical PHP or reverse-proxy request timeout allows, and DOES on a live account
	 * with real data volume even though it looks instant against a small local/dev dataset. Handles
	 * the 'ajcore_manual_sync_run' cron hook scheduled by ops_trigger_sync() and the WP admin
	 * "Full Sync Now" / per-job buttons — both now schedule instead of calling run_portal_sync_job()
	 * directly. The transient carries the requested jobs + the run_key the caller is polling for
	 * (see get_sync_run_status_for_ops()).
	 */
	public function run_manual_sync_job_from_transient( $run_token ) {
		$run_token = sanitize_text_field( (string) $run_token );
		$data      = get_transient( 'ajcore_manual_sync_' . $run_token );
		delete_transient( 'ajcore_manual_sync_' . $run_token );
		if ( ! is_array( $data ) ) {
			return;
		}
		$jobs    = isset( $data['jobs'] ) && is_array( $data['jobs'] ) ? $data['jobs'] : array();
		$run_key = isset( $data['run_key'] ) ? (string) $data['run_key'] : '';
		$this->run_portal_sync_job( 'manual', $jobs, $run_key );
	}

	/**
	 * Schedules a manual sync to run in the background and returns the run_key + run_token needed
	 * to trigger and then poll it. Shared by the ops REST trigger and the WP admin manual buttons so
	 * both go through the exact same (safe, non-blocking) path.
	 */
	/**
	 * Kicks WP-Cron only AFTER the current request's response has been fully sent to the client.
	 * spawn_cron() makes a loopback HTTP request to the site's own public hostname — instant on a
	 * local/dev box, but on a Cloudflare-fronted live site that is a hairpin connection (origin →
	 * Cloudflare edge → back to origin) which can hang or be challenged/blocked outright, and any
	 * such stall inside the request window stalls the API response with it (observed live as the
	 * AJOps sync trigger hanging until the gateway 504'd, while local worked perfectly).
	 * fastcgi_finish_request() (PHP-FPM, and LiteSpeed's lsapi on modern versions) flushes the
	 * response and closes the client connection first, so a slow/hung spawn only ties up the PHP
	 * worker, never the caller. Where unavailable, the shutdown hook still runs as late as possible.
	 */
	private function kick_wp_cron_after_response() {
		add_action(
			'shutdown',
			static function () {
				if ( function_exists( 'fastcgi_finish_request' ) ) {
					fastcgi_finish_request();
				}
				spawn_cron();
			},
			PHP_INT_MAX
		);
	}

	private function schedule_manual_sync_job( $jobs ) {
		$run_key   = wp_generate_uuid4();
		$run_token = wp_generate_uuid4();
		set_transient( 'ajcore_manual_sync_' . $run_token, array( 'jobs' => $jobs, 'run_key' => $run_key ), 10 * MINUTE_IN_SECONDS );

		$scheduled = wp_schedule_single_event( time() - 1, 'ajcore_manual_sync_run', array( $run_token ), true );
		if ( is_wp_error( $scheduled ) ) {
			delete_transient( 'ajcore_manual_sync_' . $run_token );
			return $scheduled;
		}
		if ( false === $scheduled ) {
			delete_transient( 'ajcore_manual_sync_' . $run_token );
			return new WP_Error( 'schedule_failed', __( 'Could not schedule the background sync job.', 'ajforms' ) );
		}

		$this->kick_wp_cron_after_response();

		return $run_key;
	}

	/**
	 * Public entry point for the ops REST API — schedules a manual sync in the background (see
	 * schedule_manual_sync_job()) and returns the run_key to poll via get_sync_run_status_for_ops().
	 */
	public function trigger_manual_sync_for_ops( $jobs ) {
		$available_jobs = $this->get_portal_sync_jobs();
		$jobs = is_array( $jobs ) ? array_values( array_intersect( array_map( 'sanitize_key', $jobs ), array_keys( $available_jobs ) ) ) : array();

		return $this->schedule_manual_sync_job( $jobs );
	}

	/**
	 * Public entry point for the ops REST API — polls the sync_logs table for a run_key returned by
	 * trigger_manual_sync_for_ops(). Each job in a run gets exactly one log row that starts as
	 * 'started' and is updated in place to 'success'/'failed' (see write_portal_sync_log()), so the
	 * run is done once no row for this run_key is still 'started'. Empty rows means the background
	 * cron event hasn't actually fired yet (can take a few seconds on some hosts).
	 */
	public function get_sync_run_status_for_ops( $run_key ) {
		$pdb   = $this->get_pdb();
		$table = $this->get_portal_sync_logs_table();
		$rows  = $pdb->get_results( $pdb->prepare(
			"SELECT job_name, status, records_synced, message FROM {$table} WHERE run_key = %s",
			sanitize_text_field( (string) $run_key )
		) );

		if ( empty( $rows ) ) {
			// The scheduled event hasn't fired yet — re-kick cron (after this response is sent) so
			// a lost/blocked initial kick self-heals on the very first poll instead of waiting for
			// organic site traffic to trigger WP-Cron.
			$this->kick_wp_cron_after_response();
			return array( 'done' => false, 'started' => false, 'records_synced' => 0, 'errors' => array() );
		}

		$pending = 0;
		$records = 0;
		$errors  = array();
		foreach ( $rows as $row ) {
			if ( 'started' === $row->status ) {
				$pending++;
			} elseif ( 'failed' === $row->status ) {
				$errors[] = trim( sprintf( '%s: %s', $row->job_name, $row->message ) );
			} else {
				$records += (int) $row->records_synced;
			}
		}

		return array(
			'done'           => 0 === $pending,
			'started'        => true,
			'records_synced' => $records,
			'errors'         => $errors,
		);
	}

	/**
	 * Public entry point for the ops REST API — everything AJOps needs to render a sync control:
	 * available/selected jobs, enabled + frequency, and last/next run as UNIX (UTC) timestamps so
	 * the client can render them in any timezone without guessing what timezone the server is in.
	 * `ajcore_portal_sync_last_run` is stored via current_time('mysql') — the SITE's configured local
	 * time, not UTC — so it's converted back to a true UTC timestamp using the site's own timezone
	 * object rather than assumed to already be UTC (a wrong assumption would silently skew the
	 * "last completed run" time by the site's UTC offset).
	 */
	public function get_portal_sync_status_for_ops() {
		$settings   = $this->get_portal_sync_settings();
		$last_run   = get_option( 'ajcore_portal_sync_last_run', '' );
		$last_run_ts = 0;
		if ( '' !== $last_run ) {
			$dt = function_exists( 'wp_timezone' ) ? date_create( $last_run, wp_timezone() ) : date_create( $last_run . ' UTC' );
			if ( $dt ) {
				$last_run_ts = $dt->getTimestamp();
			}
		}
		$next_run_ts = wp_next_scheduled( 'ajcore_portal_stripe_sync' );

		return array(
			'enabled'         => $settings['enabled'],
			'frequency'       => $settings['frequency'],
			'frequency_label' => $this->get_portal_sync_frequency_labels()[ $settings['frequency'] ] ?? $settings['frequency'],
			'jobs'            => $this->get_portal_sync_jobs(),
			'selected_jobs'   => $settings['jobs'],
			'last_run_at'     => $last_run_ts ?: null,
			'next_run_at'     => $next_run_ts ?: null,
		);
	}

	public function handle_stripe_webhook_request() {
		$this->ensure_portal_schema();

		$secret_key = $this->get_stripe_secret_key_for_portal();
		if ( '' === $secret_key ) {
			status_header( 500 );
			wp_send_json_error( array( 'message' => __( 'Stripe secret key is required.', 'ajforms' ) ) );
		}

		$payload = file_get_contents( 'php://input' );
		$event   = json_decode( (string) $payload, true );
		if ( ! is_array( $event ) || empty( $event['id'] ) || empty( $event['type'] ) ) {
			status_header( 400 );
			wp_send_json_error( array( 'message' => __( 'Invalid Stripe event payload.', 'ajforms' ) ) );
		}

		$event_id = sanitize_text_field( (string) $event['id'] );
		$verified_event = $this->stripe_api_get( 'events/' . rawurlencode( $event_id ), $secret_key );
		if ( is_wp_error( $verified_event ) || empty( $verified_event['id'] ) || $verified_event['id'] !== $event_id ) {
			status_header( 400 );
			wp_send_json_error( array( 'message' => __( 'Stripe event could not be verified with the active Stripe key.', 'ajforms' ) ) );
		}

		$event = $verified_event;
		$type  = sanitize_text_field( (string) $event['type'] );
		$object = ! empty( $event['data']['object'] ) && is_array( $event['data']['object'] ) ? $event['data']['object'] : array();
		$object_id = $this->get_stripe_event_object_id( $event );
		$event_livemode = ! empty( $event['livemode'] ) ? 1 : 0;
		$expected_livemode = $this->get_current_stripe_livemode();
		if ( $event_livemode !== $expected_livemode ) {
			$this->log_portal_event(
				'webhook_failed',
				array(
					'severity' => 'warning',
					'source'   => 'webhook',
					'details'  => array(
						'event_id'          => $event_id,
						'event_type'        => $type,
						'object_id'         => $object_id,
						'reason'            => 'livemode_mismatch',
						'event_livemode'    => $event_livemode,
						'expected_livemode' => $expected_livemode,
					),
				)
			);
			status_header( 400 );
			wp_send_json_error( array( 'message' => __( 'Stripe event mode does not match the active AJ Core Stripe mode.', 'ajforms' ) ) );
		}

		$event_row = $this->record_stripe_event_received( $event );
		if ( is_wp_error( $event_row ) ) {
			status_header( 500 );
			wp_send_json_error( array( 'message' => $event_row->get_error_message() ) );
		}

		$this->log_portal_event(
			'webhook_received',
			array(
				'source'  => 'webhook',
				'details' => array(
					'event_id'       => $event_id,
					'event_type'     => $type,
					'object_id'      => $object_id,
					'livemode'       => $event_livemode,
					'attempts'       => isset( $event_row->attempts ) ? (int) $event_row->attempts : 1,
					'stripe_account' => $this->get_stripe_event_account_id( $event ),
				),
			)
		);

		if ( $event_row && 'processed' === (string) $event_row->processing_status ) {
			$run_key = wp_generate_uuid4();
			$job_name = sanitize_key( str_replace( '.', '_', $type ) );
			$log_id = $this->write_portal_sync_log( $run_key, 'webhook', $job_name, 'started', 0, __( 'Duplicate Stripe webhook event received.', 'ajforms' ) );
			$this->portal_sync_current_log_id = $log_id;
			$this->portal_sync_current_run_key = $run_key;
			$this->portal_sync_current_job = $job_name;
			$this->record_portal_sync_item( 'duplicate_ignored', 'stripe_event', $event_id, 'skipped', __( 'Duplicate Stripe webhook event already processed successfully.', 'ajforms' ), $event, $this->get_payment_customer_id( $object ) );
			$this->write_portal_sync_log( $run_key, 'webhook', $job_name, 'success', 0, $this->get_portal_sync_message( __( 'Duplicate Stripe webhook event ignored.', 'ajforms' ), array( 'skipped' => 1 ) ), $log_id );
			$this->portal_sync_current_log_id = 0;
			$this->portal_sync_current_run_key = '';
			$this->portal_sync_current_job = '';
			$this->log_portal_event(
				'webhook_duplicate_skipped',
				array(
					'source'  => 'webhook',
					'details' => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id ),
				)
			);
			wp_send_json_success( array( 'message' => 'duplicate_ignored' ) );
		}

		if ( $event_row && 'failed' === (string) $event_row->processing_status ) {
			$this->log_portal_event(
				'webhook_retried',
				array(
					'source'  => 'webhook',
					'details' => array(
						'event_id'   => $event_id,
						'event_type' => $type,
						'object_id'  => $object_id,
						'attempts'   => (int) $event_row->attempts,
					),
				)
			);
		}

		$this->mark_stripe_event_processing( $event_id );
		$supported = array(
			'checkout.session.completed',
			'invoice.paid',
			'invoice.payment_failed',
			'customer.subscription.updated',
			'customer.subscription.deleted',
			'charge.refunded',
		);

		if ( ! in_array( $type, $supported, true ) ) {
			$this->mark_stripe_event_processed( $event_id );
			$this->log_portal_event(
				'webhook_skipped',
				array(
					'source'  => 'webhook',
					'details' => array(
						'event_id'   => $event_id,
						'event_type' => $type,
						'object_id'  => $object_id,
						'reason'     => 'unsupported_event_type',
					),
				)
			);
			wp_send_json_success( array( 'message' => 'ignored' ) );
		}

		$current_object = $this->fetch_current_stripe_webhook_object( $type, $object, $secret_key );
		if ( is_wp_error( $current_object ) ) {
			$this->mark_stripe_event_failed( $event_id, $current_object->get_error_message() );
			$this->log_portal_event(
				'webhook_failed',
				array(
					'severity' => 'error',
					'source'   => 'webhook',
					'details'  => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id, 'error' => $current_object->get_error_message() ),
				)
			);
			status_header( 500 );
			wp_send_json_error( array( 'message' => $current_object->get_error_message() ) );
		}
		if ( is_array( $current_object ) && ! empty( $current_object['id'] ) ) {
			$object = $current_object;
		}

		$stripe_customer_id = '';
		if ( ! empty( $object['customer'] ) && is_string( $object['customer'] ) ) {
			$stripe_customer_id = sanitize_text_field( (string) $object['customer'] );
		}

		// Handle reservation payment before other checkout processing.
		if ( 'checkout.session.completed' === $type && is_array( $object ) && class_exists( 'AJCore_Reservations' ) ) {
			$session_meta      = ! empty( $object['metadata'] ) && is_array( $object['metadata'] ) ? $object['metadata'] : array();
			$reservation_uuid  = ! empty( $session_meta['reservation_uuid'] )  ? sanitize_text_field( (string) $session_meta['reservation_uuid'] )  : '';
			$reservation_uuids = ! empty( $session_meta['reservation_uuids'] ) ? sanitize_text_field( (string) $session_meta['reservation_uuids'] ) : '';
			$is_reservation    = '' !== $reservation_uuid || '' !== $reservation_uuids;
			if ( $is_reservation ) {
				$res_settings    = function_exists( 'ajforms_get_settings' ) ? ajforms_get_settings() : get_option( 'ajforms_settings', array() );
				$res_result      = AJCore_Reservations::handle_payment_success( $object['id'], $object, $res_settings );
				$this->log_portal_event(
					is_wp_error( $res_result ) ? 'reservation_payment_failed' : 'reservation_payment_succeeded',
					array(
						'source'  => 'webhook',
						'details' => array(
							'event_id'          => $event_id,
							'reservation_uuid'  => $reservation_uuid,
							'reservation_uuids' => $reservation_uuids,
							'session_id'        => $object['id'],
							'error'             => is_wp_error( $res_result ) ? $res_result->get_error_message() : null,
						),
					)
				);
				// If reservation payment processed successfully, acknowledge and exit — skip normal portal sync for this event.
				if ( ! is_wp_error( $res_result ) ) {
					$this->mark_stripe_event_processed( $event_id );
					wp_send_json_success( array( 'message' => 'reservation_processed' ) );
				}
				// On failure, fall through so the event is still synced normally.
			}
		}

		$deferred_one_time_result = 0;
		if ( 'checkout.session.completed' === $type && is_array( $object ) ) {
			$deferred_one_time_result = $this->maybe_charge_deferred_one_time_items_for_checkout_session( $object, $secret_key );
			if ( is_wp_error( $deferred_one_time_result ) ) {
				$this->mark_stripe_event_failed( $event_id, $deferred_one_time_result->get_error_message() );
				$this->log_portal_event(
					'webhook_failed',
					array(
						'severity' => 'error',
						'source'   => 'webhook',
						'details'  => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id, 'error' => $deferred_one_time_result->get_error_message(), 'phase' => 'mixed_cart_one_time_payment' ),
					)
				);
				status_header( 500 );
				wp_send_json_error( array( 'message' => $deferred_one_time_result->get_error_message() ) );
			}
			$upgrade_result = $this->process_portal_upgrade_checkout_session( $object, $secret_key, 'webhook' );
			if ( is_wp_error( $upgrade_result ) ) {
				$this->mark_stripe_event_failed( $event_id, $upgrade_result->get_error_message() );
				$this->log_portal_event(
					'webhook_failed',
					array(
						'severity' => 'error',
						'source'   => 'webhook',
						'details'  => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id, 'error' => $upgrade_result->get_error_message(), 'phase' => 'portal_service_upgrade' ),
					)
				);
				status_header( 500 );
				wp_send_json_error( array( 'message' => $upgrade_result->get_error_message() ) );
			}
		}

		$run_key = wp_generate_uuid4();
		$log_id  = $this->write_portal_sync_log( $run_key, 'webhook', sanitize_key( str_replace( '.', '_', $type ) ), 'started', 0, sprintf( __( 'Stripe webhook %s received.', 'ajforms' ), $type ) );
		$this->reset_portal_sync_stats();
		$this->portal_sync_current_log_id  = $log_id;
		$this->portal_sync_current_run_key = $run_key;
		$this->portal_sync_current_job     = sanitize_key( str_replace( '.', '_', $type ) );

		if ( '' !== $stripe_customer_id && 0 === strpos( $stripe_customer_id, 'cus_' ) ) {
			$result = $this->sync_single_portal_stripe_customer( $secret_key, $stripe_customer_id );
		} else {
			$customer_result = $this->sync_portal_stripe_customers( $secret_key );
			$result = is_wp_error( $customer_result ) ? $customer_result : $this->sync_portal_stripe_transactions( $secret_key );
		}

		if ( ! is_wp_error( $result ) ) {
			$result = absint( $result ) + absint( $deferred_one_time_result );
			$this->backfill_portal_service_requests_from_ledger();
			$this->cleanup_stale_pending_checkout_service_requests();
		}

		$this->write_portal_sync_log(
			$run_key,
			'webhook',
			sanitize_key( str_replace( '.', '_', $type ) ),
			is_wp_error( $result ) ? 'failed' : 'success',
			is_wp_error( $result ) ? 0 : absint( $result ),
			$this->get_portal_sync_message( is_wp_error( $result ) ? $result->get_error_message() : sprintf( __( 'Stripe webhook %s processed.', 'ajforms' ), $type ), $this->portal_sync_stats ),
			$log_id
		);

		$this->portal_sync_current_log_id  = 0;
		$this->portal_sync_current_run_key = '';
		$this->portal_sync_current_job     = '';

		if ( is_wp_error( $result ) ) {
			$this->mark_stripe_event_failed( $event_id, $result->get_error_message() );
			$this->log_portal_event(
				'webhook_failed',
				array(
					'severity' => 'error',
					'source'   => 'webhook',
					'details'  => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id, 'error' => $result->get_error_message() ),
				)
			);
			status_header( 500 );
			wp_send_json_error( array( 'message' => $result->get_error_message() ) );
		}

		$this->mark_stripe_event_processed( $event_id );
		$this->log_portal_event(
			'webhook_processed',
			array(
				'source'  => 'webhook',
				'details' => array( 'event_id' => $event_id, 'event_type' => $type, 'object_id' => $object_id, 'records' => absint( $result ) ),
			)
		);
		wp_send_json_success( array( 'message' => 'processed', 'records' => absint( $result ) ) );
	}

	private function sync_single_portal_stripe_customer( $secret_key, $stripe_customer_id ) {
		$stripe_customer_id = sanitize_text_field( (string) $stripe_customer_id );
		if ( '' === $stripe_customer_id ) {
			return new WP_Error( 'missing_customer', __( 'Stripe customer ID is required.', 'ajforms' ) );
		}

		if ( ! $this->is_real_stripe_customer_id( $stripe_customer_id ) ) {
			return new WP_Error( 'guest_customer_sync_disabled', __( 'Guest buyer records are no longer imported. Portal sync now imports Stripe Customer records only.', 'ajforms' ) );
		}

		$customer = $this->stripe_api_get( 'customers/' . rawurlencode( $stripe_customer_id ), $secret_key );
		if ( is_wp_error( $customer ) ) {
			return $customer;
		}

		if ( empty( $customer['id'] ) || ! empty( $customer['deleted'] ) ) {
			return new WP_Error( 'customer_not_found', __( 'Stripe customer was not found.', 'ajforms' ) );
		}

		$pdb            = $this->get_pdb();
		$customer_table = $this->get_portal_stripe_customers_table();
		$cols           = $pdb->get_col( "SHOW COLUMNS FROM `{$customer_table}` LIKE 'description'" );
		if ( empty( $cols ) ) {
			$pdb->query( "ALTER TABLE `{$customer_table}` ADD COLUMN `description` varchar(500) NOT NULL DEFAULT '' AFTER `phone`" );
		}

		$customer_record = array(
				'stripe_customer_id' => sanitize_text_field( (string) $customer['id'] ),
				'email'              => ! empty( $customer['email'] ) ? sanitize_email( (string) $customer['email'] ) : '',
				'name'               => ! empty( $customer['name'] ) ? sanitize_text_field( (string) $customer['name'] ) : '',
				'phone'              => ! empty( $customer['phone'] ) ? sanitize_text_field( (string) $customer['phone'] ) : '',
				'description'        => ! empty( $customer['description'] ) ? sanitize_text_field( (string) $customer['description'] ) : '',
				'address'            => ! empty( $customer['address'] ) ? wp_json_encode( $customer['address'] ) : '',
				'metadata'           => ! empty( $customer['metadata'] ) ? wp_json_encode( $customer['metadata'] ) : '',
				'raw_data'           => wp_json_encode( $customer ),
				'livemode'           => ! empty( $customer['livemode'] ) ? 1 : 0,
				'created_at'         => ! empty( $customer['created'] ) ? $this->stripe_timestamp_to_mysql( $customer['created'] ) : null,
				'synced_at'          => current_time( 'mysql' ),
			);
		$metadata_partner = ! empty( $customer['metadata']['partner_key'] ) ? sanitize_key( (string) $customer['metadata']['partner_key'] ) : '';
		if ( in_array( $metadata_partner, array( 'opus', 'alliance_vo' ), true ) ) {
			$customer_record['partner_key'] = $metadata_partner;
		}
		$this->upsert_portal_stripe_customer_record(
			$customer_record,
			array( '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%s', '%d', '%s', '%s', '%s' )
		);

		$subscription_count = $this->sync_portal_stripe_subscriptions( $secret_key, $stripe_customer_id );
		if ( is_wp_error( $subscription_count ) ) {
			return $subscription_count;
		}

		$transaction_count = $this->sync_portal_stripe_transactions( $secret_key, $stripe_customer_id );
		if ( is_wp_error( $transaction_count ) ) {
			return $transaction_count;
		}

		return 1 + absint( $subscription_count ) + absint( $transaction_count );
	}

	public function disable_stripe_customer_portal_access( $stripe_customer_id, $portal_status = 'disabled' ) {
		global $wpdb;

		$stripe_customer_id = sanitize_text_field( (string) $stripe_customer_id );
		$portal_status      = in_array( $this->normalize_portal_customer_status( $portal_status ), array( 'disabled', 'archived', 'without_portal_login' ), true ) ? $this->normalize_portal_customer_status( $portal_status ) : 'disabled';
		$mapping = $wpdb->get_row(
			$wpdb->prepare(
				"SELECT * FROM {$this->get_portal_user_mappings_table()} WHERE stripe_customer_id = %s",
				$stripe_customer_id
			)
		);

		if ( $mapping && ! empty( $mapping->user_id ) ) {
			$user = get_userdata( (int) $mapping->user_id );
			if ( $user && in_array( 'aj_portal_user', (array) $user->roles, true ) ) {
				$user->remove_role( 'aj_portal_user' );
				$this->log_portal_event(
					'role_removed',
					array(
						'stripe_customer_id' => $stripe_customer_id,
						'wp_user_id_before'  => (int) $user->ID,
						'email_before'       => $user->user_email,
						'details'            => array( 'role' => 'aj_portal_user' ),
					)
				);
			}
		}

		return $this->set_portal_customer_status(
			$stripe_customer_id,
			$portal_status,
			$portal_status,
			'portal_users',
			array( 'role_removed_if_present' => true )
		);
	}

	/** Resolves the From email/name for a branded email, preferring a per-email-type override
	 *  (e.g. lead_followup_from_email) when set and valid, otherwise falling back to the global
	 *  "System From Email/Name" settings (and finally hardcoded safe defaults). Lets an admin route
	 *  one email type — e.g. Lead Follow-up — through a different inbox like contactus@ without
	 *  affecting the others. */
	private function resolve_email_sender( $settings, $from_email_key = '', $from_name_key = '' ) {
		$from_email = '';
		if ( '' !== $from_email_key && ! empty( $settings[ $from_email_key ] ) ) {
			$candidate = sanitize_email( (string) $settings[ $from_email_key ] );
			if ( is_email( $candidate ) ) {
				$from_email = $candidate;
			}
		}
		if ( '' === $from_email ) {
			$from_email = ! empty( $settings['wp_email_from_email'] ) ? sanitize_email( (string) $settings['wp_email_from_email'] ) : ( defined( 'AJCORE_SYSTEM_FROM_EMAIL' ) ? sanitize_email( AJCORE_SYSTEM_FROM_EMAIL ) : 'donotreply@ncllcagents.com' );
		}
		if ( ! is_email( $from_email ) ) {
			$from_email = 'donotreply@ncllcagents.com';
		}

		$from_name = '';
		if ( '' !== $from_name_key && ! empty( $settings[ $from_name_key ] ) ) {
			$from_name = sanitize_text_field( (string) $settings[ $from_name_key ] );
		}
		if ( '' === $from_name ) {
			$from_name = ! empty( $settings['wp_email_from_name'] ) ? sanitize_text_field( (string) $settings['wp_email_from_name'] ) : ( ! empty( $settings['default_from_name'] ) ? sanitize_text_field( (string) $settings['default_from_name'] ) : wp_specialchars_decode( get_bloginfo( 'name' ), ENT_QUOTES ) );
		}

		return array(
			'from_email' => $from_email,
			'from_name'  => $from_name,
		);
	}

	/** Resolves the editable heading + body-paragraphs for a branded email from plugin settings,
	 *  falling back to the built-in defaults when the admin hasn't customized them. Body text is
	 *  stored as one paragraph per line in a textarea; tokens like {name} are substituted in both
	 *  the heading and every paragraph (custom or default) so admins can reword copy without
	 *  breaking the dynamic bits. Shared by every send_* function and by the Settings page preview. */
	private function resolve_email_copy( $settings, $heading_key, $body_key, $default_heading, $default_body_lines, $tokens ) {
		$heading = ! empty( $settings[ $heading_key ] ) ? sanitize_text_field( (string) $settings[ $heading_key ] ) : $default_heading;
		$heading = strtr( $heading, $tokens );

		$body_raw = isset( $settings[ $body_key ] ) ? trim( (string) $settings[ $body_key ] ) : '';
		$lines    = array();
		if ( '' !== $body_raw ) {
			foreach ( preg_split( '/\r\n|\r|\n/', $body_raw ) as $line ) {
				$line = trim( $line );
				if ( '' !== $line ) {
					$lines[] = $line;
				}
			}
		}
		if ( empty( $lines ) ) {
			$lines = $default_body_lines;
		}

		$paragraphs = array();
		foreach ( $lines as $line ) {
			$paragraphs[] = strtr( $line, $tokens );
		}

		return array( 'heading' => $heading, 'paragraphs' => $paragraphs );
	}

	/** Shared branded-email HTML shell (gradient top bar, white card, kicker/heading/body,
	 *  optional info box + CTA button + fallback link + footer note) used by every AJ Core
	 *  system email so the visual design only needs to change in one place. All string args
	 *  are plain text (translated but unescaped) — this method handles escaping itself so
	 *  callers can safely pass user-submitted values (e.g. a lead's name) without remembering to. */
	private function render_branded_email_html( $args ) {
		$a = wp_parse_args(
			$args,
			array(
				'kicker'          => '',
				'heading'         => '',
				'paragraphs'      => array(),
				'info_box_label'  => '',
				'info_box_value'  => '',
				'info_box_layout' => 'inline', // 'inline' => "Label: value", 'stacked' => "Label\nvalue"
				'cta_text'        => '',
				'cta_url'         => '',
				'fallback_note'   => '',
				'footer_note'     => '',
			)
		);

		$paragraphs_html = '';
		foreach ( (array) $a['paragraphs'] as $p ) {
			$p = trim( (string) $p );
			if ( '' === $p ) {
				continue;
			}
			$paragraphs_html .= '<p style="margin:0 0 18px;font-size:16px;line-height:1.6;color:#475569;">' . esc_html( $p ) . '</p>';
		}

		$info_box_html = '';
		if ( '' !== (string) $a['info_box_value'] ) {
			$info_box_style = 'margin:0 0 28px;padding:14px 16px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;font-size:16px;line-height:1.55;color:#0f172a;';
			if ( 'stacked' === $a['info_box_layout'] ) {
				$info_box_html = '<p style="' . $info_box_style . '">'
					. ( '' !== (string) $a['info_box_label'] ? '<strong>' . esc_html( $a['info_box_label'] ) . '</strong><br>' : '' )
					. esc_html( $a['info_box_value'] ) . '</p>';
			} else {
				$info_box_html = '<p style="' . $info_box_style . '">'
					. ( '' !== (string) $a['info_box_label'] ? '<strong>' . esc_html( $a['info_box_label'] ) . ':</strong> ' : '' )
					. esc_html( $a['info_box_value'] ) . '</p>';
			}
		}

		$cta_html      = '';
		$fallback_html = '';
		if ( '' !== (string) $a['cta_url'] && '' !== (string) $a['cta_text'] ) {
			$cta_html = '<p style="margin:0 0 28px;"><a href="' . esc_url( $a['cta_url'] ) . '" style="display:inline-block;background:#3157ff;color:#ffffff;text-decoration:none;border-radius:999px;padding:14px 24px;font-size:16px;font-weight:800;box-shadow:0 12px 28px rgba(49,87,255,.28);">' . esc_html( $a['cta_text'] ) . '</a></p>';
			if ( '' !== (string) $a['fallback_note'] ) {
				$fallback_html = '<p style="margin:0 0 8px;font-size:13px;line-height:1.5;color:#64748b;">' . esc_html( $a['fallback_note'] ) . '</p>'
					. '<p style="margin:0;padding:14px 16px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;font-size:14px;line-height:1.55;word-break:break-all;"><a href="' . esc_url( $a['cta_url'] ) . '" style="color:#2563eb;text-decoration:underline;">' . esc_html( $a['cta_url'] ) . '</a></p>';
			}
		}

		$footer_html = '';
		if ( '' !== (string) $a['footer_note'] ) {
			$footer_html = '<p style="margin:24px 0 0;font-size:13px;line-height:1.5;color:#64748b;">' . esc_html( $a['footer_note'] ) . '</p>';
		}

		return sprintf(
			'<!doctype html><html><body style="margin:0;padding:0;background:#f6f8fc;color:#0f172a;font-family:Arial,Helvetica,sans-serif;">
				<table role="presentation" width="100%%" cellspacing="0" cellpadding="0" style="background:#f6f8fc;padding:32px 16px;">
					<tr>
						<td align="center">
							<table role="presentation" width="100%%" cellspacing="0" cellpadding="0" style="max-width:640px;background:#ffffff;border:1px solid #dbe7f3;border-radius:24px;overflow:hidden;box-shadow:0 18px 48px rgba(15,23,42,.10);">
								<tr>
									<td style="height:8px;background:linear-gradient(90deg,#06b6d4,#3157ff,#7c3aed);font-size:0;line-height:0;">&nbsp;</td>
								</tr>
								<tr>
									<td style="padding:34px 34px 30px;">
										<p style="margin:0 0 10px;color:#2563eb;font-size:13px;font-weight:800;letter-spacing:.08em;text-transform:uppercase;">%1$s</p>
										<h1 style="margin:0 0 16px;font-size:28px;line-height:1.15;color:#0f172a;">%2$s</h1>
										%3$s%4$s%5$s%6$s
									</td>
								</tr>
							</table>
						</td>
					</tr>
				</table>
			</body></html>',
			esc_html( $a['kicker'] ),
			esc_html( $a['heading'] ),
			$paragraphs_html,
			$info_box_html,
			$cta_html,
			$fallback_html . $footer_html
		);
	}

	/**
	 * The static (non-editable-via-Settings) render_branded_email_html() args for each branded
	 * email template — everything besides heading/paragraphs (already shared via
	 * resolve_email_copy()) and the per-send dynamic values (cta_url, info_box_value, etc).
	 *
	 * Both the real sending function AND the Settings page's "Preview email" panel call these, so
	 * there is exactly one place to edit a footer note, info box label, or button text — previously
	 * each was hardcoded twice (once per call site) and could silently drift out of sync, which is
	 * exactly what happened when a footer note was added to the send function but not the preview.
	 */
	private function get_password_reset_email_static_parts() {
		return array(
			'cta_text'      => __( 'Set New Password', 'ajforms' ),
			'fallback_note' => __( 'If the button does not work, copy and paste this link into your browser:', 'ajforms' ),
			'footer_note'   => __( 'If you did not request this email, you can ignore it.', 'ajforms' ),
		);
	}

