	/**
	 * The product type's own forward-pipeline steps, with no injected fallback for the request's
	 * current status — unlike get_portal_service_request_service_status_options() below, which
	 * prepends the current status when it isn't naturally in this list (so the save dropdown always
	 * has *something* selected for legacy/out-of-band data). Callers that need to distinguish "this
	 * is a real pipeline step" from "this was only added so the UI has somewhere to show a stale
	 * value" — see is_service_request_status_in_pipeline_for_ops() — should use this method instead.
	 */
	private function get_portal_service_request_native_service_status_options( $request ) {
		$product_type = $this->get_portal_service_request_product_type( $request );
		$labels       = $this->get_portal_sr_service_status_labels();

		$sets = array(
			// This bundle always includes a year of Registered Agent service alongside the one-time
			// entity setup, so it never truly "completes" — it settles into "active" like a standalone
			// Registered Agent Subscription would.
			'llc_setup' => array(
				'new',
				'meeting_scheduled',
				'sosnc_filing',
				'llc_documents_emailed',
				'active',
				'cancelled',
			),
			// Also always bundled with a year of Virtual Office Subscription — settles into "active"
			// once the one-time ID/address proof setup is done, same reasoning as llc_setup above.
			'virtual_office_setup' => array(
				'new',
				'signing_cmra',
				'id_proof_needed',
				'address_proof_needed',
				'active',
				'cancelled',
			),
			// Buying this subscription means one thing: get the CMRA signed, then it's active — no other steps.
			'virtual_office_subscription' => array(
				'new',
				'signing_cmra',
				'active',
				'cancelled',
			),
			// Buying this subscription means one thing: update the registered agent on SOS/NC (we do it, or the
			// customer does it), then it's active — no other steps.
			'registered_agent_subscription' => array(
				'new',
				'updating_sosn',
				'active',
				'cancelled',
			),
			'custom_request' => array(
				'new',
				'under_review',
				'pending_customer',
				'pending_agent',
				'active',
				'completed',
				'cancelled',
			),
		);

		$keys = isset( $sets[ $product_type ] ) ? $sets[ $product_type ] : $sets['custom_request'];
		$options = array();
		foreach ( $keys as $key ) {
			if ( isset( $labels[ $key ] ) ) {
				$options[ $key ] = $labels[ $key ];
			}
		}

		return $options;
	}

	private function get_portal_service_request_service_status_options( $request ) {
		$options = $this->get_portal_service_request_native_service_status_options( $request );
		$labels  = $this->get_portal_sr_service_status_labels();

		$current = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		if ( '' !== $current && isset( $labels[ $current ] ) && ! isset( $options[ $current ] ) ) {
			$options = array( $current => $labels[ $current ] ) + $options;
		}

		return $options;
	}

	/** Emails the customer when the workflow status of their service request changes. */
	private function send_service_request_status_email( $request, $old_service_status, $new_service_status ) {
		$old_service_status = sanitize_key( (string) $old_service_status );
		$new_service_status = sanitize_key( (string) $new_service_status );
		if ( $old_service_status === $new_service_status ) {
			return;
		}
		$this->send_service_request_status_email_now( $request, $new_service_status );
	}

	/**
	 * Sends the status-update email for the CURRENT service_status regardless of whether it just
	 * changed — the on-demand path staff use to notify a customer about a status that was already
	 * set silently (SVC Status defaults to no email; see update_service_request_from_ops()). Shares
	 * every template/branding detail with send_service_request_status_email() above, which only
	 * differs by the old!==new guard before deciding to call this.
	 */
	private function send_service_request_status_email_now( $request, $service_status ) {
		$new_service_status = sanitize_key( (string) $service_status );
		$labels = $this->get_portal_sr_service_status_labels();
		if ( ! isset( $labels[ $new_service_status ] ) ) {
			return false;
		}

		$customer = $this->get_pdb()->get_row(
			$this->get_pdb()->prepare(
				"SELECT name, email FROM {$this->get_portal_stripe_customers_table()} WHERE stripe_customer_id = %s LIMIT 1",
				sanitize_text_field( (string) $request->stripe_customer_id )
			)
		);
		if ( ! $customer || ! is_email( (string) $customer->email ) ) {
			return false;
		}

		$settings   = $this->get_plugin_settings();
		$sender     = $this->resolve_email_sender( $settings, 'wp_service_status_from_email', 'wp_service_status_from_name' );
		$from_email = $sender['from_email'];
		$from_name  = $sender['from_name'];
		$site_name  = wp_specialchars_decode( get_bloginfo( 'name' ), ENT_QUOTES );

		$service_name    = sanitize_text_field( (string) $request->service_name );
		$status_label    = $labels[ $new_service_status ];
		$service_display = '' !== $service_name ? $service_name : __( 'your service request', 'ajforms' );
		$subject_template = ! empty( $settings['wp_service_status_subject'] ) ? sanitize_text_field( (string) $settings['wp_service_status_subject'] ) : __( 'Update on {service_name}: {status_label}', 'ajforms' );
		$email_tokens     = array(
			'{name}'          => ! empty( $customer->name ) ? $customer->name : $customer->email,
			'{service_name}'  => $service_display,
			'{status_label}'  => $status_label,
		);
		$subject = strtr( $subject_template, $email_tokens );

		$copy = $this->resolve_email_copy(
			$settings,
			'wp_service_status_heading',
			'wp_service_status_body',
			__( 'Your service request was updated', 'ajforms' ),
			array(
				sprintf( __( 'Hi %s,', 'ajforms' ), '{name}' ),
				sprintf( __( 'The status of "%s" has changed.', 'ajforms' ), '{service_name}' ),
			),
			$email_tokens
		);

		$message = $this->render_branded_email_html( array_merge(
			array(
				'kicker'         => $site_name,
				'heading'        => $copy['heading'],
				'paragraphs'     => $copy['paragraphs'],
				'info_box_value' => $status_label,
			),
			$this->get_service_request_status_email_static_parts()
		) );

		$headers = array( 'Content-Type: text/html; charset=UTF-8' );
		if ( is_email( $from_email ) ) {
			$headers[] = 'From: ' . $from_name . ' <' . $from_email . '>';
			$headers[] = 'Reply-To: ' . $from_email;
		}

		return (bool) wp_mail( $customer->email, $subject, $message, $headers );
	}

	/**
	 * Public entry point for the ops REST API — the "ability to send those notifications" on
	 * demand: emails the customer about the request's CURRENT service_status, independent of
	 * whether it just changed. Used when staff want to notify after the fact for a status that was
	 * set silently (the default), rather than only ever at the moment of the change.
	 */
	public function notify_service_request_status_for_ops( $request_id ) {
		$pdb        = $this->get_pdb();
		$request_id = absint( $request_id );
		$request    = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d", $request_id ) );
		if ( ! $request ) {
			return new WP_Error( 'not_found', __( 'Service request not found.', 'ajforms' ) );
		}

		$service_status = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		$sent           = $this->send_service_request_status_email_now( $request, $service_status );
		if ( ! $sent ) {
			return new WP_Error( 'send_failed', __( 'Could not send the notification — check the customer has a valid email on file.', 'ajforms' ) );
		}

		$this->add_portal_service_request_history(
			$request_id,
			'status_changed',
			array(
				'status_before'         => sanitize_key( (string) $request->status ),
				'status_after'          => sanitize_key( (string) $request->status ),
				'service_status_before' => $service_status,
				'service_status_after'  => $service_status,
				'note'                  => __( 'Customer manually notified of the current status.', 'ajforms' ),
				'details'               => array( 'source' => 'manual_notify' ),
			)
		);

		return true;
	}

	/**
	 * Public entry point for the ops REST API — notifies a client that a piece of physical
	 * mail was received for them at the office. Service-of-process items get an urgent
	 * subject and copy because timely delivery is the registered agent's legal obligation.
	 *
	 * @param array  $item           Mail item row (mail_type, is_sop, sender_name, received_at, scan_url).
	 * @param string $customer_name  Display name for the greeting.
	 * @param string $customer_email Destination address.
	 * @return bool Whether wp_mail() accepted the message.
	 */
	public function send_mail_item_notification_for_ops( $item, $customer_name, $customer_email ) {
		$customer_email = sanitize_email( (string) $customer_email );
		if ( ! is_email( $customer_email ) ) {
			return false;
		}

		$settings  = $this->get_plugin_settings();
		$sender    = $this->resolve_email_sender( $settings, 'wp_mail_item_from_email', 'wp_mail_item_from_name' );
		$site_name = wp_specialchars_decode( get_bloginfo( 'name' ), ENT_QUOTES );

		$is_sop      = ! empty( $item['is_sop'] );
		$type_labels = array(
			'letter'     => __( 'Letter', 'ajforms' ),
			'legal'      => __( 'Legal document', 'ajforms' ),
			'government' => __( 'Government notice', 'ajforms' ),
			'package'    => __( 'Package', 'ajforms' ),
			'check'      => __( 'Check', 'ajforms' ),
			'other'      => __( 'Mail item', 'ajforms' ),
		);
		$mail_type  = isset( $item['mail_type'] ) ? sanitize_key( (string) $item['mail_type'] ) : 'letter';
		$type_label = isset( $type_labels[ $mail_type ] ) ? $type_labels[ $mail_type ] : $type_labels['other'];

		$received_at = ! empty( $item['received_at'] ) ? mysql2date( get_option( 'date_format' ), (string) $item['received_at'] ) : '';
		$sender_name = ! empty( $item['sender_name'] ) ? sanitize_text_field( (string) $item['sender_name'] ) : '';

		$email_tokens = array(
			'{name}'        => '' !== trim( (string) $customer_name ) ? $customer_name : $customer_email,
			'{mail_type}'   => $type_label,
			'{sender_name}' => '' !== $sender_name ? $sender_name : __( 'an unlisted sender', 'ajforms' ),
			'{received_at}' => $received_at,
		);

		if ( $is_sop ) {
			$default_subject = __( 'URGENT: Legal document received for you — {mail_type}', 'ajforms' );
			$default_heading = __( 'A legal document was delivered to your registered agent', 'ajforms' );
			$default_body    = array(
				sprintf( __( 'Hi %s,', 'ajforms' ), '{name}' ),
				__( 'We received service of process or another time-sensitive legal document addressed to you: {mail_type} from {sender_name}.', 'ajforms' ),
				__( 'Legal documents often carry response deadlines. Please review it as soon as possible.', 'ajforms' ),
			);
			$subject_key = 'wp_mail_item_sop_subject';
			$heading_key = 'wp_mail_item_sop_heading';
			$body_key    = 'wp_mail_item_sop_body';
		} else {
			$default_subject = __( 'New mail received for you: {mail_type}', 'ajforms' );
			$default_heading = __( 'You have new mail at our office', 'ajforms' );
			$default_body    = array(
				sprintf( __( 'Hi %s,', 'ajforms' ), '{name}' ),
				__( 'We received a {mail_type} addressed to you from {sender_name}.', 'ajforms' ),
			);
			$subject_key = 'wp_mail_item_subject';
			$heading_key = 'wp_mail_item_heading';
			$body_key    = 'wp_mail_item_body';
		}

		$subject_template = ! empty( $settings[ $subject_key ] ) ? sanitize_text_field( (string) $settings[ $subject_key ] ) : $default_subject;
		$subject          = strtr( $subject_template, $email_tokens );

		$copy = $this->resolve_email_copy( $settings, $heading_key, $body_key, $default_heading, $default_body, $email_tokens );

		$info_value = $type_label
			. ( '' !== $sender_name ? ' — ' . sprintf( __( 'from %s', 'ajforms' ), $sender_name ) : '' )
			. ( '' !== $received_at ? ' — ' . sprintf( __( 'received %s', 'ajforms' ), $received_at ) : '' );

		$scan_url = ! empty( $item['scan_url'] ) ? esc_url_raw( (string) $item['scan_url'] ) : '';

		$message = $this->render_branded_email_html(
			array(
				'kicker'         => $site_name,
				'heading'        => $copy['heading'],
				'paragraphs'     => $copy['paragraphs'],
				'info_box_label' => __( 'Mail item', 'ajforms' ),
				'info_box_value' => $info_value,
				'cta_text'       => '' !== $scan_url ? __( 'View Scanned Document', 'ajforms' ) : '',
				'cta_url'        => $scan_url,
				'footer_note'    => __( 'Log in to your client portal to view your mailbox and manage this item.', 'ajforms' ),
			)
		);

		$headers = array( 'Content-Type: text/html; charset=UTF-8' );
		if ( is_email( $sender['from_email'] ) ) {
			$headers[] = 'From: ' . $sender['from_name'] . ' <' . $sender['from_email'] . '>';
			$headers[] = 'Reply-To: ' . $sender['from_email'];
		}

		return (bool) wp_mail( $customer_email, $subject, $message, $headers );
	}

	/**
	 * Branded compliance-deadline reminder (annual report). Used by the ops REST
	 * "Remind now" action and the daily reminder cron.
	 */
	public function send_compliance_reminder_for_ops( $entity, $filing, $customer_name, $customer_email ) {
		$customer_email = sanitize_email( (string) $customer_email );
		if ( ! is_email( $customer_email ) ) {
			return false;
		}

		$settings  = $this->get_plugin_settings();
		$sender    = $this->resolve_email_sender( $settings, 'wp_compliance_from_email', 'wp_compliance_from_name' );
		$site_name = wp_specialchars_decode( get_bloginfo( 'name' ), ENT_QUOTES );

		$due_date  = mysql2date( get_option( 'date_format' ), (string) $filing->due_date . ' 00:00:00' );
		$days_left = (int) floor( ( strtotime( (string) $filing->due_date ) - strtotime( gmdate( 'Y-m-d' ) ) ) / DAY_IN_SECONDS );
		$overdue   = $days_left < 0;

		$email_tokens = array(
			'{name}'        => '' !== trim( (string) $customer_name ) ? $customer_name : $customer_email,
			'{entity_name}' => (string) $entity->entity_name,
			'{year}'        => (string) $filing->period_year,
			'{due_date}'    => $due_date,
			'{state}'       => (string) $entity->jurisdiction,
		);

		if ( $overdue ) {
			$default_subject = __( 'OVERDUE: {year} {state} Annual Report for {entity_name}', 'ajforms' );
			$default_heading = __( 'The annual report for {entity_name} is past due', 'ajforms' );
			$default_body    = array(
				sprintf( __( 'Hi %s,', 'ajforms' ), '{name}' ),
				__( 'The {year} annual report for {entity_name} was due {due_date} and has not been filed with the {state} Secretary of State.', 'ajforms' ),
				__( 'A missed annual report can lead to administrative dissolution. We can prepare and file it for you — reply to this email or contact us to get it taken care of.', 'ajforms' ),
			);
			$subject_key = 'wp_compliance_overdue_subject';
			$heading_key = 'wp_compliance_overdue_heading';
			$body_key    = 'wp_compliance_overdue_body';
		} else {
			$default_subject = __( 'Reminder: {year} {state} Annual Report for {entity_name} is due {due_date}', 'ajforms' );
			$default_heading = __( 'An annual report deadline is coming up', 'ajforms' );
			$default_body    = array(
				sprintf( __( 'Hi %s,', 'ajforms' ), '{name}' ),
				__( 'The {year} annual report for {entity_name} is due {due_date} with the {state} Secretary of State.', 'ajforms' ),
				__( 'We can prepare and file it for you so nothing slips — reply to this email or contact us and we will handle the rest.', 'ajforms' ),
			);
			$subject_key = 'wp_compliance_reminder_subject';
			$heading_key = 'wp_compliance_reminder_heading';
			$body_key    = 'wp_compliance_reminder_body';
		}

		$subject_template = ! empty( $settings[ $subject_key ] ) ? sanitize_text_field( (string) $settings[ $subject_key ] ) : $default_subject;
		$subject          = strtr( $subject_template, $email_tokens );

		$copy = $this->resolve_email_copy( $settings, $heading_key, $body_key, $default_heading, $default_body, $email_tokens );

		$info_value = sprintf(
			/* translators: 1: entity name, 2: report year, 3: due date */
			__( '%1$s — %2$s annual report — due %3$s', 'ajforms' ),
			(string) $entity->entity_name,
			(string) $filing->period_year,
			$due_date
		);

		$message = $this->render_branded_email_html(
			array(
				'kicker'         => $site_name,
				'heading'        => $copy['heading'],
				'paragraphs'     => $copy['paragraphs'],
				'info_box_label' => __( 'Deadline', 'ajforms' ),
				'info_box_value' => $info_value,
				'footer_note'    => __( 'You are receiving this because we serve as registered agent for this entity.', 'ajforms' ),
			)
		);

		$headers = array( 'Content-Type: text/html; charset=UTF-8' );
		if ( is_email( $sender['from_email'] ) ) {
			$headers[] = 'From: ' . $sender['from_name'] . ' <' . $sender['from_email'] . '>';
			$headers[] = 'Reply-To: ' . $sender['from_email'];
		}

		return (bool) wp_mail( $customer_email, $subject, $message, $headers );
	}

	/**
	 * Daily cron: walk pending filings and email the linked customer as each
	 * reminder window opens (60/30/14/7 days out, then overdue). Stage tracking on
	 * the filing row makes the job idempotent — each window fires at most once.
	 */
	public function run_compliance_reminder_job() {
		if ( '1' !== (string) get_option( 'ajcore_compliance_reminders_enabled', '1' ) ) {
			return;
		}
		if ( function_exists( 'ajcore_is_stripe_sync_owner' ) && ! ajcore_is_stripe_sync_owner() ) {
			return;
		}

		$pdb         = $this->get_pdb();
		$t_entities  = $pdb->prefix . 'aj_portal_compliance_entities';
		$t_filings   = $pdb->prefix . 'aj_portal_compliance_filings';
		$t_customers = $pdb->prefix . 'aj_portal_stripe_customers';
		if ( $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $t_filings ) ) !== $t_filings ) {
			return;
		}

		// Seed the current year's filing row for any active entity missing one, so
		// reminders fire after Jan 1 even if nobody has opened the ops calendar yet.
		$current_year = (int) gmdate( 'Y' );
		$entities     = $pdb->get_results( "SELECT * FROM `{$t_entities}` WHERE entity_status = 'active'" );
		foreach ( (array) $entities as $entity ) {
			$year   = max( $current_year, (int) $entity->first_report_year );
			$exists = (int) $pdb->get_var( $pdb->prepare(
				"SELECT COUNT(*) FROM `{$t_filings}` WHERE entity_id = %d AND filing_type = 'annual_report' AND period_year = %d",
				(int) $entity->id,
				$year
			) );
			if ( ! $exists ) {
				$month = max( 1, min( 12, (int) $entity->due_month ) );
				$day   = max( 1, min( 28, (int) $entity->due_day ) );
				$pdb->query( $pdb->prepare(
					"INSERT IGNORE INTO `{$t_filings}` (entity_id, filing_type, period_year, due_date) VALUES (%d, 'annual_report', %d, %s)",
					(int) $entity->id,
					$year,
					sprintf( '%04d-%02d-%02d', $year, $month, $day )
				) );
			}
		}

		$horizon = gmdate( 'Y-m-d', time() + 60 * DAY_IN_SECONDS );
		$rows    = $pdb->get_results( $pdb->prepare(
			"SELECT f.*, e.entity_name, e.jurisdiction, e.stripe_customer_id, c.name AS customer_name, c.email AS customer_email
			FROM `{$t_filings}` f
			INNER JOIN `{$t_entities}` e ON e.id = f.entity_id AND e.entity_status = 'active'
			LEFT JOIN `{$t_customers}` c ON c.stripe_customer_id = e.stripe_customer_id
			WHERE f.status = 'pending' AND f.client_completed = 0 AND f.due_date <= %s
			ORDER BY f.due_date ASC
			LIMIT 500",
			$horizon
		) );

		$stage_rank = array( '' => 0, '60d' => 1, '30d' => 2, '14d' => 3, '7d' => 4, 'overdue' => 5 );
		$today_ts   = strtotime( gmdate( 'Y-m-d' ) );

		foreach ( (array) $rows as $row ) {
			if ( ! is_email( (string) $row->customer_email ) ) {
				continue;
			}

			$days_left = (int) floor( ( strtotime( (string) $row->due_date ) - $today_ts ) / DAY_IN_SECONDS );
			if ( $days_left < 0 ) {
				$desired = 'overdue';
			} elseif ( $days_left <= 7 ) {
				$desired = '7d';
			} elseif ( $days_left <= 14 ) {
				$desired = '14d';
			} elseif ( $days_left <= 30 ) {
				$desired = '30d';
			} else {
				$desired = '60d';
			}

			$current = isset( $stage_rank[ (string) $row->reminder_stage ] ) ? (string) $row->reminder_stage : '';
			if ( $stage_rank[ $desired ] <= $stage_rank[ $current ] ) {
				continue;
			}

			$sent = $this->send_compliance_reminder_for_ops( $row, $row, (string) $row->customer_name, (string) $row->customer_email );
			if ( $sent ) {
				$pdb->update(
					$t_filings,
					array(
						'reminder_stage'   => $desired,
						'last_reminder_at' => current_time( 'mysql' ),
						'reminders_sent'   => (int) $row->reminders_sent + 1,
					),
					array( 'id' => (int) $row->id ),
					array( '%s', '%s', '%d' ),
					array( '%d' )
				);
			}
		}
	}

	/** Public entry point for the ops REST API — returns the workflow status options for a request. */
	public function get_service_request_service_status_options_for_ops( $request ) {
		return $this->get_portal_service_request_service_status_options( $request );
	}

	/**
	 * Public entry point for the ops REST API — true when the request's current service_status is
	 * one of its product type's normal forward-pipeline steps, false for a legacy/out-of-band value
	 * (e.g. 'completed' on a bundled llc_setup or virtual_office_setup request, which per product
	 * design settles at 'active' instead — see get_portal_service_request_native_service_status_options()).
	 * Lets AJOps render such a request without implying it's "step 1" of its own forward pipeline.
	 */
	public function is_service_request_status_in_pipeline_for_ops( $request ) {
		$native = $this->get_portal_service_request_native_service_status_options( $request );
		$status = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		return isset( $native[ $status ] );
	}

	/**
	 * Focused update used by the ops REST API: payment status, workflow service_status, admin notes,
	 * and an optional history note. Mirrors the WP admin details-save side effects (ledger sync + history).
	 */
	public function update_service_request_from_ops( $request_id, $fields ) {
		$pdb        = $this->get_pdb();
		$request_id = absint( $request_id );
		$request    = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d", $request_id ) );
		if ( ! $request ) {
			return new WP_Error( 'not_found', __( 'Service request not found.', 'ajforms' ) );
		}

		$fields             = is_array( $fields ) ? $fields : array();
		$old_status         = sanitize_key( (string) $request->status );
		$old_service_status = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';

		$status         = $old_status;
		$service_status = $old_service_status;
		if ( ! empty( $fields['status'] ) && isset( $this->get_portal_service_request_status_labels()[ sanitize_key( (string) $fields['status'] ) ] ) ) {
			$status = sanitize_key( (string) $fields['status'] );
		}
		if ( ! empty( $fields['service_status'] ) && isset( $this->get_portal_sr_service_status_labels()[ sanitize_key( (string) $fields['service_status'] ) ] ) ) {
			$service_status = sanitize_key( (string) $fields['service_status'] );
		}
		$admin_notes = array_key_exists( 'admin_notes', $fields ) && null !== $fields['admin_notes']
			? sanitize_textarea_field( (string) $fields['admin_notes'] )
			: (string) $request->admin_notes;
		$note        = ! empty( $fields['note'] ) ? sanitize_textarea_field( (string) $fields['note'] ) : '';

		$old_assigned_user_id = isset( $request->assigned_user_id ) ? (int) $request->assigned_user_id : 0;
		$assigned_user_id     = $old_assigned_user_id;
		if ( array_key_exists( 'assigned_user_id', $fields ) && null !== $fields['assigned_user_id'] ) {
			$assigned_user_id = absint( $fields['assigned_user_id'] );
		}

		$pdb->update(
			$this->get_portal_service_requests_table(),
			array(
				'status'           => $status,
				'service_status'   => $service_status,
				'admin_notes'      => $admin_notes,
				'assigned_user_id' => $assigned_user_id,
				'updated_at'       => current_time( 'mysql' ),
			),
			array( 'id' => $request_id ),
			array( '%s', '%s', '%s', '%d', '%s' ),
			array( '%d' )
		);

		$request->status           = $status;
		$request->service_status   = $service_status;
		$request->admin_notes      = $admin_notes;
		$request->assigned_user_id = $assigned_user_id;

		$this->sync_portal_service_request_to_ledger(
			$request,
			array(
				'amount'       => (float) $request->amount,
				'currency'     => (string) $request->currency,
				'status'       => $status,
				'client_notes' => (string) $request->client_notes,
				'request_id'   => $request_id,
			)
		);

		if ( $old_status !== $status || $old_service_status !== $service_status ) {
			// SVC Status is mostly internal staff tracking (per explicit user decision) — a customer
			// email only goes out when the caller opts in (notify_customer truthy), not on every
			// change by default. AJOps sends this only when staff explicitly check "Notify customer"
			// or use the dedicated Cancel Request action.
			$notify = ! empty( $fields['notify_customer'] );
			$this->add_portal_service_request_history(
				$request_id,
				'status_changed',
				array(
					'status_before'         => $old_status,
					'status_after'          => $status,
					'service_status_before' => $old_service_status,
					'service_status_after'  => $service_status,
					'note'                  => $notify
						? __( 'Status updated from AJ Ops. Customer notified.', 'ajforms' )
						: __( 'Status updated from AJ Ops.', 'ajforms' ),
					'details'               => array( 'source' => 'ops_api' ),
				)
			);
			if ( $notify ) {
				$this->send_service_request_status_email( $request, $old_service_status, $service_status );
			}
		}
		if ( '' !== $note ) {
			$this->add_portal_service_request_history(
				$request_id,
				'note',
				array(
					'note'                  => $note,
					'status_before'         => $old_status,
					'status_after'          => $status,
					'service_status_before' => $old_service_status,
					'service_status_after'  => $service_status,
				)
			);
		}
		if ( $old_assigned_user_id !== $assigned_user_id ) {
			$this->add_portal_service_request_history(
				$request_id,
				'assigned',
				array(
					'note'    => $this->describe_portal_service_request_assignment_change( $old_assigned_user_id, $assigned_user_id ),
					'details' => array( 'assigned_user_id_before' => $old_assigned_user_id, 'assigned_user_id_after' => $assigned_user_id ),
				)
			);
		}

		return $request;
	}

	private function describe_portal_service_request_assignment_change( $old_user_id, $new_user_id ) {
		$name = function ( $user_id ) {
			if ( ! $user_id ) {
				return __( 'Unassigned', 'ajforms' );
			}
			$user = get_userdata( (int) $user_id );
			return $user ? ( $user->display_name ?: $user->user_login ) : __( 'Unknown user', 'ajforms' );
		};
		return sprintf( __( 'Reassigned from %1$s to %2$s.', 'ajforms' ), $name( $old_user_id ), $name( $new_user_id ) );
	}

	/**
	 * Applies service_status and/or assigned_user_id to several service requests at once — the
	 * bulk-action toolbar on the Service Requests list. Returns per-id results so the caller can
	 * report partial failures.
	 */
	public function bulk_update_service_requests_for_ops( $ids, $fields ) {
		$ids     = array_values( array_filter( array_map( 'absint', (array) $ids ) ) );
		$fields  = is_array( $fields ) ? $fields : array();
		$results = array();
		foreach ( $ids as $id ) {
			$result           = $this->update_service_request_from_ops( $id, $fields );
			$results[ $id ]   = is_wp_error( $result ) ? array( 'success' => false, 'message' => $result->get_error_message() ) : array( 'success' => true );
		}
		return $results;
	}

	private function get_portal_service_request_product_type( $request ) {
		$name_parts = array();
		if ( ! empty( $request->service_name ) ) {
			$name_parts[] = (string) $request->service_name;
		}
		if ( ! empty( $request->stripe_price_id ) ) {
			$product = $this->get_portal_product_by_price_id( sanitize_text_field( (string) $request->stripe_price_id ) );
			if ( $product ) {
				foreach ( array( 'custom_label', 'name', 'description', 'recurring_interval' ) as $field ) {
					if ( ! empty( $product->{$field} ) ) {
						$name_parts[] = (string) $product->{$field};
					}
				}
			}
		}

		$name = strtolower( implode( ' ', array_map( 'sanitize_text_field', $name_parts ) ) );
		$name = str_replace( array( '_', '-' ), ' ', $name );

		if ( false !== strpos( $name, 'llc setup' ) || false !== strpos( $name, 'entity setup' ) || false !== strpos( $name, 'new entity' ) ) {
			return 'llc_setup';
		}
		if ( false !== strpos( $name, 'registered agent' ) ) {
			return 'registered_agent_subscription';
		}
		if ( false !== strpos( $name, 'virtual office' ) ) {
			if ( false !== strpos( $name, 'setup' ) || false !== strpos( $name, 'one time' ) || false !== strpos( $name, 'one-time' ) ) {
				return 'virtual_office_setup';
			}
			return 'virtual_office_subscription';
		}

		return 'custom_request';
	}

	private function get_portal_service_request_quick_actions( $request, $raw_data = array() ) {
		$status           = isset( $request->status ) ? sanitize_key( (string) $request->status ) : '';
		$service_status   = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		$raw_data         = is_array( $raw_data ) ? $raw_data : array();
		$billing_preview  = ! empty( $raw_data['billing_preview'] ) && is_array( $raw_data['billing_preview'] ) ? $raw_data['billing_preview'] : array();
		$source_type      = isset( $request->source_type ) ? sanitize_key( (string) $request->source_type ) : '';
		$ledger_source_type = isset( $request->ledger_source_type ) ? sanitize_key( (string) $request->ledger_source_type ) : '';
		$is_stripe_import = $this->is_portal_service_request_stripe_import( $request );
		$product_type     = $this->get_portal_service_request_product_type( $request );
		$actions          = array();
		$is_paid          = in_array( $status, array( 'paid', 'completed', 'active' ), true );
		$is_terminal      = in_array( $service_status, array( 'completed', 'cancelled' ), true );
		$review_states    = array( 'new', '', 'under_review' );

		if ( ! $is_paid && in_array( $status, array( 'draft', 'pending_payment', 'awaiting_payment', 'failed', 'admin_review_required' ), true ) ) {
			$actions['await_payment'] = __( 'Request Payment', 'ajforms' );
		}

		if ( $is_paid && ! $is_terminal ) {
			if ( in_array( $service_status, $review_states, true ) ) {
				if ( 'llc_setup' === $product_type ) {
					$actions['schedule_meeting'] = __( 'Schedule Meeting', 'ajforms' );
				} elseif ( 'virtual_office_setup' === $product_type ) {
					$actions['sign_cmra'] = __( 'Send CMRA for Signing', 'ajforms' );
				} elseif ( 'virtual_office_subscription' === $product_type ) {
					// One step: get the CMRA signed. Once signed, mark active — no further action.
					$actions['sign_cmra'] = __( 'Send CMRA for Signing', 'ajforms' );
				} elseif ( 'registered_agent_subscription' === $product_type ) {
					// One step: update the registered agent on SOS/NC (staff or customer). Once done, mark active.
					$actions['update_sosn'] = __( 'Update RA on SOS/NC', 'ajforms' );
				} else {
					if ( 'new' === $service_status || '' === $service_status ) {
						$actions['under_review'] = __( 'Start Review', 'ajforms' );
					} else {
						$actions['pending_customer'] = __( 'Pending Customer', 'ajforms' );
						$actions['pending_agent'] = __( 'Pending Agent', 'ajforms' );
						$actions['complete'] = __( 'Mark Completed', 'ajforms' );
					}
				}
			} elseif ( 'meeting_scheduled' === $service_status ) {
				$actions['file_sosnc'] = __( 'File with SOS/NC', 'ajforms' );
			} elseif ( 'sosnc_filing' === $service_status ) {
				$actions['email_llc_documents'] = __( 'Email LLC Documents', 'ajforms' );
			} elseif ( 'llc_documents_emailed' === $service_status ) {
				// The one-time setup work is done, but the bundled Registered Agent year keeps this
				// request ongoing — settle into "active", not "completed".
				$actions['activate'] = __( 'Mark Active', 'ajforms' );
			} elseif ( 'signing_cmra' === $service_status ) {
				if ( 'virtual_office_subscription' === $product_type ) {
					// Subscription flow ends here: CMRA signed → active, no ID/address proof collection step.
					$actions['activate'] = __( 'Mark Active', 'ajforms' );
				} else {
					$actions['collect_id_proof'] = __( 'Collect ID Proof', 'ajforms' );
				}
			} elseif ( 'id_proof_needed' === $service_status ) {
				$actions['collect_address_proof'] = __( 'Collect Address Proof', 'ajforms' );
			} elseif ( 'address_proof_needed' === $service_status ) {
				if ( 'virtual_office_setup' === $product_type ) {
					// Bundled with a year of Virtual Office Subscription — settles into "active", not "completed".
					$actions['activate'] = __( 'Complete Setup', 'ajforms' );
				} else {
					$actions['complete'] = __( 'Mark Completed', 'ajforms' );
				}
			} elseif ( 'vo_setup_required' === $service_status ) {
				$actions['activate'] = __( 'Mark Active', 'ajforms' );
			} elseif ( in_array( $service_status, array( 'sosnc_client', 'updating_sosn', 'included_with_llc_setup' ), true ) ) {
				$actions['activate'] = __( 'Mark Active', 'ajforms' );
			} elseif ( in_array( $service_status, array( 'pending_customer', 'pending_agent' ), true ) ) {
				$actions['complete'] = __( 'Mark Completed', 'ajforms' );
			}
		}

		if (
			! $is_terminal
			&& ! empty( $billing_preview )
			&& ( ! empty( $billing_preview['subscription_id'] ) || ! empty( $billing_preview['subscription_item_id'] ) )
			&& ( ! empty( $billing_preview['new_price_id'] ) || ! empty( $request->stripe_price_id ) )
		) {
			$actions['apply_billing_change'] = __( 'Apply Billing Change', 'ajforms' );
		}

		if ( ! $is_stripe_import && ! $is_terminal ) {
			$actions['cancel'] = __( 'Cancel', 'ajforms' );
		}

		if ( ! $is_stripe_import || 'checkout_session' === $source_type || 'checkout_session' === $ledger_source_type ) {
			$actions['delete'] = __( 'Delete', 'ajforms' );
		}

		return $actions;
	}

	private function is_portal_service_request_stripe_import( $request ) {
		$source_type = isset( $request->source_type ) ? sanitize_key( (string) $request->source_type ) : '';
		$ledger_source_type = isset( $request->ledger_source_type ) ? sanitize_key( (string) $request->ledger_source_type ) : '';
		$stripe_source_types = array( 'checkout_session', 'invoice', 'charge', 'payment', 'payment_intent', 'refund', 'subscription' );

		return in_array( $source_type, $stripe_source_types, true ) || in_array( $ledger_source_type, $stripe_source_types, true );
	}

	private function normalize_portal_service_request_status( $status ) {
		$status = sanitize_key( (string) $status );
		$labels = $this->get_portal_service_request_status_labels();

		return isset( $labels[ $status ] ) ? $status : 'draft';
	}


	private function get_portal_service_request_raw_data( $request ) {
		$raw = isset( $request->raw_data ) ? json_decode( (string) $request->raw_data, true ) : array();

		return is_array( $raw ) ? $raw : array();
	}

	private function get_portal_service_request_meta_value( $request, $key ) {
		$raw = $this->get_portal_service_request_raw_data( $request );

		return isset( $raw[ $key ] ) && is_scalar( $raw[ $key ] ) ? sanitize_text_field( (string) $raw[ $key ] ) : '';
	}

	private function get_portal_service_request_customer_labels( $request ) {
		$company_name = ! empty( $request->customer_name ) ? sanitize_text_field( (string) $request->customer_name ) : '';
		$email        = ! empty( $request->customer_email ) ? sanitize_email( (string) $request->customer_email ) : '';
		if ( '' === $email && ! empty( $request->wp_user_email ) ) {
			$email = sanitize_email( (string) $request->wp_user_email );
		}

		return array(
			'name'  => '' !== $company_name ? $company_name : ( '' !== $email ? $email : sanitize_text_field( (string) $request->stripe_customer_id ) ),
			'email' => '' !== $email ? $email : sanitize_text_field( (string) $request->stripe_customer_id ),
		);
	}

	private function add_portal_service_request_price_id_candidates( $value, &$price_ids ) {
		if ( is_array( $value ) ) {
			foreach ( $value as $nested_value ) {
				$this->add_portal_service_request_price_id_candidates( $nested_value, $price_ids );
			}
			return;
		}

		if ( ! is_scalar( $value ) ) {
			return;
		}

		foreach ( preg_split( '/\s*,\s*/', sanitize_text_field( (string) $value ) ) as $price_id ) {
			if ( preg_match( '/^price_/', $price_id ) && ! in_array( $price_id, $price_ids, true ) ) {
				$price_ids[] = $price_id;
			}
		}
	}

	private function collect_portal_service_request_price_ids_from_data( $data, &$price_ids ) {
		if ( ! is_array( $data ) ) {
			return;
		}

		foreach ( array( 'price_id', 'stripe_price_id', 'price_ids', 'ajcore_one_time_price_ids' ) as $key ) {
			if ( isset( $data[ $key ] ) ) {
				$this->add_portal_service_request_price_id_candidates( $data[ $key ], $price_ids );
			}
		}

		if ( ! empty( $data['price'] ) && is_array( $data['price'] ) && ! empty( $data['price']['id'] ) ) {
			$this->add_portal_service_request_price_id_candidates( $data['price']['id'], $price_ids );
		}

		// Stripe API 2025-03-31+ ("Basil") moved invoice/subscription line item pricing under
		// pricing.price_details.price (a plain string) instead of the legacy price.id object.
		if ( ! empty( $data['pricing']['price_details']['price'] ) ) {
			$this->add_portal_service_request_price_id_candidates( $data['pricing']['price_details']['price'], $price_ids );
		}

		foreach ( $data as $value ) {
			if ( is_array( $value ) ) {
				$this->collect_portal_service_request_price_ids_from_data( $value, $price_ids );
			}
		}
	}

	/**
	 * Resolves the subscription ID a Stripe invoice belongs to, across API versions: Basil
	 * (2025-03-31+) nests it under parent.subscription_details.subscription; older invoices carry
	 * a direct "subscription" field (sometimes expanded to an object).
	 */
	private function get_invoice_subscription_id_from_raw_data( $invoice_raw ) {
		if ( ! is_array( $invoice_raw ) ) {
			return '';
		}
		if ( ! empty( $invoice_raw['parent']['subscription_details']['subscription'] ) ) {
			return sanitize_text_field( (string) $invoice_raw['parent']['subscription_details']['subscription'] );
		}
		if ( ! empty( $invoice_raw['subscription'] ) ) {
			$sub = $invoice_raw['subscription'];
			return sanitize_text_field( (string) ( is_array( $sub ) ? ( $sub['id'] ?? '' ) : $sub ) );
		}
		return '';
	}

	/**
	 * Keeps invoice-sourced service requests honest against Stripe: if the subscription an
	 * invoice belongs to has since been canceled, the request's workflow status is moved to
	 * "Cancelled" so staff stop seeing follow-up actions for a subscription that no longer exists —
	 * matching what the Stripe dashboard itself shows for that subscription. Also re-resolves the
	 * service name for auto-generated rows now that Basil-era price IDs are recognized (see
	 * collect_portal_service_request_price_ids_from_data): older invoices synced before that fix
	 * fell back to Stripe's frozen, sometimes stale, invoice line-item description text.
	 */
	/**
	 * Determines whether the charge behind this service request has been refunded, by reusing
	 * AJCore_REST_API::attach_payment_display_fields() — the exact same matcher the Payments screen
	 * uses to show "Refunded" correctly. That method's own docblock explains why: on current Stripe
	 * API versions, charge objects no longer expose `invoice`/`payment_intent` cross-link fields, so
	 * a ledger row can't be reliably joined to its charge by ID alone — it falls back to matching by
	 * (customer, amount, nearest date within 48h). Re-deriving that matching here via ID lookups
	 * (an earlier version of this method did) silently found nothing, because those ID columns are
	 * often empty for exactly the reason above. Returns '' when no refund is detected.
	 */
	private function get_service_request_refund_status( $row ) {
		if ( ! class_exists( 'AJCore_REST_API' ) ) {
			return '';
		}
		$pdb      = $this->get_pdb();
		$t_ledger = $this->get_portal_ledger_table();

		$own_ledger = null;
		if ( ! empty( $row->ledger_id ) ) {
			$own_ledger = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$t_ledger} WHERE id = %d", (int) $row->ledger_id ) );
		}
		if ( ! $own_ledger ) {
			$own_ledger = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$t_ledger} WHERE source_object_id = %s LIMIT 1", (string) $row->source_object_id ) );
		}
		if ( ! $own_ledger || empty( $own_ledger->stripe_customer_id ) ) {
			return '';
		}

		$synthetic_tx = array(
			array(
				'object_type'        => sanitize_key( (string) $own_ledger->source_type ),
				'stripe_object_id'   => (string) $own_ledger->source_object_id,
				'stripe_customer_id' => (string) $own_ledger->stripe_customer_id,
				'currency'           => (string) $own_ledger->currency,
				'amount'             => (float) $own_ledger->amount,
				'transaction_date'   => (string) $own_ledger->ledger_date,
				'charge_id'          => (string) $own_ledger->charge_id,
				'payment_intent_id'  => (string) $own_ledger->payment_intent_id,
			),
		);

		$rest_api      = new AJCore_REST_API();
		$result        = $rest_api->attach_payment_display_fields( $synthetic_tx );
		$refund_status = ! empty( $result[0]['refund_status'] ) ? sanitize_key( (string) $result[0]['refund_status'] ) : '';

		return in_array( $refund_status, array( 'refunded', 'partially_refunded' ), true ) ? $refund_status : '';
	}

	private function reconcile_invoice_sourced_service_requests() {
		$pdb   = $this->get_pdb();
		$table = $this->get_portal_service_requests_table();

		// A row already marked refunded/partially_refunded must still be revisited until its
		// service_status has caught up to 'cancelled' (or 'completed') — otherwise a row whose pay
		// status was flagged refunded before service_status auto-cancellation existed (or before a
		// staff member got to it) would be excluded here forever and never picked up retroactively.
		$rows = $pdb->get_results(
			"SELECT * FROM {$table}
			WHERE source_type IN ('invoice','checkout_session')
			AND status NOT IN ('cancelled','failed','draft')
			AND NOT ( status IN ('refunded','partially_refunded') AND service_status IN ('cancelled','completed') )
			ORDER BY id ASC LIMIT 500"
		);

		foreach ( (array) $rows as $row ) {
			$update      = array();
			$formats     = array();
			$old_service_status = isset( $row->service_status ) && '' !== $row->service_status ? sanitize_key( (string) $row->service_status ) : 'new';

			// Refund detection applies to any source type. A refund means the service is being
			// discontinued, so the fulfillment pipeline is auto-cancelled here too (per explicit
			// user decision) — which piggybacks on the existing status-change notification email
			// below, same as the manual "Cancel Request" button already does. Checked independently
			// of whether $row->status already says 'refunded', so a row that got flagged refunded
			// before service_status caught up still gets the auto-cancel + email applied.
			$refund_status       = $this->get_service_request_refund_status( $row );
			$auto_cancel_refund  = false;
			if ( '' !== $refund_status ) {
				if ( $refund_status !== sanitize_key( (string) $row->status ) ) {
					$update['status'] = $refund_status;
					$formats[]        = '%s';
				}
				if ( ! in_array( $old_service_status, array( 'cancelled', 'completed' ), true ) ) {
					$update['service_status'] = 'cancelled';
					$formats[]                = '%s';
					$auto_cancel_refund       = true;
				}
			}

			$invoice_id = sanitize_text_field( (string) $row->source_object_id );
			if ( '' === $invoice_id || 'invoice' !== sanitize_key( (string) $row->source_type ) ) {
				if ( ! empty( $update ) ) {
					$update['updated_at'] = current_time( 'mysql' );
					$formats[]            = '%s';
					$pdb->update( $table, $update, array( 'id' => (int) $row->id ), $formats, array( '%d' ) );
					if ( isset( $update['status'] ) || $auto_cancel_refund ) {
						$this->add_portal_service_request_history(
							(int) $row->id,
							'status_changed',
							array(
								'status_before'         => sanitize_key( (string) $row->status ),
								'status_after'          => isset( $update['status'] ) ? $update['status'] : sanitize_key( (string) $row->status ),
								'service_status_before' => $old_service_status,
								'service_status_after'  => isset( $update['service_status'] ) ? $update['service_status'] : $old_service_status,
								'note'                  => $auto_cancel_refund
									? __( 'Reconciled automatically: the linked Stripe charge was refunded — service cancelled and customer notified.', 'ajforms' )
									: __( 'Reconciled automatically: the linked Stripe charge was refunded.', 'ajforms' ),
								'details'               => array( 'source' => 'refund_reconcile' ),
							)
						);
						if ( $auto_cancel_refund ) {
							$this->send_service_request_status_email( $row, $old_service_status, $update['service_status'] );
						}
					}
				}
				continue;
			}
			$invoice_raw_json = $pdb->get_var(
				$pdb->prepare(
					"SELECT raw_data FROM {$this->get_portal_stripe_transactions_table()} WHERE stripe_object_id = %s LIMIT 1",
					$invoice_id
				)
			);
			$invoice_raw = $invoice_raw_json ? json_decode( (string) $invoice_raw_json, true ) : null;
			if ( ! is_array( $invoice_raw ) ) {
				if ( ! empty( $update ) ) {
					$update['updated_at'] = current_time( 'mysql' );
					$formats[]            = '%s';
					$pdb->update( $table, $update, array( 'id' => (int) $row->id ), $formats, array( '%d' ) );
					if ( isset( $update['status'] ) || $auto_cancel_refund ) {
						$this->add_portal_service_request_history(
							(int) $row->id,
							'status_changed',
							array(
								'status_before'         => sanitize_key( (string) $row->status ),
								'status_after'          => isset( $update['status'] ) ? $update['status'] : sanitize_key( (string) $row->status ),
								'service_status_before' => $old_service_status,
								'service_status_after'  => isset( $update['service_status'] ) ? $update['service_status'] : $old_service_status,
								'note'                  => $auto_cancel_refund
									? __( 'Reconciled automatically: the linked Stripe charge was refunded — service cancelled and customer notified.', 'ajforms' )
									: __( 'Reconciled automatically: the linked Stripe charge was refunded.', 'ajforms' ),
								'details'               => array( 'source' => 'refund_reconcile' ),
							)
						);
						if ( $auto_cancel_refund ) {
							$this->send_service_request_status_email( $row, $old_service_status, $update['service_status'] );
						}
					}
				}
				continue;
			}

			$subscription_id = $this->get_invoice_subscription_id_from_raw_data( $invoice_raw );
			if ( '' !== $subscription_id ) {
				$sub_status = $this->get_synced_portal_subscription_status( $subscription_id );
				// Skip if the refund check above already queued the same field — service_status can
				// only be set once per $update, or the extra %s format spec would misalign wpdb->update().
				if ( in_array( $sub_status, array( 'canceled', 'incomplete_expired' ), true ) && 'cancelled' !== $old_service_status && ! isset( $update['service_status'] ) ) {
					$update['service_status'] = 'cancelled';
					$formats[]                = '%s';
				}
			}

			// Only auto-generated, never-manually-edited rows get their name re-resolved.
			if ( 'ledger_backfill' === sanitize_key( (string) $row->source ) ) {
				$price_ids = array();
				$this->collect_portal_service_request_price_ids_from_data( $invoice_raw, $price_ids );
				$names = array();
				foreach ( $price_ids as $pid ) {
					$product = $this->get_portal_product_by_price_id( $pid );
					if ( $product ) {
						$label = ! empty( $product->custom_label ) ? $product->custom_label : ( ! empty( $product->name ) ? $product->name : '' );
						if ( '' !== $label && ! in_array( $label, $names, true ) ) {
							$names[] = sanitize_text_field( (string) $label );
						}
					}
				}
				$resolved_name = ! empty( $names ) ? implode( ', ', $names ) : '';
				if ( '' !== $resolved_name && $resolved_name !== $row->service_name ) {
					$update['service_name'] = $resolved_name;
					$formats[]              = '%s';
					if ( empty( $row->stripe_price_id ) && ! empty( $price_ids ) ) {
						$update['stripe_price_id'] = sanitize_text_field( (string) reset( $price_ids ) );
						$formats[]                 = '%s';
					}
				}
			}

			if ( empty( $update ) ) {
				continue;
			}

			$update['updated_at'] = current_time( 'mysql' );
			$formats[]            = '%s';
			$pdb->update( $table, $update, array( 'id' => (int) $row->id ), $formats, array( '%d' ) );

			// $auto_cancel_refund (not just isset($update['status'])) identifies a refund-driven
			// update, because a row that was already flagged 'refunded' in an earlier pass — before
			// service_status caught up — only has 'service_status' queued here, with 'status'
			// left unset since it already matches. The subscription-cancel branch below only ever
			// sets 'service_status' with $auto_cancel_refund staying false, so it's still the only
			// other way to reach the elseif.
			if ( isset( $update['status'] ) || $auto_cancel_refund ) {
				$this->add_portal_service_request_history(
					(int) $row->id,
					'status_changed',
					array(
						'status_before'         => sanitize_key( (string) $row->status ),
						'status_after'          => isset( $update['status'] ) ? $update['status'] : sanitize_key( (string) $row->status ),
						'service_status_before' => $old_service_status,
						'service_status_after'  => isset( $update['service_status'] ) ? $update['service_status'] : $old_service_status,
						'note'                  => $auto_cancel_refund
							? __( 'Reconciled automatically: the linked Stripe charge was refunded — service cancelled and customer notified.', 'ajforms' )
							: __( 'Reconciled automatically: the linked Stripe charge was refunded.', 'ajforms' ),
						'details'               => array( 'source' => 'refund_reconcile' ),
					)
				);
				if ( $auto_cancel_refund ) {
					$this->send_service_request_status_email( $row, $old_service_status, $update['service_status'] );
				}
			} elseif ( isset( $update['service_status'] ) ) {
				$this->add_portal_service_request_history(
					(int) $row->id,
					'status_changed',
					array(
						'status_before'         => sanitize_key( (string) $row->status ),
						'status_after'          => sanitize_key( (string) $row->status ),
						'service_status_before' => $old_service_status,
						'service_status_after'  => 'cancelled',
						'note'                  => __( 'Reconciled automatically: the linked Stripe subscription is canceled.', 'ajforms' ),
						'details'               => array( 'source' => 'subscription_reconcile', 'subscription_id' => $subscription_id ),
					)
				);
			}
		}
	}

	private function get_portal_service_request_display_name( $request, $raw_data = array() ) {
		$candidates = array();
		$price_ids  = array();

		if ( ! empty( $request->stripe_price_id ) ) {
			$this->add_portal_service_request_price_id_candidates( $request->stripe_price_id, $price_ids );
		}

		$raw_data = is_array( $raw_data ) ? $raw_data : array();
		$this->collect_portal_service_label_candidates_from_data( $raw_data, $candidates );
		$this->collect_portal_service_request_price_ids_from_data( $raw_data, $price_ids );

		foreach ( array( 'ledger_metadata', 'transaction_raw_data' ) as $field ) {
			if ( ! empty( $request->$field ) ) {
				$decoded = $this->decode_portal_json( $request->$field );
				$this->collect_portal_service_label_candidates_from_data( $decoded, $candidates );
				$this->collect_portal_service_request_price_ids_from_data( $decoded, $price_ids );
			}
		}

		foreach ( $price_ids as $price_id ) {
			$product = $this->get_portal_product_by_price_id( $price_id );
			if ( $product ) {
				$label = ! empty( $product->custom_label ) ? $product->custom_label : ( ! empty( $product->name ) ? $product->name : '' );
				$this->add_portal_service_label_candidate( $candidates, $label, 8 );
			}
		}

		if ( ! empty( $request->service_name ) ) {
			$this->add_portal_service_label_candidate( $candidates, $request->service_name, 15 );
		}

		usort(
			$candidates,
			function ( $a, $b ) {
				return (int) $a['priority'] <=> (int) $b['priority'];
			}
		);

		$labels = array();
		foreach ( $candidates as $candidate ) {
			$label = sanitize_text_field( (string) $candidate['label'] );
			$key   = strtolower( $label );
			if ( '' !== $label && ! isset( $labels[ $key ] ) ) {
				$labels[ $key ] = $label;
			}
		}

		if ( ! empty( $labels ) ) {
			return reset( $labels );
		}

		return __( 'Service Request', 'ajforms' );
	}

	private function sync_portal_service_request_to_ledger( $request, $data = array() ) {
		global $wpdb;

		if ( ! $request ) {
			return false;
		}

		$ledger_update = array();
		$ledger_formats = array();

		if ( array_key_exists( 'amount', $data ) ) {
			$ledger_update['amount'] = (float) $data['amount'];
			$ledger_formats[] = '%f';
		}
		if ( array_key_exists( 'currency', $data ) ) {
			$ledger_update['currency'] = sanitize_key( (string) $data['currency'] );
			$ledger_formats[] = '%s';
		}
		if ( array_key_exists( 'status', $data ) ) {
			$ledger_update['status'] = sanitize_key( (string) $data['status'] );
			$ledger_formats[] = '%s';
		}

		$ledger = null;
		if ( ! empty( $request->ledger_id ) ) {
			$ledger = $wpdb->get_row(
				$wpdb->prepare(
					"SELECT * FROM {$this->get_portal_ledger_table()} WHERE id = %d LIMIT 1",
					(int) $request->ledger_id
				)
			);
		}

		if ( ! $ledger && ! empty( $request->source_object_id ) ) {
			$ledger = $wpdb->get_row(
				$wpdb->prepare(
					"SELECT * FROM {$this->get_portal_ledger_table()} WHERE stripe_customer_id = %s AND source_object_id = %s LIMIT 1",
					sanitize_text_field( (string) $request->stripe_customer_id ),
					sanitize_text_field( (string) $request->source_object_id )
				)
			);
		}

		if ( ! $ledger ) {
			return false;
		}

		$metadata = ! empty( $ledger->metadata ) ? json_decode( (string) $ledger->metadata, true ) : array();
		$metadata = is_array( $metadata ) ? $metadata : array();

		foreach ( array( 'payment_url', 'payment_reference', 'client_notes', 'request_id' ) as $meta_key ) {
			if ( array_key_exists( $meta_key, $data ) ) {
				$metadata[ $meta_key ] = is_scalar( $data[ $meta_key ] ) ? (string) $data[ $meta_key ] : '';
			}
		}
		$metadata['request_status_updated_at'] = current_time( 'mysql' );

		$ledger_update['metadata'] = wp_json_encode( $metadata );
		$ledger_formats[] = '%s';

		if ( empty( $ledger_update ) ) {
			return true;
		}

		$updated = $wpdb->update(
			$this->get_portal_ledger_table(),
			$ledger_update,
			array( 'id' => (int) $ledger->id ),
			$ledger_formats,
			array( '%d' )
		);

		return false !== $updated;
	}

	private function handle_portal_service_request_details_save() {
		if ( ! current_user_can( 'manage_options' ) ) {
			return;
		}

		if ( ! isset( $_POST['service_request_action'] ) || 'save_details' !== sanitize_key( wp_unslash( $_POST['service_request_action'] ) ) ) {
			return;
		}

		$request_id = isset( $_POST['request_id'] ) ? absint( wp_unslash( $_POST['request_id'] ) ) : 0;
		if ( ! $request_id ) {
			return;
		}

		check_admin_referer( 'ajcore_service_request_details_' . $request_id );

		$pdb     = $this->get_pdb();
		$request = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d", $request_id ) );
		if ( ! $request ) {
			return;
		}

		$amount = (float) $request->amount;
		if ( isset( $_POST['request_amount'] ) ) {
			$raw_amount = wp_unslash( $_POST['request_amount'] );
			if ( function_exists( 'wc_format_decimal' ) ) {
				$amount = (float) wc_format_decimal( $raw_amount );
			} else {
				$amount = (float) preg_replace( '/[^0-9.\-]/', '', (string) $raw_amount );
			}
		}
		$currency = isset( $_POST['request_currency'] ) ? sanitize_key( wp_unslash( $_POST['request_currency'] ) ) : sanitize_key( (string) $request->currency );
		if ( '' === $currency ) {
			$currency = 'usd';
		}

		$client_notes       = isset( $_POST['client_notes'] ) ? sanitize_textarea_field( wp_unslash( $_POST['client_notes'] ) ) : (string) $request->client_notes;
		$admin_notes        = isset( $_POST['admin_notes'] ) ? sanitize_textarea_field( wp_unslash( $_POST['admin_notes'] ) ) : (string) $request->admin_notes;
		$new_history_note   = isset( $_POST['service_request_note'] ) ? sanitize_textarea_field( wp_unslash( $_POST['service_request_note'] ) ) : '';
		$payment_url        = isset( $_POST['payment_url'] ) ? esc_url_raw( wp_unslash( $_POST['payment_url'] ) ) : $this->get_portal_service_request_meta_value( $request, 'payment_url' );
		$payment_reference  = isset( $_POST['payment_reference'] ) ? sanitize_text_field( wp_unslash( $_POST['payment_reference'] ) ) : $this->get_portal_service_request_meta_value( $request, 'payment_reference' );
		$after_save_status  = isset( $_POST['after_save_status'] ) ? sanitize_key( wp_unslash( $_POST['after_save_status'] ) ) : '';
		$after_service_status = isset( $_POST['after_service_status'] ) ? sanitize_key( wp_unslash( $_POST['after_service_status'] ) ) : '';
		// SVC Status is mostly internal staff tracking — email only goes out when a form explicitly
		// opts in (see the "Cancel Request" form below, which always does; the stepper/edit-panel
		// forms default to silent).
		$notify_customer    = ! empty( $_POST['notify_customer'] );
		$selected_price_id  = isset( $_POST['request_stripe_price_id'] ) ? sanitize_text_field( wp_unslash( $_POST['request_stripe_price_id'] ) ) : '';
		$selected_product   = $this->get_portal_product_by_price_id( $selected_price_id );
		if ( '' !== $selected_price_id && ! $selected_product ) {
			wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'service-requests', 'service-request-error' => rawurlencode( __( 'Selected Stripe price was not found in the synced product cache.', 'ajforms' ) ) ), admin_url( 'admin.php' ) ) );
			exit;
		}

		$subscription_id = isset( $_POST['billing_subscription_id'] ) ? sanitize_text_field( wp_unslash( $_POST['billing_subscription_id'] ) ) : '';
		$subscription_item_id = isset( $_POST['billing_subscription_item_id'] ) ? sanitize_text_field( wp_unslash( $_POST['billing_subscription_item_id'] ) ) : '';
		$proration_behavior = isset( $_POST['billing_proration_behavior'] ) ? sanitize_key( wp_unslash( $_POST['billing_proration_behavior'] ) ) : 'create_prorations';
		if ( ! in_array( $proration_behavior, array( 'create_prorations', 'none', 'always_invoice' ), true ) ) {
			$proration_behavior = 'create_prorations';
		}

		$old_request_status   = sanitize_key( (string) $request->status );
		$old_service_status   = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		$old_assigned_user_id = isset( $request->assigned_user_id ) ? (int) $request->assigned_user_id : 0;
		$assigned_user_id     = isset( $_POST['assigned_user_id'] ) ? absint( wp_unslash( $_POST['assigned_user_id'] ) ) : $old_assigned_user_id;
		$status             = $old_request_status;
		$service_status     = $old_service_status;
		if ( '' !== $after_save_status && isset( $this->get_portal_service_request_status_labels()[ $after_save_status ] ) ) {
			$status = $after_save_status;
		}
		if ( '' !== $after_service_status && isset( $this->get_portal_sr_service_status_labels()[ $after_service_status ] ) ) {
			$service_status = $after_service_status;
		}

		$raw_data = $this->get_portal_service_request_raw_data( $request );
		$raw_data['payment_url'] = $payment_url;
		$raw_data['payment_reference'] = $payment_reference;
		$raw_data['details_updated_at'] = current_time( 'mysql' );
		$raw_data['details_updated_by'] = get_current_user_id();
		if ( $selected_product ) {
			$raw_data['selected_service_price'] = array(
				'stripe_price_id'   => sanitize_text_field( (string) $selected_product->stripe_price_id ),
				'stripe_product_id' => sanitize_text_field( (string) $selected_product->stripe_product_id ),
				'name'              => sanitize_text_field( (string) $selected_product->name ),
				'amount'            => (float) $selected_product->price_amount,
				'currency'          => sanitize_key( (string) $selected_product->currency ),
				'recurring_interval'=> sanitize_key( (string) $selected_product->recurring_interval ),
				'active'            => ! empty( $selected_product->active ) ? 1 : 0,
			);
			$raw_data['billing_preview'] = array(
				'subscription_id'      => $subscription_id,
				'subscription_item_id' => $subscription_item_id,
				'new_price_id'         => sanitize_text_field( (string) $selected_product->stripe_price_id ),
				'new_product_id'       => sanitize_text_field( (string) $selected_product->stripe_product_id ),
				'new_price_label'      => $this->get_portal_product_admin_label( $selected_product ),
				'proration_behavior'   => $proration_behavior,
				'preview_saved_at'     => current_time( 'mysql' ),
				'preview_saved_by'     => get_current_user_id(),
			);
		}

		$update_data = array(
			'amount'           => $amount,
			'currency'         => $currency,
			'status'           => $status,
			'service_status'   => $service_status,
			'admin_notes'      => $admin_notes,
			'client_notes'     => $client_notes,
			'assigned_user_id' => $assigned_user_id,
			'raw_data'         => wp_json_encode( $raw_data ),
			'updated_at'       => current_time( 'mysql' ),
		);
		$update_formats = array( '%f', '%s', '%s', '%s', '%s', '%s', '%d', '%s', '%s' );

		if ( $selected_product ) {
			$update_data['stripe_price_id']   = sanitize_text_field( (string) $selected_product->stripe_price_id );
			$update_data['stripe_product_id'] = sanitize_text_field( (string) $selected_product->stripe_product_id );
			$update_data['service_name']      = sanitize_text_field( (string) $selected_product->name );
			$update_formats[] = '%s';
			$update_formats[] = '%s';
			$update_formats[] = '%s';
		}

		$pdb->update(
			$this->get_portal_service_requests_table(),
			$update_data,
			array( 'id' => $request_id ),
			$update_formats,
			array( '%d' )
		);

		$request->amount = $amount;
		$request->currency = $currency;
		$request->status = $status;
		$request->service_status = $service_status;
		$request->client_notes = $client_notes;
		$request->admin_notes = $admin_notes;
		$request->assigned_user_id = $assigned_user_id;
		$request->raw_data = wp_json_encode( $raw_data );
		if ( $selected_product ) {
			$request->stripe_price_id = sanitize_text_field( (string) $selected_product->stripe_price_id );
			$request->stripe_product_id = sanitize_text_field( (string) $selected_product->stripe_product_id );
			$request->service_name = sanitize_text_field( (string) $selected_product->name );
		}

		$this->sync_portal_service_request_to_ledger(
			$request,
			array(
				'amount'            => $amount,
				'currency'          => $currency,
				'status'            => $status,
				'payment_url'       => $payment_url,
				'payment_reference' => $payment_reference,
				'client_notes'      => $client_notes,
				'request_id'        => $request_id,
			)
		);

		if ( $old_request_status !== $status || $old_service_status !== $service_status ) {
			$this->add_portal_service_request_history(
				$request_id,
				'status_changed',
				array(
					'status_before'         => $old_request_status,
					'status_after'          => $status,
					'service_status_before' => $old_service_status,
					'service_status_after'  => $service_status,
					'note'                  => $notify_customer
						? __( 'Status updated from the edit panel. Customer notified.', 'ajforms' )
						: __( 'Status updated from the edit panel.', 'ajforms' ),
					'details'               => array( 'source' => 'details_save' ),
				)
			);
			if ( $notify_customer ) {
				$this->send_service_request_status_email( $request, $old_service_status, $service_status );
			}
		}
		if ( '' !== $new_history_note ) {
			$this->add_portal_service_request_history(
				$request_id,
				'note',
				array(
					'note'                  => $new_history_note,
					'status_before'         => $old_request_status,
					'status_after'          => $status,
					'service_status_before' => $old_service_status,
					'service_status_after'  => $service_status,
				)
			);
		}
		if ( $old_assigned_user_id !== $assigned_user_id ) {
			$this->add_portal_service_request_history(
				$request_id,
				'assigned',
				array(
					'note'    => $this->describe_portal_service_request_assignment_change( $old_assigned_user_id, $assigned_user_id ),
					'details' => array( 'assigned_user_id_before' => $old_assigned_user_id, 'assigned_user_id_after' => $assigned_user_id ),
				)
			);
		}
		$this->add_portal_service_request_history(
			$request_id,
			'details_updated',
			array(
				'note'                  => __( 'Request details were saved.', 'ajforms' ),
				'status_before'         => $old_request_status,
				'status_after'          => $status,
				'service_status_before' => $old_service_status,
				'service_status_after'  => $service_status,
				'details'               => array( 'amount' => $amount, 'currency' => $currency, 'selected_price_id' => $selected_price_id ),
			)
		);

		if ( 'completed' === $status && 'completed' !== $old_request_status ) {
			$this->log_portal_event(
				'service_provisioned',
				array(
					'source'             => 'service_requests',
					'stripe_customer_id' => $request->stripe_customer_id,
					'wp_user_id_after'   => isset( $request->wp_user_id ) ? (int) $request->wp_user_id : 0,
					'portal_status_before'=> $old_request_status,
					'portal_status_after'=> 'active',
					'details'            => array(
						'request_id'        => (int) $request_id,
						'service_name'      => $request->service_name,
						'stripe_price_id'   => $request->stripe_price_id,
						'stripe_product_id' => $request->stripe_product_id,
					),
				)
			);
		}

		wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'service-requests', 'service-request-updated' => 1 ), admin_url( 'admin.php' ) ) );
		exit;
	}

	private function handle_service_requests_bulk_save() {
		if ( ! current_user_can( 'manage_options' ) ) {
			return;
		}

		if ( ! isset( $_POST['service_request_action'] ) || 'bulk_update' !== sanitize_key( wp_unslash( $_POST['service_request_action'] ) ) ) {
			return;
		}

		check_admin_referer( 'ajcore_service_request_bulk' );

		$ids = isset( $_POST['request_ids'] ) ? array_map( 'absint', (array) wp_unslash( $_POST['request_ids'] ) ) : array();
		$ids = array_values( array_filter( $ids ) );

		$fields = array();
		if ( ! empty( $_POST['bulk_service_status'] ) ) {
			$fields['service_status'] = sanitize_key( wp_unslash( $_POST['bulk_service_status'] ) );
		}
		if ( isset( $_POST['bulk_assigned_user_id'] ) && '' !== $_POST['bulk_assigned_user_id'] ) {
			$fields['assigned_user_id'] = absint( wp_unslash( $_POST['bulk_assigned_user_id'] ) );
		}

		if ( ! empty( $ids ) && ! empty( $fields ) ) {
			$this->bulk_update_service_requests_for_ops( $ids, $fields );
		}

		wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'service-requests', 'service-request-updated' => 1 ), admin_url( 'admin.php' ) ) );
		exit;
	}


	private function cleanup_stale_pending_checkout_service_requests() {
		$pdb = $this->get_pdb();

		$this->ensure_portal_schema();

		$stale_requests = $pdb->get_results(
			"SELECT r.*, l.source_type AS ledger_source_type, l.status AS ledger_status, l.invoice_id, l.payment_intent_id, l.charge_id
			FROM {$this->get_portal_service_requests_table()} r
			LEFT JOIN {$this->get_portal_ledger_table()} l ON l.id = r.ledger_id
			WHERE r.request_type = 'add_service'
			AND r.source = 'ledger_backfill'
			AND r.status IN ('draft','pending_payment')
			AND (r.source_type = 'checkout_session' OR l.source_type = 'checkout_session')"
		);

		foreach ( $stale_requests as $request ) {
			if ( ! empty( $request->ledger_id ) && $this->is_portal_service_request_ledger_safe_to_delete( $request ) ) {
				$pdb->delete( $this->get_portal_ledger_table(), array( 'id' => (int) $request->ledger_id ), array( '%d' ) );
			}

			$pdb->delete( $this->get_portal_service_requests_table(), array( 'id' => (int) $request->id ), array( '%d' ) );
		}
	}

	private function is_portal_service_request_ledger_safe_to_delete( $request ) {
		if ( empty( $request->ledger_id ) ) {
			return false;
		}

		$pdb    = $this->get_pdb();
		$ledger = $pdb->get_row(
			$pdb->prepare(
				"SELECT * FROM {$this->get_portal_ledger_table()} WHERE id = %d LIMIT 1",
				(int) $request->ledger_id
			)
		);

		if ( ! $ledger ) {
			return false;
		}

		if ( ! empty( $ledger->invoice_id ) || ! empty( $ledger->payment_intent_id ) || ! empty( $ledger->charge_id ) ) {
			return false;
		}

		$source_type = sanitize_key( (string) $ledger->source_type );
		$status      = sanitize_key( (string) $ledger->status );

		if ( in_array( $source_type, array( 'invoice', 'charge' ), true ) ) {
			return false;
		}

		if ( 'checkout_session' === $source_type && in_array( $status, array( 'paid', 'succeeded', 'completed' ), true ) ) {
			return false;
		}

		return in_array( $source_type, array( 'checkout_session', 'custom_service_request', 'service_quote_request', 'custom_request', 'service_request', 'portal_custom_request', 'portal_additional_entity_pricing' ), true );
	}

	private function handle_portal_service_request_delete( $request_id ) {
		$pdb = $this->get_pdb();

		$request = $pdb->get_row(
			$pdb->prepare(
				"SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d LIMIT 1",
				(int) $request_id
			)
		);

		if ( ! $request ) {
			return false;
		}

		if ( $this->is_portal_service_request_ledger_safe_to_delete( $request ) ) {
			$pdb->delete( $this->get_portal_ledger_table(), array( 'id' => (int) $request->ledger_id ), array( '%d' ) );
		}

		return false !== $pdb->delete( $this->get_portal_service_requests_table(), array( 'id' => (int) $request_id ), array( '%d' ) );
	}

	private function apply_portal_billing_change_request( $request_id ) {
		$pdb = $this->get_pdb();

		$request = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d LIMIT 1", absint( $request_id ) ) );
		if ( ! $request ) {
			return new WP_Error( 'request_not_found', __( 'Service request was not found.', 'ajforms' ) );
		}

		$raw = $this->get_portal_service_request_raw_data( $request );
		$preview = ! empty( $raw['billing_preview'] ) && is_array( $raw['billing_preview'] ) ? $raw['billing_preview'] : $raw;
		$subscription_id = ! empty( $preview['subscription_id'] ) ? sanitize_text_field( (string) $preview['subscription_id'] ) : '';
		$subscription_item_id = ! empty( $preview['subscription_item_id'] ) ? sanitize_text_field( (string) $preview['subscription_item_id'] ) : '';
		$new_price_id = ! empty( $preview['new_price_id'] ) ? sanitize_text_field( (string) $preview['new_price_id'] ) : ( ! empty( $request->stripe_price_id ) ? sanitize_text_field( (string) $request->stripe_price_id ) : '' );
		$proration_behavior = ! empty( $preview['proration_behavior'] ) ? sanitize_key( (string) $preview['proration_behavior'] ) : 'create_prorations';
		$allowed_proration = array( 'create_prorations', 'none', 'always_invoice' );
		if ( ! in_array( $proration_behavior, $allowed_proration, true ) ) {
			$proration_behavior = 'create_prorations';
		}

		if ( '' === $subscription_id || '' === $new_price_id ) {
			return new WP_Error( 'missing_billing_preview', __( 'This request does not have enough saved billing preview data to apply to Stripe.', 'ajforms' ) );
		}

		$secret_key = $this->get_stripe_secret_key_for_portal();
		if ( '' === $secret_key ) {
			return new WP_Error( 'missing_stripe_key', __( 'Stripe secret key is required.', 'ajforms' ) );
		}

		if ( '' === $subscription_item_id ) {
			$subscription = $this->stripe_api_get( 'subscriptions/' . rawurlencode( $subscription_id ), $secret_key );
			if ( is_wp_error( $subscription ) ) {
				return $subscription;
			}
			if ( ! empty( $subscription['items']['data'][0]['id'] ) ) {
				$subscription_item_id = sanitize_text_field( (string) $subscription['items']['data'][0]['id'] );
			}
		}

		if ( '' === $subscription_item_id ) {
			return new WP_Error( 'missing_subscription_item', __( 'Unable to determine the Stripe subscription item to update.', 'ajforms' ) );
		}

		$response = $this->stripe_api_request(
			'subscription_items/' . rawurlencode( $subscription_item_id ),
			$secret_key,
			array(
				'price'              => $new_price_id,
				'proration_behavior' => $proration_behavior,
			),
			'POST'
		);

		if ( is_wp_error( $response ) ) {
			return $response;
		}

		$raw['billing_apply'] = array(
			'applied_at'            => current_time( 'mysql' ),
			'applied_by'            => get_current_user_id(),
			'subscription_id'       => $subscription_id,
			'subscription_item_id'  => $subscription_item_id,
			'new_price_id'          => $new_price_id,
			'proration_behavior'    => $proration_behavior,
			'stripe_response_id'    => ! empty( $response['id'] ) ? sanitize_text_field( (string) $response['id'] ) : '',
		);

		$wpdb->update(
			$this->get_portal_service_requests_table(),
			array(
				'status'          => 'admin_review_required',
				'stripe_price_id' => $new_price_id,
				'raw_data'        => wp_json_encode( $raw ),
				'updated_at'      => current_time( 'mysql' ),
			),
			array( 'id' => (int) $request->id ),
			array( '%s', '%s', '%s', '%s' ),
			array( '%d' )
		);

		$this->sync_single_portal_stripe_customer( $secret_key, sanitize_text_field( (string) $request->stripe_customer_id ) );
		$this->sync_portal_service_request_to_ledger(
			$request,
			array(
				'status'            => 'admin_review_required',
				'payment_reference' => ! empty( $raw['billing_apply']['stripe_response_id'] ) ? $raw['billing_apply']['stripe_response_id'] : '',
				'request_id'        => (int) $request->id,
			)
		);

		return true;
	}

	private function backfill_portal_service_requests_from_ledger() {
		global $wpdb;
		$pdb = $this->get_pdb();

		$this->ensure_portal_schema();
		$actionable_source_types = array( 'custom_service_request', 'service_quote_request', 'custom_request', 'service_request', 'checkout_session' );
		$source_placeholders = implode( ',', array_fill( 0, count( $actionable_source_types ), '%s' ) );
		$ledger_rows = $pdb->get_results(
			$pdb->prepare(
				"SELECT l.*, c.email AS customer_email, c.name AS customer_name
				FROM {$this->get_portal_ledger_table()} l
				LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = l.stripe_customer_id
				WHERE l.source_type IN ({$source_placeholders})
				ORDER BY l.id ASC",
				$actionable_source_types
			)
		);

		foreach ( $ledger_rows as $entry ) {
			if ( empty( $entry->source_object_id ) ) {
				continue;
			}

			$existing = $pdb->get_row(
				$pdb->prepare(
					"SELECT * FROM {$this->get_portal_service_requests_table()} WHERE source_object_id = %s LIMIT 1",
					$entry->source_object_id
				)
			);

			$metadata = ! empty( $entry->metadata ) ? json_decode( (string) $entry->metadata, true ) : array();
			$metadata = is_array( $metadata ) ? $metadata : array();
			$stripe_customer_id = sanitize_text_field( (string) $entry->stripe_customer_id );
			$wp_user_id = (int) $wpdb->get_var(
				$wpdb->prepare(
					"SELECT user_id FROM {$this->get_portal_user_mappings_table()} WHERE stripe_customer_id = %s LIMIT 1",
					$stripe_customer_id
				)
			);
			$source_type = sanitize_key( (string) $entry->source_type );
			$is_checkout_request = 'checkout_session' === $source_type;
			if ( $is_checkout_request && ! in_array( sanitize_key( (string) $entry->status ), array( 'paid', 'succeeded', 'completed', 'failed' ), true ) ) {
				continue;
			}
			$request_type = $is_checkout_request ? 'add_service' : 'custom_request';
			$status = 'admin_review_required';
			if ( $is_checkout_request ) {
				$status = 'paid' === $entry->status ? 'paid' : ( 'failed' === $entry->status ? 'failed' : 'pending_payment' );
			} elseif ( ! empty( $entry->status ) ) {
				$status = $this->normalize_portal_service_request_status( $entry->status );
			}

			// Resolve price IDs from metadata (handle both single price_id and multi-product price_ids array).
			$meta_price_id  = ! empty( $metadata['price_id'] ) ? sanitize_text_field( (string) $metadata['price_id'] ) : '';
			$meta_price_ids = ! empty( $metadata['price_ids'] ) && is_array( $metadata['price_ids'] )
				? array_values( array_filter( array_unique( array_map( 'sanitize_text_field', $metadata['price_ids'] ) ) ) )
				: array();
			if ( '' !== $meta_price_id && ! in_array( $meta_price_id, $meta_price_ids, true ) ) {
				array_unshift( $meta_price_ids, $meta_price_id );
			}

			// Resolve service name: prefer stored product_name, then look up the product catalog by price IDs.
			$resolved_service_name = ! empty( $metadata['product_name'] ) ? sanitize_text_field( (string) $metadata['product_name'] ) : '';
			if ( '' === $resolved_service_name || $this->is_generic_portal_service_label( $resolved_service_name ) ) {
				$resolved_names = array();
				foreach ( $meta_price_ids as $pid ) {
					$pid_product = $this->get_portal_product_by_price_id( $pid );
					if ( $pid_product ) {
						$pid_label = ! empty( $pid_product->custom_label ) ? $pid_product->custom_label : ( ! empty( $pid_product->name ) ? $pid_product->name : '' );
						if ( '' !== $pid_label ) {
							$resolved_names[] = sanitize_text_field( (string) $pid_label );
						}
					}
				}
				if ( ! empty( $resolved_names ) ) {
					$resolved_service_name = implode( ', ', array_unique( $resolved_names ) );
				}
			}
			if ( '' === $resolved_service_name || $this->is_generic_portal_service_label( $resolved_service_name ) ) {
				$desc = sanitize_text_field( (string) $entry->description );
				$resolved_service_name = $this->is_generic_portal_service_label( $desc ) ? '' : $desc;
			}

			// For single-product requests, use the explicit price_id; for multi-product, use the first resolved one.
			$resolved_price_id   = '' !== $meta_price_id ? $meta_price_id : ( ! empty( $meta_price_ids ) ? $meta_price_ids[0] : '' );
			$resolved_product_id = ! empty( $metadata['product_id'] ) ? sanitize_text_field( (string) $metadata['product_id'] ) : '';

			// Last resort: look up the checkout session in stripe_transactions (populated by Stripe sync) to
			// find price IDs and product names from the raw session data and expanded line items.
			if ( $is_checkout_request && ( '' === $resolved_service_name || $this->is_generic_portal_service_label( $resolved_service_name ) ) ) {
				$tx_raw_json = $pdb->get_var(
					$pdb->prepare(
						"SELECT raw_data FROM {$this->get_portal_stripe_transactions_table()} WHERE stripe_object_id = %s LIMIT 1",
						sanitize_text_field( (string) $entry->source_object_id )
					)
				);
				if ( $tx_raw_json ) {
					$tx_data = json_decode( (string) $tx_raw_json, true );
					if ( is_array( $tx_data ) ) {
						// Collect price IDs from the full session object (including session.metadata.price_id).
						$tx_price_ids = array();
						$this->collect_portal_service_request_price_ids_from_data( $tx_data, $tx_price_ids );
						foreach ( $tx_price_ids as $tx_pid ) {
							if ( '' === $resolved_price_id ) {
								$resolved_price_id = $tx_pid;
							}
							if ( ! in_array( $tx_pid, $meta_price_ids, true ) ) {
								$meta_price_ids[] = $tx_pid;
							}
						}
						// Try product catalog lookup with newly discovered price IDs.
						$tx_resolved_names = array();
						foreach ( $meta_price_ids as $tx_pid ) {
							$tx_product = $this->get_portal_product_by_price_id( $tx_pid );
							if ( $tx_product ) {
								$tx_label = ! empty( $tx_product->custom_label ) ? $tx_product->custom_label : ( ! empty( $tx_product->name ) ? $tx_product->name : '' );
								if ( '' !== $tx_label ) {
									$tx_resolved_names[] = sanitize_text_field( (string) $tx_label );
								}
							}
						}
						if ( ! empty( $tx_resolved_names ) ) {
							$resolved_service_name = implode( ', ', array_unique( $tx_resolved_names ) );
						}
						// If still unresolved, extract names directly from line items in the session data.
						if ( '' === $resolved_service_name || $this->is_generic_portal_service_label( $resolved_service_name ) ) {
							$tx_candidates = array();
							$this->collect_portal_service_label_candidates_from_data( $tx_data, $tx_candidates );
							if ( ! empty( $tx_candidates ) ) {
								usort(
									$tx_candidates,
									function ( $a, $b ) {
										return (int) $a['priority'] <=> (int) $b['priority'];
									}
								);
								$tx_label = sanitize_text_field( (string) reset( $tx_candidates )['label'] );
								if ( '' !== $tx_label && ! $this->is_generic_portal_service_label( $tx_label ) ) {
									$resolved_service_name = $tx_label;
								}
							}
						}
					}
				}
			}

			// When updating an existing record, preserve values that were set at checkout creation time but
			// may have been lost because the Stripe sync overwrote the ledger entry metadata.
			if ( $existing ) {
				// Preserve service_name: if we resolved nothing useful, keep whatever good name is already stored.
				if ( '' === $resolved_service_name || $this->is_generic_portal_service_label( $resolved_service_name ) ) {
					$existing_name = sanitize_text_field( (string) $existing->service_name );
					if ( '' !== $existing_name && ! $this->is_generic_portal_service_label( $existing_name ) ) {
						$resolved_service_name = $existing_name;
					}
				}
				// Preserve stripe_price_id: don't overwrite a known price ID with empty.
				if ( '' === $resolved_price_id && ! empty( $existing->stripe_price_id ) ) {
					$resolved_price_id = sanitize_text_field( (string) $existing->stripe_price_id );
				}
				// Preserve stripe_product_id similarly.
				if ( '' === $resolved_product_id && ! empty( $existing->stripe_product_id ) ) {
					$resolved_product_id = sanitize_text_field( (string) $existing->stripe_product_id );
				}
				// Merge ledger_metadata into existing raw_data so we don't erase the original checkout session data.
				$existing_raw = ! empty( $existing->raw_data ) ? json_decode( (string) $existing->raw_data, true ) : array();
				$existing_raw = is_array( $existing_raw ) ? $existing_raw : array();
				$merged_raw   = array_merge( $existing_raw, array( 'ledger_metadata' => $metadata ) );
				$raw_data_value = wp_json_encode( $merged_raw );
			} else {
				$raw_data_value = wp_json_encode( array( 'ledger_metadata' => $metadata ) );
			}

			$request_data = array(
				'wp_user_id'          => $wp_user_id,
				'stripe_customer_id'  => $stripe_customer_id,
				'stripe_price_id'     => $resolved_price_id,
				'stripe_product_id'   => $resolved_product_id,
				'service_name'        => $resolved_service_name,
				'request_type'        => $request_type,
				'status'              => $status,
				'amount'              => (float) $entry->amount,
				'currency'            => sanitize_key( (string) $entry->currency ),
				'source_object_id'    => sanitize_text_field( (string) $entry->source_object_id ),
				'source_type'         => sanitize_key( (string) $entry->source_type ),
				'ledger_id'           => (int) $entry->id,
				'source'              => ! empty( $metadata['source'] ) ? sanitize_key( (string) $metadata['source'] ) : 'ledger_backfill',
				'created_by'          => 0,
				'raw_data'            => $raw_data_value,
				'updated_at'          => current_time( 'mysql' ),
			);

			$request_formats = array( '%d', '%s', '%s', '%s', '%s', '%s', '%s', '%f', '%s', '%s', '%s', '%d', '%s', '%d', '%s', '%s' );

			if ( $existing ) {
					$pdb->update(
					$this->get_portal_service_requests_table(),
					$request_data,
					array( 'id' => (int) $existing->id ),
					$request_formats,
					array( '%d' )
				);
					continue;
			}

			$request_data['created_at'] = ! empty( $entry->created_at ) ? $entry->created_at : current_time( 'mysql' );
			$request_formats[] = '%s';

			$pdb->insert(
				$this->get_portal_service_requests_table(),
				$request_data,
				$request_formats
			);
		}

		$this->backfill_portal_service_requests_from_first_invoices();

		// Repair orphaned service requests: records whose ledger_id points to a non-existent ledger entry.
		// This happens after a master reset — the ledger is wiped and re-synced with new IDs, but service
		// requests are intentionally kept. Their ledger_id values become stale (pointing to deleted rows).
		$orphaned = $pdb->get_results(
			"SELECT r.*
			FROM {$this->get_portal_service_requests_table()} r
			LEFT JOIN {$this->get_portal_ledger_table()} l ON l.id = r.ledger_id
			WHERE r.ledger_id > 0 AND l.id IS NULL
			LIMIT 200"
		);
		foreach ( (array) $orphaned as $orphan ) {
			$source_object_id = sanitize_text_field( (string) $orphan->source_object_id );
			if ( '' === $source_object_id ) {
				continue;
			}

			$repair_data   = array( 'updated_at' => current_time( 'mysql' ) );
			$repair_fmts   = array( '%s' );

			// Try to relink to a ledger entry that matches this checkout session ID.
			$new_ledger = $pdb->get_row(
				$pdb->prepare(
					"SELECT * FROM {$this->get_portal_ledger_table()} WHERE source_object_id = %s LIMIT 1",
					$source_object_id
				)
			);
			if ( $new_ledger ) {
				$repair_data['ledger_id'] = (int) $new_ledger->id;
				$repair_fmts[]            = '%d';
			}

			// If service_name is generic/empty, try to recover a product name from stripe_transactions.
			$existing_name = sanitize_text_field( (string) $orphan->service_name );
			if ( '' === $existing_name || $this->is_generic_portal_service_label( $existing_name ) ) {
				$tx_raw_json = $pdb->get_var(
					$pdb->prepare(
						"SELECT raw_data FROM {$this->get_portal_stripe_transactions_table()} WHERE stripe_object_id = %s LIMIT 1",
						$source_object_id
					)
				);
				if ( $tx_raw_json ) {
					$tx_data       = json_decode( (string) $tx_raw_json, true );
					$tx_price_ids  = array();
					$recovered_name = '';
					if ( is_array( $tx_data ) ) {
						$this->collect_portal_service_request_price_ids_from_data( $tx_data, $tx_price_ids );
						$tx_names = array();
						foreach ( $tx_price_ids as $tx_pid ) {
							$tx_product = $this->get_portal_product_by_price_id( $tx_pid );
							if ( $tx_product ) {
								$tx_label = ! empty( $tx_product->custom_label ) ? $tx_product->custom_label : ( ! empty( $tx_product->name ) ? $tx_product->name : '' );
								if ( '' !== $tx_label ) {
									$tx_names[] = sanitize_text_field( (string) $tx_label );
								}
							}
						}
						if ( ! empty( $tx_names ) ) {
							$recovered_name = implode( ', ', array_unique( $tx_names ) );
						}
						if ( '' === $recovered_name || $this->is_generic_portal_service_label( $recovered_name ) ) {
							$tx_candidates = array();
							$this->collect_portal_service_label_candidates_from_data( $tx_data, $tx_candidates );
							if ( ! empty( $tx_candidates ) ) {
								usort(
									$tx_candidates,
									function ( $a, $b ) {
										return (int) $a['priority'] <=> (int) $b['priority'];
									}
								);
								$c_label = sanitize_text_field( (string) reset( $tx_candidates )['label'] );
								if ( '' !== $c_label && ! $this->is_generic_portal_service_label( $c_label ) ) {
									$recovered_name = $c_label;
								}
							}
						}
						if ( '' !== $recovered_name ) {
							$repair_data['service_name'] = $recovered_name;
							$repair_fmts[]               = '%s';
							if ( '' === (string) $orphan->stripe_price_id && ! empty( $tx_price_ids ) ) {
								$repair_data['stripe_price_id'] = sanitize_text_field( (string) reset( $tx_price_ids ) );
								$repair_fmts[]                  = '%s';
							}
						}
					}
				}
			}

			if ( count( $repair_data ) > 1 ) {
				$pdb->update(
					$this->get_portal_service_requests_table(),
					$repair_data,
					array( 'id' => (int) $orphan->id ),
					$repair_fmts,
					array( '%d' )
				);
			}
		}

		$this->reconcile_invoice_sourced_service_requests();
	}

	/** Public entry point for the ops REST API — same reconciliation the WP admin page triggers. */
	public function reconcile_service_requests_for_ops() {
		$this->reconcile_invoice_sourced_service_requests();
	}

	/** Public entry point for the ops REST API — history timeline for the "View History" panel. */
	public function get_service_request_history_for_ops( $request_id, $limit = 40 ) {
		$rows = $this->get_portal_service_request_history( $request_id, $limit );
		$out  = array();
		foreach ( (array) $rows as $row ) {
			$out[] = array(
				'id'                    => (int) $row->id,
				'event_type'            => (string) $row->event_type,
				'title'                 => $this->get_portal_service_request_history_title( $row ),
				'status_before'         => (string) $row->status_before,
				'status_after'          => (string) $row->status_after,
				'service_status_before' => (string) $row->service_status_before,
				'service_status_after'  => (string) $row->service_status_after,
				'note'                  => (string) $row->note,
				'actor_email'           => (string) $row->actor_email,
				'created_at'            => (string) $row->created_at,
			);
		}
		return $out;
	}

	/**
	 * Some purchases never get a synced checkout session (Stripe attributes the session to a guest,
	 * or the session is missing entirely), so the session-based backfill above skips them. Create
	 * service requests for paid first-purchase invoices that no session or request covers yet.
	 */
	private function backfill_portal_service_requests_from_first_invoices() {
		global $wpdb;
		$pdb = $this->get_pdb();

		$invoice_rows = $pdb->get_results(
			"SELECT l.* FROM {$this->get_portal_ledger_table()} l
			WHERE l.source_type = 'invoice' AND l.status = 'paid' AND l.stripe_customer_id LIKE 'cus_%'
			ORDER BY l.id ASC"
		);

		foreach ( (array) $invoice_rows as $entry ) {
			$invoice_id = sanitize_text_field( (string) $entry->source_object_id );
			if ( '' === $invoice_id ) {
				continue;
			}

			$existing = $pdb->get_var(
				$pdb->prepare(
					"SELECT id FROM {$this->get_portal_service_requests_table()} WHERE source_object_id = %s LIMIT 1",
					$invoice_id
				)
			);
			if ( $existing ) {
				continue;
			}

			// Covered by a synced checkout session — its own SR is created from the session row.
			$session_covered = $pdb->get_var(
				$pdb->prepare(
					"SELECT id FROM {$this->get_portal_stripe_transactions_table()} WHERE object_type = 'checkout_session' AND invoice_id = %s LIMIT 1",
					$invoice_id
				)
			);
			if ( $session_covered ) {
				continue;
			}

			// Only first-purchase invoices — renewals and manual invoices are not new service requests.
			$invoice_raw_json = $pdb->get_var(
				$pdb->prepare(
					"SELECT raw_data FROM {$this->get_portal_stripe_transactions_table()} WHERE stripe_object_id = %s LIMIT 1",
					$invoice_id
				)
			);
			$invoice_raw = $invoice_raw_json ? json_decode( (string) $invoice_raw_json, true ) : null;
			if ( ! is_array( $invoice_raw ) ) {
				continue;
			}
			$billing_reason = isset( $invoice_raw['billing_reason'] ) ? sanitize_key( (string) $invoice_raw['billing_reason'] ) : '';
			if ( 'subscription_create' !== $billing_reason ) {
				continue;
			}

			$stripe_customer_id = sanitize_text_field( (string) $entry->stripe_customer_id );
			$wp_user_id         = (int) $wpdb->get_var(
				$wpdb->prepare(
					"SELECT user_id FROM {$this->get_portal_user_mappings_table()} WHERE stripe_customer_id = %s LIMIT 1",
					$stripe_customer_id
				)
			);

			// Resolve service name and price IDs from the invoice line items.
			$price_ids = array();
			$this->collect_portal_service_request_price_ids_from_data( $invoice_raw, $price_ids );
			$names = array();
			foreach ( $price_ids as $pid ) {
				$product = $this->get_portal_product_by_price_id( $pid );
				if ( $product ) {
					$label = ! empty( $product->custom_label ) ? $product->custom_label : ( ! empty( $product->name ) ? $product->name : '' );
					if ( '' !== $label ) {
						$names[] = sanitize_text_field( (string) $label );
					}
				}
			}
			$service_name = ! empty( $names ) ? implode( ', ', array_unique( $names ) ) : sanitize_text_field( (string) $entry->description );

			$pdb->insert(
				$this->get_portal_service_requests_table(),
				array(
					'wp_user_id'         => $wp_user_id,
					'stripe_customer_id' => $stripe_customer_id,
					'stripe_price_id'    => ! empty( $price_ids ) ? sanitize_text_field( (string) reset( $price_ids ) ) : '',
					'stripe_product_id'  => '',
					'service_name'       => $service_name,
					'request_type'       => 'add_service',
					'status'             => 'paid',
					'amount'             => (float) $entry->amount,
					'currency'           => sanitize_key( (string) $entry->currency ),
					'source_object_id'   => $invoice_id,
					'source_type'        => 'invoice',
					'ledger_id'          => (int) $entry->id,
					'source'             => 'ledger_backfill',
					'created_by'         => 0,
					'raw_data'           => wp_json_encode( array( 'billing_reason' => $billing_reason ) ),
					'updated_at'         => current_time( 'mysql' ),
					'created_at'         => ! empty( $entry->created_at ) ? $entry->created_at : current_time( 'mysql' ),
				),
				array( '%d', '%s', '%s', '%s', '%s', '%s', '%s', '%f', '%s', '%s', '%s', '%d', '%s', '%d', '%s', '%s', '%s' )
			);
		}
	}

	/**
	 * Applies one quick-action key (see get_portal_service_request_quick_actions) to a service
	 * request: updates status/service_status, records history, syncs the ledger for payment
	 * actions, and emails the customer on service_status changes. Shared by the WP admin quick
	 * action links and the AJ Ops API, so both surfaces behave identically.
	 *
	 * @return array|WP_Error array( 'request_id', 'status', 'service_status' ) plus a 'deleted' or
	 *                        'billing_change_applied' flag for those two special actions.
	 */
	private function apply_service_request_quick_action( $request_id, $action, $notify = false ) {
		$request_id = absint( $request_id );
		$action     = sanitize_key( (string) $action );

		if ( 'delete' === $action ) {
			$this->add_portal_service_request_history( $request_id, 'deleted', array( 'note' => __( 'Service request was deleted from the admin queue.', 'ajforms' ) ) );
			$this->handle_portal_service_request_delete( $request_id );
			return array( 'request_id' => $request_id, 'deleted' => true );
		}

		if ( 'apply_billing_change' === $action ) {
			$result = $this->apply_portal_billing_change_request( $request_id );
			if ( is_wp_error( $result ) ) {
				return $result;
			}
			$this->add_portal_service_request_history( $request_id, 'billing_change', array( 'note' => __( 'Billing change was applied.', 'ajforms' ) ) );
			return array( 'request_id' => $request_id, 'billing_change_applied' => true );
		}

		$payment_action_map = array(
			'await_payment' => 'awaiting_payment',
			'paid'          => 'paid',
			'failed'        => 'failed',
		);
		$service_action_map = array(
			'under_review'          => 'under_review',
			'pending_customer'      => 'pending_customer',
			'pending_agent'         => 'pending_agent',
			'schedule_meeting'      => 'meeting_scheduled',
			'file_sosnc'            => 'sosnc_filing',
			'email_llc_documents'   => 'llc_documents_emailed',
			'sign_cmra'             => 'signing_cmra',
			'collect_id_proof'      => 'id_proof_needed',
			'collect_address_proof' => 'address_proof_needed',
			'require_vo_setup'      => 'vo_setup_required',
			'customer_sosnc'        => 'sosnc_client',
			'update_sosn'           => 'updating_sosn',
			'included_llc_setup'    => 'included_with_llc_setup',
			'activate'              => 'active',
			'complete'              => 'completed',
			'cancel'                => 'cancelled',
		);

		$is_payment_action = isset( $payment_action_map[ $action ] );
		$is_service_action = isset( $service_action_map[ $action ] );
		if ( ! $is_payment_action && ! $is_service_action ) {
			return new WP_Error( 'invalid_action', __( 'Unknown quick action.', 'ajforms' ) );
		}

		$pdb     = $this->get_pdb();
		$request = $pdb->get_row( $pdb->prepare( "SELECT * FROM {$this->get_portal_service_requests_table()} WHERE id = %d", $request_id ) );
		if ( ! $request ) {
			return new WP_Error( 'not_found', __( 'Service request not found.', 'ajforms' ) );
		}

		$old_status         = sanitize_key( (string) $request->status );
		$old_service_status = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		$update_data        = array( 'updated_at' => current_time( 'mysql' ) );
		$update_formats     = array( '%s' );
		$new_status         = $old_status;
		$new_service_status = $old_service_status;

		if ( $is_payment_action ) {
			$new_status             = $payment_action_map[ $action ];
			$update_data['status']  = $new_status;
			$update_formats[]       = '%s';
		}
		if ( $is_service_action ) {
			$new_service_status             = $service_action_map[ $action ];
			$update_data['service_status']  = $new_service_status;
			$update_formats[]               = '%s';
		}

		$pdb->update(
			$this->get_portal_service_requests_table(),
			$update_data,
			array( 'id' => $request_id ),
			$update_formats,
			array( '%d' )
		);

		if ( $old_status !== $new_status || $old_service_status !== $new_service_status ) {
			$this->add_portal_service_request_history(
				$request_id,
				'status_changed',
				array(
					'status_before'         => $old_status,
					'status_after'          => $new_status,
					'service_status_before' => $old_service_status,
					'service_status_after'  => $new_service_status,
					'note'                  => sprintf( __( 'Quick action: %s', 'ajforms' ), ucwords( str_replace( '_', ' ', $action ) ) ),
					'details'               => array( 'action' => $action ),
				)
			);
			// SVC Status changes don't email the customer by default — same opt-in rule as
			// update_service_request_from_ops(); callers pass $notify=true to send it.
			if ( $notify ) {
				$this->send_service_request_status_email( $request, $old_service_status, $new_service_status );
			}
		}

		if ( $is_payment_action ) {
			$ledger_status   = 'awaiting_payment' === $new_status ? 'unpaid' : $new_status;
			$request->status = $new_status;
			$this->sync_portal_service_request_to_ledger( $request, array( 'status' => $ledger_status ) );
		}

		return array(
			'request_id'     => $request_id,
			'status'         => $new_status,
			'service_status' => $new_service_status,
		);
	}

	/** Public entry point for the ops REST API — applies a quick action key directly (e.g. "update_sosn"). */
	public function apply_service_request_quick_action_for_ops( $request_id, $action, $notify = false ) {
		return $this->apply_service_request_quick_action( $request_id, $action, $notify );
	}

	/** Public entry point for the ops REST API — the same button set the WP admin list shows for this row. */
	public function get_service_request_quick_actions_for_ops( $request, $raw_data = array() ) {
		return $this->get_portal_service_request_quick_actions( $request, $raw_data );
	}

	/**
	 * True when this request has a real next step (per get_portal_service_request_quick_actions)
	 * beyond just "cancel" or "delete" — used for the Needs Action stat and default filter so a
	 * request that is fully active/completed no longer counts, regardless of its raw status value.
	 */
	public function service_request_needs_action_for_ops( $request, $raw_data = array() ) {
		// Friends & Family / internal accounts (e.g. "Registered Agent Subscription F&F") are
		// complimentary accounts — no follow-up action is ever required for them.
		$service_name = isset( $request->service_name ) ? (string) $request->service_name : '';
		if ( false !== stripos( $service_name, 'f&f' ) ) {
			return false;
		}

		// A refund is always staff-actionable (decide whether to cancel the service and notify the
		// customer), but it isn't one of the forward workflow steps get_portal_service_request_quick_actions()
		// builds — that function treats a refunded pay status the same as "not paid" and offers no
		// next-step button for it, so without this check a refunded request would silently vanish
		// from the default "Needs Action" queue the moment the refund was detected.
		$status         = isset( $request->status ) ? sanitize_key( (string) $request->status ) : '';
		$service_status = isset( $request->service_status ) && '' !== $request->service_status ? sanitize_key( (string) $request->service_status ) : 'new';
		if ( in_array( $status, array( 'refunded', 'partially_refunded' ), true ) && ! in_array( $service_status, array( 'completed', 'cancelled' ), true ) ) {
			return true;
		}

		$actions = $this->get_portal_service_request_quick_actions( $request, $raw_data );
		unset( $actions['cancel'], $actions['delete'] );
		return ! empty( $actions );
	}

	private function handle_service_requests_actions() {
		if ( ! current_user_can( 'manage_options' ) ) {
			return;
		}

		$this->ensure_portal_schema();
		$this->backfill_portal_service_requests_from_ledger();
		$this->cleanup_stale_pending_checkout_service_requests();
		$this->handle_portal_service_request_details_save();
		$this->handle_service_requests_bulk_save();

		if ( ! isset( $_GET['service_request_action'], $_GET['request_id'], $_GET['_wpnonce'] ) ) {
			return;
		}

		$request_id = absint( wp_unslash( $_GET['request_id'] ) );
		$action     = sanitize_key( wp_unslash( $_GET['service_request_action'] ) );
		check_admin_referer( 'ajcore_service_request_' . $request_id );

		$result = $this->apply_service_request_quick_action( $request_id, $action );
		$args   = array( 'page' => 'ajforms-client-portal', 'tab' => 'service-requests' );

		if ( is_wp_error( $result ) ) {
			$args['service-request-error'] = rawurlencode( $result->get_error_message() );
		} elseif ( ! empty( $result['deleted'] ) ) {
			$args['service-request-deleted'] = 1;
		} else {
			$args['service-request-updated'] = 1;
			if ( ! empty( $result['billing_change_applied'] ) ) {
				$args['billing-change-applied'] = 1;
			}
		}

		wp_safe_redirect( add_query_arg( $args, admin_url( 'admin.php' ) ) );
		exit;
	}


	private function render_service_requests_admin_interface( $context = 'portal_tab' ) {
		global $wpdb;
		$pdb = $this->get_pdb();

		$this->ensure_portal_schema();
		$this->backfill_portal_service_requests_from_ledger();
		$this->cleanup_stale_pending_checkout_service_requests();

		$status_filter = isset( $_GET['request_status'] ) ? sanitize_key( wp_unslash( $_GET['request_status'] ) ) : '';
		$search        = isset( $_GET['s'] ) ? sanitize_text_field( wp_unslash( $_GET['s'] ) ) : '';
		$source_filter = isset( $_GET['sr_source'] ) ? sanitize_key( wp_unslash( $_GET['sr_source'] ) ) : 'hide_checkout';
		$labels        = $this->get_portal_service_request_status_labels();
		$service_labels = $this->get_portal_sr_service_status_labels();
		$where         = array( '1=1' );
		$params        = array();
		$show_actionable_default = '' === $status_filter && '' === $search;
		// service_view_filter mirrors the OR-based logic used for the Active/Completed stat
		// counts below (a request can be status='paid' but service_status='active' and still
		// belong to the "Active" view), so it's applied in PHP rather than as a literal
		// r.status = %s clause like the dropdown's other options.
		$service_view_filter = '';

		if ( 'all' === $status_filter ) {
			$status_filter = 'all';
		} elseif ( 'service_active' === $status_filter ) {
			$service_view_filter = 'active';
		} elseif ( 'service_completed' === $status_filter ) {
			$service_view_filter = 'completed';
		} elseif ( '' !== $status_filter && isset( $labels[ $status_filter ] ) ) {
			$where[]  = 'r.status = %s';
			$params[] = $status_filter;
		}
		// $show_actionable_default is applied in PHP below (via service_request_needs_action_for_ops),
		// not SQL — a literal status like 'paid' isn't enough on its own once the service_status has
		// reached active/completed, and that requires the same button logic the quick actions use.

		if ( 'checkout_only' === $source_filter ) {
			$where[] = "(r.source_type = 'checkout_session' OR r.source = 'checkout_session')";
		} elseif ( 'show_all' !== $source_filter ) {
			// Hide only unpaid/unfinished checkout leads by default. Paid checkout sessions are real service purchases and must stay visible.
			$where[] = "NOT ((r.source_type = 'checkout_session' OR r.source = 'checkout_session') AND r.status NOT IN ('paid','completed','active'))";
		}

		if ( '' !== $search ) {
			$like = '%' . $pdb->esc_like( $search ) . '%';
			$where[] = '(r.service_name LIKE %s OR r.stripe_customer_id LIKE %s OR c.email LIKE %s OR c.name LIKE %s OR r.client_notes LIKE %s OR r.admin_notes LIKE %s)';
			$params = array_merge( $params, array( $like, $like, $like, $like, $like, $like ) );
		}

		$sql = "SELECT r.*, c.email AS customer_email, c.name AS customer_name, l.metadata AS ledger_metadata, l.source_type AS ledger_source_type, l.invoice_id, l.payment_intent_id, l.charge_id, t.raw_data AS transaction_raw_data
			FROM {$this->get_portal_service_requests_table()} r
			LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = r.stripe_customer_id
			LEFT JOIN {$this->get_portal_ledger_table()} l ON l.id = r.ledger_id
			LEFT JOIN {$this->get_portal_stripe_transactions_table()} t ON t.stripe_object_id = r.source_object_id
			WHERE " . implode( ' AND ', $where ) . "
			ORDER BY r.updated_at DESC, r.created_at DESC, r.id DESC
			LIMIT 500";
		$requests_raw = ! empty( $params ) ? $pdb->get_results( $pdb->prepare( $sql, $params ) ) : $pdb->get_results( $sql );
		$user_ids     = array_values( array_unique( array_filter( array_map( function( $r ) { return (int) $r->wp_user_id; }, (array) $requests_raw ) ) ) );
		$users_by_id  = array();
		if ( ! empty( $user_ids ) ) {
			$uid_ph = implode( ',', array_fill( 0, count( $user_ids ), '%d' ) );
			foreach ( (array) $wpdb->get_results( $wpdb->prepare( "SELECT ID, user_email, display_name FROM {$wpdb->users} WHERE ID IN ({$uid_ph})", ...$user_ids ) ) as $u ) {
				$users_by_id[ (int) $u->ID ] = $u;
			}
		}
		$requests = array();
		foreach ( (array) $requests_raw as $r ) {
			if ( $show_actionable_default && ! $this->service_request_needs_action_for_ops( $r, $this->get_portal_service_request_raw_data( $r ) ) ) {
				continue;
			}
			if ( '' !== $service_view_filter && $service_view_filter !== sanitize_key( (string) $r->status ) && $service_view_filter !== sanitize_key( (string) $r->service_status ) ) {
				continue;
			}
			$u                  = isset( $users_by_id[ (int) $r->wp_user_id ] ) ? $users_by_id[ (int) $r->wp_user_id ] : null;
			$r->wp_user_email   = $u ? $u->user_email : '';
			$r->wp_display_name = $u ? $u->display_name : '';
			$requests[]         = $r;
			if ( count( $requests ) >= 200 ) {
				break;
			}
		}

		$counts = $pdb->get_results( "SELECT status, COUNT(*) AS total FROM {$this->get_portal_service_requests_table()} GROUP BY status", OBJECT_K );
		$checkout_source_count = (int) $pdb->get_var( "SELECT COUNT(*) FROM {$this->get_portal_service_requests_table()} WHERE source_type = 'checkout_session' OR source = 'checkout_session'" );

		$staff_users    = get_users( array( 'role__in' => array( 'administrator', 'aj_ops_user' ), 'number' => 200, 'orderby' => 'display_name' ) );
		$staff_by_id    = array();
		foreach ( $staff_users as $staff_user ) {
			$staff_by_id[ (int) $staff_user->ID ] = $staff_user;
		}

		// Stats reflect the whole table (not just the current filter) and use the same
		// needs-action logic as the quick-action buttons, so the numbers and the default list
		// never disagree — see service_request_needs_action_for_ops().
		$all_rows_for_stats = $pdb->get_results( "SELECT id, service_name, stripe_price_id, status, service_status FROM {$this->get_portal_service_requests_table()}" );
		$total_count        = count( $all_rows_for_stats );
		$needs_action_count = 0;
		$active_count       = 0;
		$completed_count    = 0;
		foreach ( $all_rows_for_stats as $stat_row ) {
			if ( $this->service_request_needs_action_for_ops( $stat_row ) ) {
				$needs_action_count++;
			}
			if ( 'active' === $stat_row->status || 'active' === $stat_row->service_status ) {
				$active_count++;
			}
			if ( 'completed' === $stat_row->status || 'completed' === $stat_row->service_status ) {
				$completed_count++;
			}
		}

		$is_standalone = 'standalone' === $context;
		$base_url = $is_standalone ? add_query_arg( array( 'page' => 'ajforms-service-requests' ), admin_url( 'admin.php' ) ) : add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'service-requests' ), admin_url( 'admin.php' ) );
		?>
		<style>
			.aj-sr-shell{display:grid;gap:12px;margin-top:10px}
			.aj-sr-topline{display:flex;align-items:center;gap:12px;flex-wrap:wrap}
			.aj-sr-stats{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;flex:1}
			.aj-sr-stat{background:#fff;border:1px solid #e4ebf3;border-radius:14px;padding:12px 16px;box-shadow:0 2px 8px rgba(15,23,42,.05);text-decoration:none;color:inherit;display:block;transition:box-shadow .15s,border-color .15s}
			.aj-sr-stat:hover{box-shadow:0 4px 14px rgba(15,23,42,.12)}
			.aj-sr-stat.is-active{border-color:#2563eb;box-shadow:0 0 0 2px rgba(37,99,235,.25)}
			.aj-sr-stat strong{display:block;font-size:22px;line-height:1;color:#0f172a;font-weight:800}
			.aj-sr-stat span{display:block;margin-top:4px;color:#64748b;font-weight:700;font-size:11px;text-transform:uppercase;letter-spacing:.5px}
			.aj-sr-toolbar{display:flex;gap:9px;align-items:center;flex-wrap:wrap;background:#fff;border:1px solid #e4ebf3;border-radius:14px;padding:10px 14px;box-shadow:0 2px 8px rgba(15,23,42,.05)}
			.aj-sr-bulk-bar{display:flex;gap:9px;align-items:center;flex-wrap:wrap;background:#eff6ff;border:1px solid #bfdbfe;border-radius:14px;padding:10px 14px}
			.aj-sr-bulk-bar select{min-height:36px;border-radius:8px;border-color:#bfdbfe;font-size:13px}
			.aj-sr-bulk-count{font-weight:700;color:#1d4ed8;font-size:13px;white-space:nowrap}
			.aj-sr-td-assignee{min-width:76px;max-width:98px}
			.aj-sr-td-assignee select{width:100%;min-height:26px;border-radius:6px;border:1px solid #cbd5e1;font-size:11px;padding:0 2px}
			.aj-sr-stepper{display:flex;align-items:flex-start;width:100%}
			.aj-sr-stepper-step{display:flex;align-items:flex-start}
			.aj-sr-stepper-step.is-grow{flex:1 1 0}
			.aj-sr-stepper-step:first-child{flex:none}
			.aj-sr-stepper-line{flex:1 1 0;min-width:10px;height:4px;margin-top:15px;background:#e2e8f0}
			.aj-sr-stepper-line.is-done{background:#86efac}
