													<?php foreach ( $staff_users as $staff_user ) : ?>
														<option value="<?php echo esc_attr( (int) $staff_user->ID ); ?>" <?php selected( (int) $request->assigned_user_id, (int) $staff_user->ID ); ?>><?php echo esc_html( $staff_user->display_name ); ?></option>
													<?php endforeach; ?>
												</select>
											</form>
