	private function handle_portal_billing_actions() {
		if ( ! current_user_can( 'manage_options' ) ) {
			return;
		}

		if ( isset( $_GET['billing_export'], $_GET['_wpnonce'] ) && 'csv' === sanitize_key( wp_unslash( $_GET['billing_export'] ) ) ) {
			check_admin_referer( 'ajcore_export_billing_ledger' );
			$this->export_portal_billing_csv();
			exit;
		}

		$action = isset( $_POST['ajcore_billing_action'] ) ? sanitize_key( wp_unslash( $_POST['ajcore_billing_action'] ) ) : '';
		if ( 'add_manual_charge' !== $action ) {
			return;
		}

		check_admin_referer( 'ajcore_add_manual_charge', 'ajcore_manual_charge_nonce' );
		$this->ensure_portal_schema();

		$stripe_customer_id = isset( $_POST['stripe_customer_id'] ) ? sanitize_text_field( wp_unslash( $_POST['stripe_customer_id'] ) ) : '';
		$description        = isset( $_POST['charge_label'] ) ? sanitize_text_field( wp_unslash( $_POST['charge_label'] ) ) : '';
		$amount             = isset( $_POST['charge_amount'] ) ? (float) sanitize_text_field( wp_unslash( $_POST['charge_amount'] ) ) : 0;
		$currency           = isset( $_POST['charge_currency'] ) ? strtolower( sanitize_key( wp_unslash( $_POST['charge_currency'] ) ) ) : 'usd';
		$client_notes       = isset( $_POST['client_notes'] ) ? sanitize_textarea_field( wp_unslash( $_POST['client_notes'] ) ) : (string) $request->client_notes;
		$admin_notes        = isset( $_POST['admin_notes'] ) ? sanitize_textarea_field( wp_unslash( $_POST['admin_notes'] ) ) : (string) $request->admin_notes;

		$redirect = add_query_arg(
			array(
				'page' => 'ajforms-client-portal',
				'tab'  => 'payments',
			),
			admin_url( 'admin.php' )
		);

		if ( '' === $stripe_customer_id || '' === $description || $amount <= 0 || '' === $currency ) {
			wp_safe_redirect( add_query_arg( 'billing-error', 'missing-fields', $redirect ) );
			exit;
		}

		$pdb             = $this->get_pdb();
		$customer_exists = (int) $pdb->get_var(
			$pdb->prepare(
				"SELECT COUNT(*) FROM {$this->get_portal_stripe_customers_table()} WHERE stripe_customer_id = %s",
				$stripe_customer_id
			)
		);

		if ( ! $customer_exists ) {
			wp_safe_redirect( add_query_arg( 'billing-error', 'customer-not-found', $redirect ) );
			exit;
		}

		$source_object_id = 'manual_charge_' . wp_generate_uuid4();
		$metadata = array(
			'source'       => 'manual_charge',
			'client_notes' => $client_notes,
			'admin_notes'  => $admin_notes,
			'created_by'   => get_current_user_id(),
		);

		$inserted = $pdb->insert(
			$this->get_portal_ledger_table(),
			array(
				'stripe_customer_id' => $stripe_customer_id,
				'source_object_id'   => $source_object_id,
				'source_type'        => 'manual_charge',
				'ledger_date'        => current_time( 'mysql' ),
				'description'        => $description,
				'amount'             => $amount,
				'currency'           => $currency,
				'status'             => 'unpaid',
				'invoice_id'         => '',
				'payment_intent_id'  => '',
				'charge_id'          => '',
				'metadata'           => wp_json_encode( $metadata ),
				'created_at'         => current_time( 'mysql' ),
			),
			array( '%s', '%s', '%s', '%s', '%s', '%f', '%s', '%s', '%s', '%s', '%s', '%s', '%s' )
		);

		if ( false === $inserted ) {
			wp_safe_redirect( add_query_arg( 'billing-error', 'insert-failed', $redirect ) );
			exit;
		}

		wp_safe_redirect( add_query_arg( 'manual-charge-added', '1', $redirect ) );
		exit;
	}

	private function get_portal_billing_filter_data() {
		global $wpdb;
		$pdb = $this->get_pdb();

		$status_filter   = isset( $_GET['billing_status'] ) ? sanitize_key( wp_unslash( $_GET['billing_status'] ) ) : '';
		$source_filter   = isset( $_GET['billing_source'] ) ? sanitize_key( wp_unslash( $_GET['billing_source'] ) ) : '';
		$customer_filter = isset( $_GET['billing_customer'] ) ? sanitize_text_field( wp_unslash( $_GET['billing_customer'] ) ) : '';
		$view_filter     = isset( $_GET['billing_view'] ) ? sanitize_key( wp_unslash( $_GET['billing_view'] ) ) : '';
		$search          = isset( $_GET['s'] ) ? sanitize_text_field( wp_unslash( $_GET['s'] ) ) : '';
		$where           = array( '1=1' );
		$params          = array();
		$open_statuses   = $this->get_portal_open_ledger_statuses();

		if ( '' !== $status_filter ) {
			$where[]  = 'l.status = %s';
			$params[] = $status_filter;
		}

		if ( '' !== $source_filter ) {
			$where[]  = 'l.source_type = %s';
			$params[] = $source_filter;
		} else {
			$where[] = "l.source_type <> 'refund'";
		}

		if ( '' !== $customer_filter ) {
			$where[]  = 'l.stripe_customer_id = %s';
			$params[] = $customer_filter;
		}

		if ( 'open' === $view_filter ) {
			$where[] = 'l.status IN (' . implode( ',', array_fill( 0, count( $open_statuses ), '%s' ) ) . ')';
			$params = array_merge( $params, $open_statuses );
		} elseif ( 'failed' === $view_filter ) {
			$failed_statuses = array( 'failed', 'payment_failed', 'requires_payment_method' );
			$where[] = 'l.status IN (' . implode( ',', array_fill( 0, count( $failed_statuses ), '%s' ) ) . ')';
			$params = array_merge( $params, $failed_statuses );
		} elseif ( 'overdue' === $view_filter ) {
			$ledger_columns = $pdb->get_col( "SHOW COLUMNS FROM {$this->get_portal_ledger_table()}", 0 );
			$date_expression = is_array( $ledger_columns ) && in_array( 'due_date', $ledger_columns, true ) ? 'COALESCE(NULLIF(l.due_date,\'\'), l.ledger_date)' : 'l.ledger_date';
			$where[] = 'l.status IN (' . implode( ',', array_fill( 0, count( $open_statuses ), '%s' ) ) . ')';
			$params = array_merge( $params, $open_statuses );
			$where[] = "DATE({$date_expression}) < %s";
			$params[] = current_time( 'Y-m-d' );
		}

		if ( '' !== $search ) {
			$like = '%' . $pdb->esc_like( $search ) . '%';
			$where[] = '(l.description LIKE %s OR l.stripe_customer_id LIKE %s OR l.invoice_id LIKE %s OR c.email LIKE %s OR c.name LIKE %s)';
			$params = array_merge( $params, array( $like, $like, $like, $like, $like ) );
		}

		return array(
			'status'   => $status_filter,
			'source'   => $source_filter,
			'customer' => $customer_filter,
			'view'     => $view_filter,
			'search'   => $search,
			'where'    => $where,
			'params'   => $params,
		);
	}

	private function export_portal_billing_csv() {
		$pdb = $this->get_pdb();

		$this->ensure_portal_schema();
		$filters = $this->get_portal_billing_filter_data();
		$sql = "SELECT l.*, c.email AS customer_email, c.name AS customer_name
			FROM {$this->get_portal_ledger_table()} l
			LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = l.stripe_customer_id
			WHERE " . implode( ' AND ', $filters['where'] ) . '
			ORDER BY l.ledger_date DESC, l.id DESC';
		$ledger = ! empty( $filters['params'] ) ? $pdb->get_results( $pdb->prepare( $sql, $filters['params'] ) ) : $pdb->get_results( $sql );

		nocache_headers();
		header( 'Content-Type: text/csv; charset=utf-8' );
		header( 'Content-Disposition: attachment; filename=ajcore-billing-ledger-' . gmdate( 'Ymd-His' ) . '.csv' );

		$output = fopen( 'php://output', 'w' );
		fputcsv( $output, array( 'Date', 'Customer', 'Email', 'Stripe Customer ID', 'Description', 'Transaction ID', 'Source', 'Status', 'Debit', 'Credit', 'Amount', 'Currency', 'Invoice ID', 'Charge ID' ) );
		foreach ( $ledger as $entry ) {
			$debit_credit = $this->get_portal_ledger_debit_credit( $entry );
			fputcsv(
				$output,
				array(
					$entry->ledger_date,
					$entry->customer_name,
					$entry->customer_email,
					$entry->stripe_customer_id,
					$this->get_portal_ledger_display_description( $entry ),
					$this->get_portal_ledger_transaction_id( $entry ),
					$entry->source_type,
					$entry->status,
					$debit_credit['debit'],
					$debit_credit['credit'],
					$entry->amount,
					$entry->currency,
					$entry->invoice_id,
					$entry->charge_id,
				)
			);
		}
		fclose( $output );
	}


	/** Billing KPIs for the ops REST API — same math as the WP admin Billing tab. */
	public function get_ops_billing_stats() {
		$pdb = $this->get_pdb();
		$this->ensure_portal_schema();

		$filters = $this->get_portal_billing_filter_data();
		$sql     = "SELECT l.*, c.email AS customer_email, c.name AS customer_name
			FROM {$this->get_portal_ledger_table()} l
			LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = l.stripe_customer_id
			WHERE " . implode( ' AND ', $filters['where'] ) . "
			ORDER BY l.ledger_date ASC, l.id ASC
			LIMIT 2000";
		$ledger  = ! empty( $filters['params'] ) ? $pdb->get_results( $pdb->prepare( $sql, $filters['params'] ) ) : $pdb->get_results( $sql );
		$ledger  = $this->get_admin_portal_display_ledger( $ledger );

		$balance_data   = $this->get_portal_ledger_running_balances( $ledger );
		$open_balance   = 0.0;
		$credit_balance = 0.0;
		$paid_total     = 0.0;
		foreach ( $ledger as $entry ) {
			$effect = $this->get_portal_ledger_balance_effect( $entry );
			if ( $effect < 0 && in_array( sanitize_key( (string) $entry->status ), array( 'paid', 'succeeded', 'partially_refunded', 'partial_refund' ), true ) ) {
				$paid_total += abs( $effect );
			}
		}
		foreach ( $balance_data['totals'] as $customer_balance ) {
			$customer_balance = (float) $customer_balance;
			if ( $customer_balance > 0.00001 ) {
				$open_balance += $customer_balance;
			} elseif ( $customer_balance < -0.00001 ) {
				$credit_balance += abs( $customer_balance );
			}
		}

		return array(
			'records'        => (int) $pdb->get_var( "SELECT COUNT(*) FROM {$this->get_portal_ledger_table()}" ),
			'open_balance'   => round( $open_balance, 2 ),
			'credit_balance' => round( $credit_balance, 2 ),
			'paid_total'     => round( $paid_total, 2 ),
		);
	}

	/**
	 * Business grouping for a payment row: did the customer pay, or not?
	 */
	private function get_portal_payment_status_group( $row ) {
		$refund = isset( $row['refund_status'] ) ? (string) $row['refund_status'] : '';
		if ( 'refunded' === $refund || 'partially_refunded' === $refund ) {
			return 'refunded';
		}
		$status = sanitize_key( isset( $row['status'] ) ? (string) $row['status'] : '' );
		$map    = array(
			'paid'                    => 'paid',
			'succeeded'               => 'paid',
			'pending'                 => 'pending',
			'pending_payment'         => 'pending',
			'processing'              => 'pending',
			'open'                    => 'unpaid',
			'unpaid'                  => 'unpaid',
			'uncollectible'           => 'unpaid',
			'awaiting_payment'        => 'unpaid',
			'requires_payment_method' => 'unpaid',
			'failed'                  => 'failed',
			'void'                    => 'canceled',
			'canceled'                => 'canceled',
			'cancelled'               => 'canceled',
			'draft'                   => 'canceled',
			'refunded'                => 'refunded',
			'partially_refunded'      => 'refunded',
			'partial_refund'          => 'refunded',
		);
		return isset( $map[ $status ] ) ? $map[ $status ] : 'other';
	}

	private function get_portal_payment_status_display( $row ) {
		$refund = isset( $row['refund_status'] ) ? (string) $row['refund_status'] : '';
		if ( 'refunded' === $refund ) {
			return array( __( 'Refunded', 'ajforms' ), 'off' );
		}
		if ( 'partially_refunded' === $refund ) {
			return array( __( 'Partial Refund', 'ajforms' ), 'disabled' );
		}
		$status = sanitize_key( isset( $row['status'] ) ? (string) $row['status'] : '' );
		switch ( $this->get_portal_payment_status_group( $row ) ) {
			case 'paid':
				return array( __( 'Paid', 'ajforms' ), 'active' );
			case 'pending':
				return array( __( 'Pending', 'ajforms' ), 'disabled' );
			case 'unpaid':
				return array( __( 'Unpaid', 'ajforms' ), 'archived' );
			case 'failed':
				return array( __( 'Failed', 'ajforms' ), 'archived' );
			case 'canceled':
				return 'draft' === $status ? array( __( 'Draft', 'ajforms' ), 'off' ) : array( __( 'Canceled', 'ajforms' ), 'off' );
			case 'refunded':
				return array( __( 'Refunded', 'ajforms' ), 'off' );
		}
		return array( '' !== $status ? ucwords( str_replace( '_', ' ', $status ) ) : '—', 'off' );
	}

	/**
	 * Payments tab — replaces the old Billing (ledger) and Transactions (sold items) tabs
	 * with one staff-facing view: who paid, for what service/product, how much, how it was
	 * paid, when, and refund status. Same framing as the AJOps Payments screen.
	 */
	private function display_portal_payments_tab() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		$pdb = $this->get_pdb();
		$this->ensure_portal_schema();
		$this->cleanup_unpaid_portal_checkout_sessions();
		$this->backfill_portal_ledger_service_charges_from_snapshots();

		$search          = isset( $_GET['pay_search'] ) ? sanitize_text_field( wp_unslash( $_GET['pay_search'] ) ) : '';
		$status_filter   = isset( $_GET['pay_status'] ) ? sanitize_key( wp_unslash( $_GET['pay_status'] ) ) : '';
		$status_filter   = in_array( $status_filter, array( 'paid', 'unpaid', 'pending', 'refunded', 'failed', 'canceled' ), true ) ? $status_filter : '';
		$customer_filter = isset( $_GET['pay_customer'] ) ? sanitize_text_field( wp_unslash( $_GET['pay_customer'] ) ) : '';

		$rows = $pdb->get_results(
			"SELECT t.id, t.stripe_object_id, t.object_type, t.stripe_customer_id, t.description, t.amount, t.currency, t.status, t.transaction_date, t.invoice_id, t.payment_intent_id, t.charge_id, t.raw_data, c.name AS customer_name, c.email AS customer_email
			FROM {$this->get_portal_stripe_transactions_table()} t
			LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = t.stripe_customer_id
			ORDER BY t.transaction_date DESC, t.id DESC
			LIMIT 500",
			ARRAY_A
		);
		$rows = is_array( $rows ) ? $rows : array();
		if ( class_exists( 'AJCore_REST_API' ) ) {
			$api  = new AJCore_REST_API();
			$rows = $api->dedupe_stripe_transaction_rows( $rows );
			$rows = $api->attach_payment_display_fields( $rows );
		}

		// Staff-recorded manual charges live in the ledger, not in synced Stripe transactions.
		$manual_rows = $pdb->get_results(
			"SELECT l.ledger_date AS transaction_date, l.stripe_customer_id, l.description, l.amount, l.currency, l.status, c.name AS customer_name, c.email AS customer_email
			FROM {$this->get_portal_ledger_table()} l
			LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = l.stripe_customer_id
			WHERE l.source_type = 'manual_charge'
			ORDER BY l.ledger_date DESC
			LIMIT 200",
			ARRAY_A
		);
		foreach ( (array) $manual_rows as $entry ) {
			$entry['object_type']     = 'manual_charge';
			$entry['service_name']    = (string) $entry['description'];
			$entry['payment_method']  = '';
			$entry['refund_status']   = '';
			$entry['refunded_amount'] = 0;
			$entry['refunded_at']     = '';
			$rows[] = $entry;
		}
		usort(
			$rows,
			function ( $a, $b ) {
				$a_ts = ! empty( $a['transaction_date'] ) ? strtotime( (string) $a['transaction_date'] ) : 0;
				$b_ts = ! empty( $b['transaction_date'] ) ? strtotime( (string) $b['transaction_date'] ) : 0;
				return $b_ts <=> $a_ts;
			}
		);

		$paid_count = 0;
		$collected  = 0.0;
		$refunded   = 0.0;
		foreach ( $rows as $row ) {
			if ( 'paid' === $this->get_portal_payment_status_group( $row ) || in_array( sanitize_key( (string) $row['status'] ), array( 'paid', 'succeeded' ), true ) ) {
				$paid_count++;
				$collected += (float) $row['amount'];
			}
			if ( ! empty( $row['refunded_amount'] ) ) {
				$refunded += (float) $row['refunded_amount'];
			}
		}
		$collected -= $refunded;

		$filtered = array();
		foreach ( $rows as $row ) {
			if ( '' !== $customer_filter && (string) $row['stripe_customer_id'] !== $customer_filter ) {
				continue;
			}
			if ( '' !== $status_filter && $this->get_portal_payment_status_group( $row ) !== $status_filter ) {
				continue;
			}
			if ( '' !== $search ) {
				$haystack = strtolower(
					implode(
						' ',
						array(
							isset( $row['service_name'] ) ? (string) $row['service_name'] : '',
							isset( $row['description'] ) ? (string) $row['description'] : '',
							isset( $row['customer_name'] ) ? (string) $row['customer_name'] : '',
							isset( $row['customer_email'] ) ? (string) $row['customer_email'] : '',
							isset( $row['stripe_customer_id'] ) ? (string) $row['stripe_customer_id'] : '',
							isset( $row['payment_method'] ) ? (string) $row['payment_method'] : '',
							isset( $row['status'] ) ? (string) $row['status'] : '',
						)
					)
				);
				if ( false === strpos( $haystack, strtolower( $search ) ) ) {
					continue;
				}
			}
			$filtered[] = $row;
		}

		$customers  = $pdb->get_results( "SELECT stripe_customer_id, email, name FROM {$this->get_portal_stripe_customers_table()} ORDER BY name ASC, email ASC, stripe_customer_id ASC LIMIT 500" );
		$base_url   = add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'payments' ), admin_url( 'admin.php' ) );
		$export_url = wp_nonce_url( add_query_arg( array_merge( $_GET, array( 'billing_export' => 'csv' ) ), admin_url( 'admin.php' ) ), 'ajcore_export_billing_ledger' );
		?>
		<div class="ajcore-admin-panel">
			<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'Payments', 'ajforms' ); ?></h2><p><?php esc_html_e( 'Customer payment activity from Stripe — what was purchased, how much, how it was paid, and refunds. Staff-recorded charges are included.', 'ajforms' ); ?></p></div><a class="button" href="<?php echo esc_url( $export_url ); ?>"><?php esc_html_e( 'Export Ledger CSV', 'ajforms' ); ?></a></div>
			<div class="ajcore-kpi-grid">
				<div class="ajcore-kpi-card"><span><?php esc_html_e( 'Payments Received', 'ajforms' ); ?></span><strong><?php echo esc_html( number_format_i18n( $paid_count ) ); ?></strong></div>
				<div class="ajcore-kpi-card"><span><?php esc_html_e( 'Collected', 'ajforms' ); ?></span><strong><?php echo esc_html( $this->format_portal_money( $collected, 'usd' ) ); ?></strong></div>
				<div class="ajcore-kpi-card"><span><?php esc_html_e( 'Refunded', 'ajforms' ); ?></span><strong><?php echo esc_html( $this->format_portal_money( $refunded, 'usd' ) ); ?></strong></div>
			</div>

			<?php if ( isset( $_GET['manual-charge-added'] ) ) : ?>
				<div class="notice notice-success inline"><p><?php esc_html_e( 'Customer charge added.', 'ajforms' ); ?></p></div>
			<?php elseif ( isset( $_GET['billing-error'] ) ) : ?>
				<div class="notice notice-error inline"><p><?php esc_html_e( 'Unable to add customer charge. Please check the customer, label, and amount.', 'ajforms' ); ?></p></div>
			<?php endif; ?>

			<details class="ajcore-admin-card" style="margin:16px 0;padding:16px;border:1px solid #dcdcde;background:#fff;border-radius:8px;">
				<summary style="font-weight:700;cursor:pointer;"><?php esc_html_e( 'Add Customer Charge', 'ajforms' ); ?></summary>
				<form method="post" style="margin-top:14px;display:grid;grid-template-columns:repeat(2,minmax(220px,1fr));gap:12px;max-width:920px;">
					<input type="hidden" name="page" value="ajforms-client-portal">
					<input type="hidden" name="tab" value="payments">
					<input type="hidden" name="ajcore_billing_action" value="add_manual_charge">
					<?php wp_nonce_field( 'ajcore_add_manual_charge', 'ajcore_manual_charge_nonce' ); ?>
					<label style="display:flex;flex-direction:column;gap:6px;grid-column:1/-1;"><?php esc_html_e( 'Customer', 'ajforms' ); ?>
						<select name="stripe_customer_id" required>
							<option value=""><?php esc_html_e( 'Select customer', 'ajforms' ); ?></option>
							<?php foreach ( $customers as $customer ) : ?>
								<?php $customer_label = $customer->name ? $customer->name : ( $customer->email ? $customer->email : $customer->stripe_customer_id ); ?>
								<option value="<?php echo esc_attr( $customer->stripe_customer_id ); ?>"><?php echo esc_html( $customer_label . ' — ' . $customer->stripe_customer_id ); ?></option>
							<?php endforeach; ?>
						</select>
					</label>
					<label style="display:flex;flex-direction:column;gap:6px;"><?php esc_html_e( 'Charge Label', 'ajforms' ); ?><input type="text" name="charge_label" required placeholder="<?php esc_attr_e( 'Document filing fee', 'ajforms' ); ?>"></label>
					<label style="display:flex;flex-direction:column;gap:6px;"><?php esc_html_e( 'Amount', 'ajforms' ); ?><span><input type="number" min="0.01" step="0.01" name="charge_amount" required style="width:140px;"> <input type="text" name="charge_currency" value="usd" style="width:70px;"></span></label>
					<label style="display:flex;flex-direction:column;gap:6px;grid-column:1/-1;"><?php esc_html_e( 'Client-facing Note', 'ajforms' ); ?><textarea name="client_notes" rows="2" placeholder="<?php esc_attr_e( 'This note appears in the client billing ledger.', 'ajforms' ); ?>"></textarea></label>
					<label style="display:flex;flex-direction:column;gap:6px;grid-column:1/-1;"><?php esc_html_e( 'Internal Admin Notes', 'ajforms' ); ?><textarea name="admin_notes" rows="2"></textarea></label>
					<div style="grid-column:1/-1;"><button type="submit" class="button button-primary"><?php esc_html_e( 'Add Charge', 'ajforms' ); ?></button></div>
				</form>
			</details>

			<form method="get" style="margin:14px 0;display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
				<input type="hidden" name="page" value="ajforms-client-portal">
				<input type="hidden" name="tab" value="payments">
				<input type="search" name="pay_search" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php esc_attr_e( 'Search customer, service, payment method', 'ajforms' ); ?>" style="min-width:280px;">
				<select name="pay_status">
					<option value=""><?php esc_html_e( 'All statuses', 'ajforms' ); ?></option>
					<option value="paid" <?php selected( $status_filter, 'paid' ); ?>><?php esc_html_e( 'Paid', 'ajforms' ); ?></option>
					<option value="unpaid" <?php selected( $status_filter, 'unpaid' ); ?>><?php esc_html_e( 'Unpaid', 'ajforms' ); ?></option>
					<option value="pending" <?php selected( $status_filter, 'pending' ); ?>><?php esc_html_e( 'Pending', 'ajforms' ); ?></option>
					<option value="refunded" <?php selected( $status_filter, 'refunded' ); ?>><?php esc_html_e( 'Refunded', 'ajforms' ); ?></option>
					<option value="failed" <?php selected( $status_filter, 'failed' ); ?>><?php esc_html_e( 'Failed', 'ajforms' ); ?></option>
					<option value="canceled" <?php selected( $status_filter, 'canceled' ); ?>><?php esc_html_e( 'Canceled', 'ajforms' ); ?></option>
				</select>
				<select name="pay_customer">
					<option value=""><?php esc_html_e( 'All customers', 'ajforms' ); ?></option>
					<?php foreach ( $customers as $customer ) : ?>
						<?php $customer_label = $customer->name ? $customer->name : ( $customer->email ? $customer->email : $customer->stripe_customer_id ); ?>
						<option value="<?php echo esc_attr( $customer->stripe_customer_id ); ?>" <?php selected( $customer_filter, $customer->stripe_customer_id ); ?>><?php echo esc_html( $customer_label ); ?></option>
					<?php endforeach; ?>
				</select>
				<button class="button"><?php esc_html_e( 'Filter', 'ajforms' ); ?></button>
				<a class="button" href="<?php echo esc_url( $base_url ); ?>"><?php esc_html_e( 'Reset', 'ajforms' ); ?></a>
				<span style="color:#64748b;font-size:12px;font-weight:700;"><?php echo esc_html( sprintf( _n( '%d payment shown', '%d payments shown', count( $filtered ), 'ajforms' ), count( $filtered ) ) ); ?></span>
			</form>

			<table class="widefat striped">
				<thead>
					<tr>
						<th><?php esc_html_e( 'Date', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Customer', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Service / Product', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Amount', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Payment Method', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Status', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Refund', 'ajforms' ); ?></th>
					</tr>
				</thead>
				<tbody>
				<?php if ( empty( $filtered ) ) : ?>
					<tr><td colspan="7"><?php esc_html_e( 'No payments found for this filter.', 'ajforms' ); ?></td></tr>
				<?php else : ?>
					<?php foreach ( $filtered as $row ) : ?>
						<?php
						$customer_label = ! empty( $row['customer_name'] ) ? $row['customer_name'] : ( ! empty( $row['customer_email'] ) ? $row['customer_email'] : $row['stripe_customer_id'] );
						$status_display = $this->get_portal_payment_status_display( $row );
						$service_label  = ! empty( $row['service_name'] ) ? $row['service_name'] : ( ! empty( $row['description'] ) ? $row['description'] : '—' );
						?>
						<tr>
							<td><?php echo esc_html( ! empty( $row['transaction_date'] ) ? date_i18n( get_option( 'date_format' ) . ' ' . get_option( 'time_format' ), strtotime( $row['transaction_date'] . ' UTC' ) ) : '-' ); ?></td>
							<td><?php echo esc_html( $customer_label ); ?><br><small><?php echo esc_html( ! empty( $row['customer_email'] ) && $customer_label !== $row['customer_email'] ? $row['customer_email'] : (string) $row['stripe_customer_id'] ); ?></small><br><a href="<?php echo esc_url( $this->get_portal_customer_360_url( $row['stripe_customer_id'] ) ); ?>"><?php esc_html_e( 'View', 'ajforms' ); ?></a></td>
							<td><?php echo esc_html( $service_label ); ?><?php if ( 'manual_charge' === $row['object_type'] ) : ?><br><small><?php esc_html_e( 'Staff-recorded charge', 'ajforms' ); ?></small><?php endif; ?></td>
							<td><strong><?php echo esc_html( $this->format_portal_money( (float) $row['amount'], (string) $row['currency'] ) ); ?></strong></td>
							<td><?php echo ! empty( $row['payment_method'] ) ? esc_html( $row['payment_method'] ) : '<span style="color:#94a3b8;">—</span>'; ?></td>
							<td><span class="ajcore-status-pill <?php echo esc_attr( $status_display[1] ); ?>"><?php echo esc_html( $status_display[0] ); ?></span></td>
							<td>
								<?php if ( ! empty( $row['refunded_amount'] ) ) : ?>
									<?php echo esc_html( $this->format_portal_money( (float) $row['refunded_amount'], (string) $row['currency'] ) ); ?>
									<?php if ( ! empty( $row['refunded_at'] ) ) : ?><br><small><?php echo esc_html( date_i18n( get_option( 'date_format' ), strtotime( $row['refunded_at'] . ' UTC' ) ) ); ?></small><?php endif; ?>
								<?php else : ?>
									<span style="color:#94a3b8;">—</span>
								<?php endif; ?>
							</td>
						</tr>
					<?php endforeach; ?>
				<?php endif; ?>
				</tbody>
			</table>
		</div>
		<?php
	}

	private function get_portal_dashboard_url( $tab, $args = array() ) {
		$args = array_merge(
			array(
				'page' => 'ajforms-client-portal',
				'tab'  => sanitize_key( (string) $tab ),
			),
			(array) $args
		);

		return add_query_arg( $args, admin_url( 'admin.php' ) );
	}

	private function get_portal_customer_360_url( $stripe_customer_id ) {
		return add_query_arg(
			array(
				'page'               => 'ajforms-client-portal',
				'tab'                => 'customer',
				'stripe_customer_id' => sanitize_text_field( (string) $stripe_customer_id ),
			),
			admin_url( 'admin.php' )
		);
	}

	private function render_portal_dashboard_metric( $label, $value, $url = '', $note = '' ) {
		?>
		<a class="ajcore-dashboard-metric" href="<?php echo esc_url( $url ? $url : '#' ); ?>">
			<span class="ajcore-dashboard-label"><?php echo esc_html( $label ); ?></span>
			<strong><?php echo esc_html( (string) $value ); ?></strong>
			<?php if ( '' !== (string) $note ) : ?>
				<small><?php echo esc_html( (string) $note ); ?></small>
			<?php endif; ?>
		</a>
		<?php
	}

	private function get_portal_dashboard_task_metrics() {
		global $wpdb;

		$tasks_table         = $this->get_portal_tasks_table();
		$task_statuses_table = $this->get_portal_task_statuses_table();
		$today               = current_time( 'Y-m-d' );
		$closed_statuses     = array( 'completed', 'verified', 'closed', 'cancelled', 'canceled', 'archived' );
		$closed_placeholders = implode( ',', array_fill( 0, count( $closed_statuses ), '%s' ) );

		return array(
			'overdue' => (int) $wpdb->get_var(
				$wpdb->prepare(
					"SELECT COUNT(DISTINCT t.id)
					FROM {$tasks_table} t
					LEFT JOIN {$task_statuses_table} ts ON ts.task_id = t.id AND ts.stripe_customer_id = t.stripe_customer_id
					WHERE t.due_date IS NOT NULL
					AND t.due_date < %s
					AND COALESCE(NULLIF(ts.status, ''), t.status) NOT IN ({$closed_placeholders})",
					array_merge( array( $today ), $closed_statuses )
				)
			),
		);
	}

	private function get_portal_dashboard_billing_metrics() {
		$pdb   = $this->get_pdb();
		$today = current_time( 'Y-m-d' );
		$ledger = $pdb->get_results( "SELECT * FROM {$this->get_portal_ledger_table()}" );
		$ledger         = $this->get_admin_portal_display_ledger( $ledger );
		$customer_balances = array();
		$open_customer_balances = array();
		$open_balance   = 0.0;
		$credit_balance = 0.0;
		$overdue_amount = 0.0;
		$failed_count   = 0;

		foreach ( $ledger as $entry ) {
			$status   = isset( $entry->status ) ? sanitize_key( (string) $entry->status ) : '';
			$effect   = $this->get_portal_ledger_balance_effect( $entry );
			$due_date = '';
			$customer_id = ! empty( $entry->stripe_customer_id ) ? sanitize_text_field( (string) $entry->stripe_customer_id ) : '_unknown';
			if ( ! isset( $customer_balances[ $customer_id ] ) ) {
				$customer_balances[ $customer_id ] = 0.0;
			}
			$customer_balances[ $customer_id ] += $effect;
			if ( $effect > 0 && in_array( $status, $this->get_portal_open_ledger_statuses(), true ) ) {
				if ( ! isset( $open_customer_balances[ $customer_id ] ) ) {
					$open_customer_balances[ $customer_id ] = 0.0;
				}
				$open_customer_balances[ $customer_id ] += $effect;
			}

			if ( in_array( $status, array( 'failed', 'payment_failed', 'requires_payment_method' ), true ) ) {
				$failed_count++;
			}

			if ( isset( $entry->due_date ) && ! empty( $entry->due_date ) ) {
				$due_date = substr( (string) $entry->due_date, 0, 10 );
			} elseif ( ! empty( $entry->ledger_date ) ) {
				$due_date = substr( (string) $entry->ledger_date, 0, 10 );
			}

			if ( $effect > 0 && '' !== $due_date && $due_date < $today && in_array( $status, $this->get_portal_open_ledger_statuses(), true ) ) {
				$overdue_amount += $effect;
			}
		}

		foreach ( $open_customer_balances as $balance ) {
			if ( $balance > 0.00001 ) {
				$open_balance += $balance;
			}
		}

		foreach ( $customer_balances as $balance ) {
			if ( $balance < -0.00001 ) {
				$credit_balance += abs( $balance );
			}
		}

		return array(
			'open_balance'   => $open_balance,
			'credit_balance' => $credit_balance,
			'overdue_amount' => $overdue_amount,
			'failed_count'   => $failed_count,
		);
	}

	/** Cross-entity search rendered on the Client Portal dashboard. */
	private function render_portal_global_search_results() {
		global $wpdb;

		$q = isset( $_GET['portal_q'] ) ? sanitize_text_field( wp_unslash( $_GET['portal_q'] ) ) : '';
		if ( strlen( $q ) < 2 ) {
			return;
		}

		$pdb  = $this->get_pdb();
		$like = '%' . $pdb->esc_like( $q ) . '%';

		$customers = $pdb->get_results( $pdb->prepare( "SELECT stripe_customer_id, name, email FROM {$this->get_portal_stripe_customers_table()} WHERE name LIKE %s OR email LIKE %s OR stripe_customer_id LIKE %s ORDER BY name ASC LIMIT 10", $like, $like, $like ) );
		$requests  = $pdb->get_results( $pdb->prepare( "SELECT r.id, r.service_name, r.status, r.service_status, c.name AS customer_name FROM {$this->get_portal_service_requests_table()} r LEFT JOIN {$this->get_portal_stripe_customers_table()} c ON c.stripe_customer_id = r.stripe_customer_id WHERE r.service_name LIKE %s OR c.name LIKE %s OR c.email LIKE %s ORDER BY r.updated_at DESC LIMIT 10", $like, $like, $like ) );
		$txns      = $pdb->get_results( $pdb->prepare( "SELECT stripe_object_id, stripe_customer_id, description, amount, currency, status FROM {$this->get_portal_stripe_transactions_table()} WHERE description LIKE %s OR stripe_object_id LIKE %s OR stripe_customer_id LIKE %s ORDER BY transaction_date DESC LIMIT 10", $like, $like, $like ) );
		$tasks     = $pdb->get_results( $pdb->prepare( "SELECT id, title, status, stripe_customer_id FROM {$this->get_portal_tasks_table()} WHERE title LIKE %s OR action_required LIKE %s ORDER BY updated_at DESC LIMIT 10", $like, $like ) );
		$files     = $wpdb->get_results( $wpdb->prepare( "SELECT id, title, category FROM {$this->get_portal_files_table()} WHERE title LIKE %s OR category LIKE %s OR description LIKE %s ORDER BY created_at DESC LIMIT 10", $like, $like, $like ) );

		$sections = array(
			array( __( 'Customers', 'ajforms' ), $customers, function ( $row ) {
				return '<a href="' . esc_url( $this->get_portal_customer_360_url( $row->stripe_customer_id ) ) . '">' . esc_html( $row->name ? $row->name : $row->stripe_customer_id ) . '</a> <span class="description">' . esc_html( $row->email ) . '</span>';
			} ),
			array( __( 'Service Requests', 'ajforms' ), $requests, function ( $row ) {
				return '<a href="' . esc_url( $this->get_portal_dashboard_url( 'service-requests' ) ) . '">' . esc_html( $row->service_name ? $row->service_name : sprintf( __( 'Request #%d', 'ajforms' ), $row->id ) ) . '</a> <span class="description">' . esc_html( trim( ( $row->customer_name ? $row->customer_name . ' · ' : '' ) . $row->status . ( $row->service_status ? ' / ' . $row->service_status : '' ) ) ) . '</span>';
			} ),
			array( __( 'Payments', 'ajforms' ), $txns, function ( $row ) {
				return '<a href="' . esc_url( $this->get_portal_customer_360_url( $row->stripe_customer_id ) ) . '">' . esc_html( $row->description ? $row->description : $row->stripe_object_id ) . '</a> <span class="description">' . esc_html( strtoupper( (string) $row->currency ) . ' ' . number_format( (float) $row->amount, 2 ) . ' · ' . $row->status ) . '</span>';
			} ),
			array( __( 'Action Items', 'ajforms' ), $tasks, function ( $row ) {
				return '<a href="' . esc_url( $this->get_portal_dashboard_url( 'tasks' ) ) . '">' . esc_html( $row->title ) . '</a> <span class="description">' . esc_html( $row->status ) . '</span>';
			} ),
			array( __( 'Files', 'ajforms' ), $files, function ( $row ) {
				return '<a href="' . esc_url( $this->get_portal_dashboard_url( 'file-library' ) ) . '">' . esc_html( $row->title ) . '</a>' . ( $row->category ? ' <span class="description">' . esc_html( $row->category ) . '</span>' : '' );
			} ),
		);

		$any = false;
		foreach ( $sections as $section ) {
			if ( ! empty( $section[1] ) ) {
				$any = true;
				break;
			}
		}
		?>
		<div class="ajcore-admin-panel" style="margin-top:6px;">
			<h3 style="margin-top:0;"><?php echo esc_html( sprintf( __( 'Search results for “%s”', 'ajforms' ), $q ) ); ?></h3>
			<?php if ( ! $any ) : ?>
				<p><?php esc_html_e( 'Nothing found across customers, requests, transactions, tasks, or files.', 'ajforms' ); ?></p>
			<?php else : ?>
				<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:16px;">
					<?php foreach ( $sections as $section ) : ?>
						<?php if ( empty( $section[1] ) ) { continue; } ?>
						<div>
							<h4 style="margin:0 0 8px;"><?php echo esc_html( $section[0] ); ?></h4>
							<ul style="margin:0;padding-left:18px;">
								<?php foreach ( $section[1] as $row ) : ?>
									<li><?php echo wp_kses_post( call_user_func( $section[2], $row ) ); ?></li>
								<?php endforeach; ?>
							</ul>
						</div>
					<?php endforeach; ?>
				</div>
			<?php endif; ?>
		</div>
		<?php
	}

	private function display_portal_dashboard_tab() {
		global $wpdb;

		$this->ensure_portal_schema();

		$customers_table        = $this->get_portal_stripe_customers_table();
		$subscriptions_table    = $this->get_portal_stripe_subscriptions_table();
		$service_requests_table = $this->get_portal_service_requests_table();
		$sync_logs_table        = $this->get_portal_sync_logs_table();

		$active_customers      = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$customers_table} WHERE portal_status = 'active' AND enabled_portal = 1" );
		$active_subscription_objects = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$subscriptions_table} WHERE status IN ('active','trialing')" );
		$active_subscription_rows = $wpdb->get_results(
			"SELECT s.*, c.name AS customer_name, c.email AS customer_email
			FROM {$subscriptions_table} s
			LEFT JOIN {$customers_table} c ON c.stripe_customer_id = s.stripe_customer_id
			WHERE s.status IN ('active','trialing')
			ORDER BY s.current_period_end ASC
			LIMIT 2000"
		);
		$active_recurring_services = $this->dedupe_portal_service_records( array_merge( $this->get_portal_service_records_from_subscriptions( $active_subscription_rows ), $this->get_portal_recurring_service_records_from_ledger( '', 2000 ) ) );
		$auto_pay_services    = count( $active_recurring_services );
		$one_time_services    = count( $this->get_portal_one_time_paid_services( '', 2000 ) );
		$active_services      = $auto_pay_services + $one_time_services;
		$billing_metrics      = $this->get_portal_dashboard_billing_metrics();
		$paid_not_completed   = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$service_requests_table} WHERE status = 'paid'" );
		$admin_review_required = (int) $wpdb->get_var( "SELECT COUNT(*) FROM {$service_requests_table} WHERE status = 'admin_review_required'" );
		$task_metrics         = $this->get_portal_dashboard_task_metrics();
		$stripe_mode          = $this->get_stripe_mode_badge_data();
		$last_success         = $wpdb->get_row( "SELECT * FROM {$sync_logs_table} WHERE status = 'success' ORDER BY finished_at DESC, started_at DESC, id DESC LIMIT 1" );
		$last_failed          = $wpdb->get_row( "SELECT * FROM {$sync_logs_table} WHERE status = 'failed' ORDER BY finished_at DESC, started_at DESC, id DESC LIMIT 1" );
		$last_webhook         = $wpdb->get_row( "SELECT * FROM {$sync_logs_table} WHERE source = 'webhook' ORDER BY started_at DESC, id DESC LIMIT 1" );
		$last_success_time    = $last_success ? strtotime( $last_success->finished_at ? $last_success->finished_at : $last_success->started_at ) : 0;
		$last_failed_time     = $last_failed ? strtotime( $last_failed->finished_at ? $last_failed->finished_at : $last_failed->started_at ) : 0;
		$health_has_issue     = ! empty( $stripe_mode['has_issues'] ) || ! $last_success || ! $last_webhook || ( $last_failed_time > $last_success_time );
		$health_note          = $last_success ? sprintf( __( 'Last sync: %s', 'ajforms' ), $last_success->finished_at ? $last_success->finished_at : $last_success->started_at ) : __( 'No successful sync found.', 'ajforms' );
		if ( $last_webhook ) {
			$health_note .= ' · ' . sprintf( __( 'Webhook: %s', 'ajforms' ), ucfirst( sanitize_key( (string) $last_webhook->status ) ) );
		} else {
			$health_note .= ' · ' . __( 'No webhook events yet.', 'ajforms' );
		}
		?>
		<div class="ajforms-settings-card ajcore-dashboard">
			<style>
				.ajcore-dashboard .ajcore-dashboard-context{display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-top:18px;color:#64748b}.ajcore-dashboard .ajcore-dashboard-context strong{margin-right:auto}.ajcore-dashboard .ajcore-dashboard-context a{display:inline-flex;align-items:center;border:1px solid #dbe7f3;background:#fff;border-radius:999px;padding:7px 11px;text-decoration:none;font-weight:800}.ajcore-dashboard .ajcore-dashboard-context a:hover{background:#f8fafc}
			</style>
			<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'Dashboard', 'ajforms' ); ?></h2><p><?php esc_html_e( 'Quick operating snapshot for billing, customers, fulfillment, tasks, and sync health.', 'ajforms' ); ?></p></div></div>

			<form method="get" class="ajforms-settings-inline-actions" style="align-items:center;gap:10px;">
				<input type="hidden" name="page" value="ajforms-client-portal">
				<input type="hidden" name="tab" value="dashboard">
				<input type="search" name="portal_q" value="<?php echo isset( $_GET['portal_q'] ) ? esc_attr( sanitize_text_field( wp_unslash( $_GET['portal_q'] ) ) ) : ''; ?>" placeholder="<?php esc_attr_e( 'Search customers, requests, transactions, files, tasks…', 'ajforms' ); ?>" style="min-width:380px;">
				<button class="button button-primary"><?php esc_html_e( 'Search Everything', 'ajforms' ); ?></button>
			</form>
			<?php $this->render_portal_global_search_results(); ?>

			<div class="ajcore-dashboard-grid">
				<?php $this->render_portal_dashboard_metric( __( 'Active Clients', 'ajforms' ), $active_customers, $this->get_portal_dashboard_url( 'portal-users', array( 'portal_user_status' => 'active' ) ) ); ?>
			<?php $this->render_portal_dashboard_metric( __( 'Active Services', 'ajforms' ), $active_services, $this->get_portal_dashboard_url( 'payments' ), sprintf( __( '%1$d auto-pay services, %2$d one-time paid.', 'ajforms' ), $auto_pay_services, $one_time_services ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Auto-Pay Subscriptions', 'ajforms' ), $auto_pay_services, $this->get_portal_dashboard_url( 'payments', array( 'pay_status' => 'paid' ) ), sprintf( __( '%d active Stripe subscription records.', 'ajforms' ), $active_subscription_objects ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Total Money Owed', 'ajforms' ), $this->format_portal_money( $billing_metrics['open_balance'], 'usd' ), $this->get_portal_dashboard_url( 'payments', array( 'pay_status' => 'unpaid' ) ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Overdue Amount', 'ajforms' ), $this->format_portal_money( $billing_metrics['overdue_amount'], 'usd' ), $this->get_portal_dashboard_url( 'payments', array( 'pay_status' => 'unpaid' ) ), __( 'Uses due date, falling back to ledger date.', 'ajforms' ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Overdue Tasks', 'ajforms' ), $task_metrics['overdue'], $this->get_portal_dashboard_url( 'tasks', array( 'task_view' => 'overdue' ) ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Paid Needs Fulfillment', 'ajforms' ), $paid_not_completed, $this->get_portal_dashboard_url( 'service-requests', array( 'request_status' => 'paid' ) ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Admin Review Required', 'ajforms' ), $admin_review_required, $this->get_portal_dashboard_url( 'service-requests', array( 'request_status' => 'admin_review_required' ) ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Failed Payments', 'ajforms' ), $billing_metrics['failed_count'], $this->get_portal_dashboard_url( 'payments', array( 'pay_status' => 'failed' ) ) ); ?>
				<?php $this->render_portal_dashboard_metric( __( 'Sync / Webhook Health', 'ajforms' ), $health_has_issue ? __( 'Review', 'ajforms' ) : __( 'OK', 'ajforms' ), $this->get_portal_dashboard_url( 'sync', $last_failed ? array( 'sync_log_id' => (int) $last_failed->id ) : array() ), $health_note ); ?>
			</div>

			<div class="ajcore-dashboard-context">
				<strong><?php echo esc_html( sprintf( __( 'Stripe mode: %s', 'ajforms' ), $stripe_mode['label'] ) ); ?></strong>
				<a href="<?php echo esc_url( $this->get_portal_dashboard_url( 'sync' ) ); ?>"><?php esc_html_e( 'View Sync History', 'ajforms' ); ?></a>
				<a href="<?php echo esc_url( $this->get_portal_dashboard_url( 'payments' ) ); ?>"><?php esc_html_e( 'Open Payments', 'ajforms' ); ?></a>
				<a href="<?php echo esc_url( $this->get_portal_dashboard_url( 'service-requests' ) ); ?>"><?php esc_html_e( 'Review Service Requests', 'ajforms' ); ?></a>
			</div>
		</div>
		<?php
	}

	public function display_client_portal_page() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		$this->ensure_portal_schema();

		$tab      = isset( $_GET['tab'] ) ? sanitize_key( wp_unslash( $_GET['tab'] ) ) : 'dashboard';
		// Menu/Calendar/API/Settings were merged into a single "CP Settings" tab with its own
		// sub-navigation (cp_section) — keep old bookmarked links working by redirecting them in,
		// before the tab whitelist below (which no longer contains these old values) resets them.
		if ( in_array( $tab, array( 'menu', 'calendar', 'api', 'settings' ), true ) ) {
			$old_tab = $tab;
			$tab     = 'cp-settings';
			if ( ! isset( $_GET['cp_section'] ) ) {
				$_GET['cp_section'] = ( 'settings' === $old_tab ) ? 'shared-db' : $old_tab;
			}
		}
		$moved_cp_tabs = array(
			'products-services' => 'product-catalog',
			'sync'              => 'sync',
			'event-log'         => 'event-log',
		);
		if ( isset( $moved_cp_tabs[ $tab ] ) ) {
			if ( ! isset( $_GET['cp_section'] ) ) {
				$_GET['cp_section'] = $moved_cp_tabs[ $tab ];
			}
			$tab = 'cp-settings';
		}
		$tab      = in_array( $tab, array( 'dashboard', 'file-library', 'sync', 'event-log', 'emails', 'partners', 'portal-users', 'sold-items', 'products-services', 'payments', 'billing', 'service-requests', 'tasks', 'customer', 'cp-settings', 'reservations' ), true ) ? $tab : 'dashboard';
		// The old Billing and Transactions (sold-items) tabs were merged into Payments; keep old links working.
		if ( 'billing' === $tab || 'sold-items' === $tab ) {
			$tab = 'payments';
		}
		$base_url = add_query_arg( array( 'page' => 'ajforms-client-portal' ), admin_url( 'admin.php' ) );
		$is_cp_settings_page = 'cp-settings' === $tab;
		$nav_tab = 'customer' === $tab ? 'portal-users' : $tab;
		// One-click full sync, available from every tab (not just the dedicated Sync tab) — redirects
		// back to whichever tab it was clicked from, same nonce/action the Sync tab's own button uses.
		$full_sync_url = wp_nonce_url( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => $nav_tab, 'portal_action' => 'sync_all' ), admin_url( 'admin.php' ) ), 'ajcore_portal_sync_all' );
		$stripe_mode = $this->get_stripe_mode_badge_data();
		$stripe_settings_url = add_query_arg( array( 'page' => 'ajforms-settings', 'section' => 'payments' ), admin_url( 'admin.php' ) );
		$tabs = array(
			'dashboard'          => __( 'Dashboard', 'ajforms' ),
			'leads'              => __( 'Leads', 'ajforms' ),
			'portal-users'       => __( 'Customers', 'ajforms' ),
			'partners'           => __( 'Partners', 'ajforms' ),
			'service-requests'   => __( 'Service Requests', 'ajforms' ),
			'payments'           => __( 'Payments', 'ajforms' ),
			'reservations'       => __( 'Reservations', 'ajforms' ),
			'tasks'              => __( 'Compliance', 'ajforms' ),
			'file-library'       => __( 'Files', 'ajforms' ),
			'emails'             => __( 'Email Log', 'ajforms' ),
		);
		// "Leads" lives on its own admin page — the nav links out to it instead of a portal tab.
		$external_tab_urls = array(
			'leads' => add_query_arg( array( 'page' => 'ajforms-leads' ), admin_url( 'admin.php' ) ),
		);
		?>
		<div class="wrap ajforms-client-portal-admin ajcore-modern-admin">
			<style>
				.ajcore-modern-admin{--ajc-ink:#0f172a;--ajc-muted:#64748b;--ajc-line:#dbe7f3;--ajc-soft:#f8fafc;--ajc-blue:#3157ff;--ajc-green:#16a34a;--ajc-amber:#d97706;--ajc-red:#dc2626;--ajc-card:#ffffff;--ajc-shadow:0 14px 34px rgba(15,23,42,.06);} 
				.ajcore-modern-admin .ajforms-settings-card,.ajcore-modern-admin .ajcore-admin-panel{background:var(--ajc-card);border:1px solid var(--ajc-line);border-radius:22px;padding:20px 22px;margin:0 0 16px;box-shadow:var(--ajc-shadow)}
				.ajcore-modern-admin .ajforms-settings-card h2,.ajcore-modern-admin .ajcore-admin-panel h2,.ajcore-modern-admin .ajforms-settings-card h3,.ajcore-modern-admin .ajcore-admin-panel h3{margin-top:0;color:var(--ajc-ink)}
				.ajcore-modern-admin .ajforms-settings-card>p,.ajcore-modern-admin .ajcore-admin-panel>p{color:var(--ajc-muted);font-size:14px;line-height:1.55;max-width:920px}
				.ajcore-modern-admin .ajcore-section-head{display:flex;align-items:flex-start;justify-content:space-between;gap:16px;margin-bottom:14px}.ajcore-modern-admin .ajcore-section-head h2{margin:0 0 5px;font-size:22px}.ajcore-modern-admin .ajcore-section-head p{margin:0;color:var(--ajc-muted);max-width:850px;line-height:1.55}
				.ajcore-modern-admin .ajforms-settings-inline-actions{display:flex;gap:10px;align-items:stretch;flex-wrap:wrap;margin:14px 0}.ajcore-modern-admin .ajforms-settings-pill{display:inline-flex;align-items:center;gap:8px;padding:10px 13px;border-radius:16px;border:1px solid #e2e8f0;background:linear-gradient(180deg,#fff,#f8fafc);color:#334155;font-weight:800;box-shadow:0 8px 18px rgba(15,23,42,.035)}
				.ajcore-modern-admin .ajcore-kpi-grid,.ajcore-modern-admin .ajcore-dashboard-grid,.ajcore-modern-admin .ajcore-task-metrics{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(190px,1fr))!important;gap:12px!important;margin:14px 0!important}.ajcore-modern-admin .ajcore-kpi-card,.ajcore-modern-admin .ajcore-dashboard-metric,.ajcore-modern-admin .ajcore-task-metric{display:flex!important;min-height:82px!important;flex-direction:column!important;justify-content:center!important;gap:5px!important;padding:16px 18px!important;border:1px solid #e2e8f0!important;border-radius:20px!important;background:linear-gradient(135deg,#fff 0%,#f8fbff 100%)!important;box-shadow:0 12px 28px rgba(15,23,42,.045)!important;text-decoration:none!important;color:var(--ajc-ink)!important}.ajcore-modern-admin .ajcore-dashboard-metric:hover{transform:translateY(-1px);border-color:#bfdbfe!important;box-shadow:0 18px 36px rgba(49,87,255,.10)!important}.ajcore-modern-admin .ajcore-kpi-card span,.ajcore-modern-admin .ajcore-dashboard-label,.ajcore-modern-admin .ajcore-task-metric span{color:var(--ajc-muted)!important;font-size:12px!important;font-weight:900!important;text-transform:uppercase;letter-spacing:.045em}.ajcore-modern-admin .ajcore-kpi-card strong,.ajcore-modern-admin .ajcore-dashboard-metric strong,.ajcore-modern-admin .ajcore-task-metric strong{color:var(--ajc-ink)!important;font-size:26px!important;line-height:1.1!important}.ajcore-modern-admin .ajcore-dashboard-metric small{color:var(--ajc-muted)!important;line-height:1.35!important}
				.ajcore-modern-admin .widefat{border:1px solid #e2e8f0!important;border-radius:18px!important;overflow:hidden!important;background:#fff!important;box-shadow:none!important}.ajcore-modern-admin .widefat thead th{background:#f8fafc!important;color:#334155!important;font-weight:900!important;border-bottom:1px solid #e2e8f0!important}.ajcore-modern-admin .widefat td,.ajcore-modern-admin .widefat th{padding:13px 14px!important;vertical-align:middle}.ajcore-modern-admin .widefat tbody tr:hover td{background:#fbfdff!important}.ajcore-modern-admin .widefat code{border-radius:8px;background:#f1f5f9;padding:3px 6px;color:#334155}
