idden}
				.ajcore-app-header{display:flex;align-items:center;justify-content:space-between;gap:16px;margin:14px 0 14px;padding:18px 20px;border:1px solid var(--ajc-line);border-radius:24px;background:radial-gradient(circle at 0% 0%,rgba(49,87,255,.16),transparent 28rem),linear-gradient(135deg,#fff 0%,#f8fbff 100%);box-shadow:0 18px 42px rgba(15,23,42,.06)}
				.ajcore-brand{display:flex;align-items:center;gap:14px}.ajcore-brand-mark{width:48px;height:48px;border-radius:18px;background:linear-gradient(135deg,#3157ff,#7c3aed);display:grid;place-items:center;color:#fff;font-size:24px;box-shadow:0 14px 30px rgba(49,87,255,.28)}.ajcore-brand h1{margin:0;font-size:25px;line-height:1.15;color:var(--ajc-ink)}.ajcore-brand span{display:block;margin-top:3px;color:var(--ajc-muted);font-weight:700}
				.ajcore-stripe-mini{display:flex;align-items:center;gap:8px;flex-wrap:wrap;justify-content:flex-end}.ajcore-stripe-mini .stripe-pill{display:inline-flex;align-items:center;gap:7px;border-radius:999px;padding:8px 12px;font-weight:800;border:1px solid #fde68a;background:#fffbeb;color:#92400e}.ajcore-stripe-mini .stripe-pill.is-test{border-color:#bfdbfe;background:#eff6ff;color:#1d4ed8}.ajcore-stripe-mini .stripe-pill.is-error{border-color:#fecaca;background:#fef2f2;color:#991b1b}
				.ajcore-tabs-shell{display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin:0 0 14px;padding:10px;border:1px solid var(--ajc-line);border-radius:20px;background:#fff;box-shadow:0 10px 26px rgba(15,23,42,.04)}.ajcore-tab-link{display:inline-flex;align-items:center;padding:9px 12px;border-radius:14px;text-decoration:none;font-weight:800;color:#334155}.ajcore-tab-link:hover{background:#f1f5f9;color:#0f172a}.ajcore-tab-link.is-active{background:#0f172a;color:#fff}.ajcore-tab-select{display:none;width:100%;max-width:360px}.ajcore-tab-spacer{flex:1}
				@media(max-width:1100px){.ajcore-app-header{align-items:flex-start;flex-direction:column}.ajcore-tabs-shell .ajcore-tab-link{display:none}.ajcore-tab-select{display:block}.ajcore-tab-spacer{display:none}}@media(max-width:700px){.ajcore-customer-modal{padding:10px}.ajcore-customer-modal-dialog{width:calc(100vw - 20px);max-height:calc(100vh - 20px)}.ajcore-customer-modal-head,.ajcore-customer-modal-body,.ajcore-customer-modal-foot{padding:18px}.ajcore-customer-modal-head h2{font-size:22px}.ajcore-customer-modal-grid,.ajcore-customer-modal-location{grid-template-columns:1fr}.ajcore-customer-modal-location{gap:20px}.ajcore-customer-modal-foot .button{flex:1}}
			</style>
			<div class="ajcore-app-header">
				<div class="ajcore-brand">
					<div class="ajcore-brand-mark" aria-hidden="true">✦</div>
					<div><h1><?php echo esc_html( $is_cp_settings_page ? __( 'AJ Core - CP Settings', 'ajforms' ) : __( 'AJ Core - Client Portal', 'ajforms' ) ); ?></h1><span><?php echo esc_html( $is_cp_settings_page ? __( 'Client Portal configuration', 'ajforms' ) : ( isset( $tabs[ $tab ] ) ? $tabs[ $tab ] : __( 'Dashboard', 'ajforms' ) ) ); ?></span></div>
				</div>
				<div class="ajcore-stripe-mini">
					<span class="stripe-pill <?php echo ! empty( $stripe_mode['has_issues'] ) ? 'is-error' : ( empty( $stripe_mode['is_live'] ) ? 'is-test' : '' ); ?>"><?php echo esc_html( sprintf( __( 'Stripe %s Mode', 'ajforms' ), $stripe_mode['label'] ) ); ?></span>
					<a href="<?php echo esc_url( $stripe_settings_url ); ?>"><?php esc_html_e( 'Stripe settings', 'ajforms' ); ?></a>
				</div>
			</div>
			<?php if ( ! $is_cp_settings_page ) : ?>
				<nav class="ajcore-tabs-shell" aria-label="<?php esc_attr_e( 'AJ Core Client Portal sections', 'ajforms' ); ?>">
					<select class="ajcore-tab-select" onchange="if(this.value){window.location.href=this.value;}">
						<?php foreach ( $tabs as $tab_key => $tab_label ) : ?>
							<?php $tab_url = isset( $external_tab_urls[ $tab_key ] ) ? $external_tab_urls[ $tab_key ] : add_query_arg( 'tab', $tab_key, $base_url ); ?>
							<option value="<?php echo esc_url( $tab_url ); ?>" <?php selected( $nav_tab, $tab_key ); ?>><?php echo esc_html( $tab_label ); ?></option>
						<?php endforeach; ?>
					</select>
					<?php foreach ( $tabs as $tab_key => $tab_label ) : ?>
						<?php $tab_url = isset( $external_tab_urls[ $tab_key ] ) ? $external_tab_urls[ $tab_key ] : add_query_arg( 'tab', $tab_key, $base_url ); ?>
						<a class="ajcore-tab-link <?php echo $nav_tab === $tab_key ? 'is-active' : ''; ?>" href="<?php echo esc_url( $tab_url ); ?>"><?php echo esc_html( $tab_label ); ?></a>
					<?php endforeach; ?>
					<div class="ajcore-tab-spacer"></div>
					<a class="button button-primary" href="<?php echo esc_url( $full_sync_url ); ?>" onclick="return confirm('<?php echo esc_js( __( 'Run a full Stripe sync now (products, customers, subscriptions, transactions)?', 'ajforms' ) ); ?>');"><?php esc_html_e( 'Full Sync Now', 'ajforms' ); ?></a>
				</nav>
			<?php endif; ?>
			<?php if ( 'customer' !== $tab && 'sync' !== $tab ) : ?>
				<?php if ( isset( $_GET['portal-sync-queued'] ) ) : ?>
					<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Sync started — it runs in the background and finishes in a moment. Check the Sync tab for progress and results.', 'ajforms' ); ?></p></div>
				<?php endif; ?>
				<?php if ( isset( $_GET['portal-synced'] ) ) : ?>
					<div class="notice notice-success is-dismissible"><p><?php echo esc_html( sprintf( __( 'Synced %d Stripe records.', 'ajforms' ), absint( wp_unslash( $_GET['portal-synced'] ) ) ) ); ?></p></div>
				<?php endif; ?>
				<?php if ( isset( $_GET['portal-error'] ) ) : ?>
					<div class="notice notice-error is-dismissible"><p><?php echo esc_html( sanitize_text_field( wp_unslash( $_GET['portal-error'] ) ) ); ?></p></div>
				<?php endif; ?>
			<?php endif; ?>
			<?php
			if ( 'customer' === $tab ) {
				$this->display_portal_customer_detail_page();
			} elseif ( 'dashboard' === $tab ) {
				$this->display_portal_dashboard_tab();
			} elseif ( 'sync' === $tab ) {
				$this->display_portal_sync_tab();
			} elseif ( 'event-log' === $tab ) {
				$this->display_portal_event_log_tab();
			} elseif ( 'emails' === $tab ) {
				$this->display_portal_emails_tab();
			} elseif ( 'partners' === $tab ) {
				$this->display_portal_partners_tab();
			} elseif ( 'portal-users' === $tab ) {
				$this->display_portal_users_tab();
			} elseif ( 'products-services' === $tab ) {
				$this->display_portal_products_services_tab();
			} elseif ( 'payments' === $tab ) {
				$this->display_portal_payments_tab();
			} elseif ( 'service-requests' === $tab ) {
				$this->display_portal_service_requests_tab();
			} elseif ( 'tasks' === $tab ) {
				$this->display_portal_tasks_tab();
			} elseif ( 'reservations' === $tab ) {
				$this->display_portal_reservations_admin_tab();
			} elseif ( 'cp-settings' === $tab ) {
				$this->display_client_portal_cp_settings_tab();
			} else {
				$this->display_file_library_page( true );
			}
			?>
		</div>
		<?php
	}

	/**
	 * "CP Settings" — Client Portal configuration, consolidated under one tab with
	 * its own sub-navigation (cp_section): the portal nav/menu builder, Calendar/
	 * Reservations, the REST API access controls, Remote Storage, Role Manager,
	 * WP Email Templates, and Shared DB / Multi-site. These previously lived as
	 * separate top-level Client Portal tabs (Menu/Calendar/API/Settings) or, for
	 * Role Manager and Email Templates, on the separate main AJ Core Settings page.
	 */
	public function display_client_portal_cp_settings_tab() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		$cp_section = isset( $_GET['cp_section'] ) ? sanitize_key( wp_unslash( $_GET['cp_section'] ) ) : 'menu';
		$sub_tabs   = array(
			'menu'            => __( 'Menu', 'ajforms' ),
			'product-catalog' => __( 'Product Catalog', 'ajforms' ),
			'sync'            => __( 'Sync', 'ajforms' ),
			'event-log'       => __( 'Event Log', 'ajforms' ),
			'db-schema'       => __( 'AJCore DB Schema', 'ajforms' ),
			'calendar'        => __( 'Calendar / Reservations', 'ajforms' ),
			'api'             => __( 'API', 'ajforms' ),
			'files'           => __( 'Files', 'ajforms' ),
			'storage'         => __( 'Storage', 'ajforms' ),
			'roles'           => __( 'Role Manager', 'ajforms' ),
			'email-templates' => __( 'Email Templates', 'ajforms' ),
			'shared-db'       => __( 'Shared DB / Multi-Site', 'ajforms' ),
		);
		if ( ! isset( $sub_tabs[ $cp_section ] ) ) {
			$cp_section = 'menu';
		}

		$base_url = add_query_arg( array( 'page' => 'ajforms-cp-settings' ), admin_url( 'admin.php' ) );
		?>
		<div class="ajforms-settings-card" style="padding:10px;">
			<nav class="ajcore-tabs-shell" aria-label="<?php esc_attr_e( 'CP Settings sections', 'ajforms' ); ?>" style="margin:0;">
				<?php foreach ( $sub_tabs as $sub_key => $sub_label ) : ?>
					<a class="ajcore-tab-link <?php echo $cp_section === $sub_key ? 'is-active' : ''; ?>" href="<?php echo esc_url( add_query_arg( 'cp_section', $sub_key, $base_url ) ); ?>"><?php echo esc_html( $sub_label ); ?></a>
				<?php endforeach; ?>
			</nav>
		</div>

		<?php if ( 'menu' === $cp_section ) : ?>
			<?php $this->display_client_portal_settings_tab( 'menu', true ); ?>
		<?php elseif ( 'product-catalog' === $cp_section ) : ?>
			<?php $this->display_portal_products_services_tab(); ?>
		<?php elseif ( 'sync' === $cp_section ) : ?>
			<?php $this->display_portal_sync_tab(); ?>
		<?php elseif ( 'event-log' === $cp_section ) : ?>
			<?php $this->display_portal_event_log_tab(); ?>
		<?php elseif ( 'db-schema' === $cp_section ) : ?>
			<?php $this->display_ajcore_db_schema_tab(); ?>
		<?php elseif ( 'calendar' === $cp_section ) : ?>
			<?php $this->display_portal_calendar_settings_tab(); ?>
		<?php elseif ( 'api' === $cp_section ) : ?>
			<?php $this->display_portal_api_tab(); ?>
		<?php elseif ( 'files' === $cp_section ) : ?>
			<?php $this->display_portal_file_settings_tab(); ?>
		<?php elseif ( 'storage' === $cp_section ) : ?>
			<?php
			if ( class_exists( 'AJCore_Storage_Service' ) ) {
				AJCore_Storage_Service::instance()->render_settings_page( true );
			}
			?>
		<?php elseif ( 'roles' === $cp_section ) : ?>
			<div class="ajforms-settings-head">
				<h2><?php esc_html_e( 'Role Manager', 'ajforms' ); ?></h2>
				<p><?php esc_html_e( 'View, add, edit, and delete WordPress roles used by AJ Core and the rest of the site.', 'ajforms' ); ?></p>
			</div>
			<?php $this->display_role_manager_page( true ); ?>
		<?php elseif ( 'email-templates' === $cp_section ) : ?>
			<?php $this->display_email_templates_settings_section(); ?>
		<?php elseif ( 'shared-db' === $cp_section ) : ?>
			<?php $this->display_portal_shared_db_settings_tab(); ?>
		<?php endif; ?>
		<?php
	}

	private function display_ajcore_db_schema_tab() {
		global $wpdb;

		$pdb       = $this->get_pdb();
		$sources   = array( 'Local WordPress DB' => $wpdb );
		if ( $pdb !== $wpdb ) {
			$sources['Shared Portal DB'] = $pdb;
		}
		$count_snapshot = get_option( 'ajcore_db_schema_row_counts', array() );
		$saved_counts   = isset( $count_snapshot['counts'] ) && is_array( $count_snapshot['counts'] ) ? $count_snapshot['counts'] : array();
		$schema_counts_updated = false;
		$schema_export_error   = '';
		$tables_by_key = array();
		$stripe_direct = array(
			'aj_portal_stripe_customers',
			'aj_portal_stripe_products',
			'aj_portal_stripe_subscriptions',
			'aj_portal_stripe_transactions',
			'aj_portal_stripe_events',
		);
		$stripe_derived = array(
			'aj_portal_product_catalog',
			'aj_portal_service_snapshots',
			'aj_portal_service_states',
			'aj_portal_ledger',
			'aj_portal_sync_logs',
			'aj_portal_sync_log_items',
		);
		$purposes = array(
			'aj_forms' => 'Legacy form definitions', 'aj_forms_forms' => 'AJCore form definitions and form-builder configuration',
			'aj_leads' => 'Legacy CRM lead records', 'aj_lead_notes' => 'Notes attached to legacy CRM leads',
			'aj_forms_leads' => 'Form submissions promoted into AJCore CRM lead records', 'aj_forms_lead_notes' => 'Notes and follow-up history attached to AJCore leads',
			'aj_portal_stripe_customers' => 'Stripe customer cache and portal status', 'aj_portal_customer_states' => 'Per-site customer portal state',
			'aj_portal_stripe_products' => 'Stripe product and price cache', 'aj_portal_product_catalog' => 'Portal catalog overrides',
			'aj_portal_stripe_subscriptions' => 'Stripe subscription cache', 'aj_portal_stripe_transactions' => 'Stripe transaction cache',
			'aj_portal_stripe_events' => 'Processed Stripe webhook events', 'aj_portal_ledger' => 'Derived billing ledger',
			'aj_portal_service_snapshots' => 'Purchased-service snapshots', 'aj_portal_service_states' => 'Service lifecycle state',
			'aj_portal_files' => 'Client file records', 'aj_portal_file_users' => 'File-to-user assignments', 'aj_portal_file_tags' => 'File tags',
			'aj_storage_objects' => 'Attachment-to-object-storage mappings', 'aj_auth_user_mappings' => 'WordPress user-to-customer mappings',
			'aj_portal_tasks' => 'Compliance task definitions', 'aj_portal_task_statuses' => 'Per-customer task status', 'aj_portal_task_comments' => 'Task comments',
			'aj_portal_compliance_entities' => 'Compliance entities', 'aj_portal_compliance_filings' => 'Compliance filing history',
			'aj_portal_service_requests' => 'Customer service requests', 'aj_portal_service_request_history' => 'Service request audit history',
			'aj_portal_sync_logs' => 'Stripe sync runs', 'aj_portal_sync_log_items' => 'Stripe sync run details',
			'aj_portal_event_log' => 'AJCore audit events', 'aj_portal_email_log' => 'Outgoing email log',
			'aj_portal_reservation_resources' => 'Reservable resources', 'aj_portal_reservations' => 'Reservations',
			'aj_portal_mail_items' => 'Received mail items', 'aj_portal_partners' => 'Partner organizations',
			'aj_portal_carts' => 'Saved client-portal checkout carts', 'aj_portal_entity_mappings' => 'Links AJCore entities to external source records',
			'aj_portal_user_mappings' => 'Legacy portal-user-to-customer mappings', 'aj_shared_sites' => 'Sites connected to the shared AJCore database',
			'aj_shared_settings' => 'AJCore settings synchronized across connected sites',
		);
		$relationships = array(
			array( 'aj_portal_stripe_customers', 'aj_portal_stripe_subscriptions', 'stripe_customer_id' ),
			array( 'aj_portal_stripe_customers', 'aj_portal_stripe_transactions', 'stripe_customer_id' ),
			array( 'aj_portal_stripe_customers', 'aj_auth_user_mappings', 'stripe_customer_id' ),
			array( 'aj_portal_stripe_customers', 'aj_portal_customer_states', 'stripe_customer_id' ),
			array( 'aj_portal_stripe_products', 'aj_portal_product_catalog', 'stripe_product_id' ),
			array( 'aj_portal_stripe_subscriptions', 'aj_portal_service_snapshots', 'subscription/customer' ),
			array( 'aj_portal_stripe_transactions', 'aj_portal_ledger', 'Stripe object/customer IDs' ),
			array( 'aj_portal_ledger', 'aj_portal_service_requests', 'ledger_id/source_object_id' ),
			array( 'aj_portal_service_requests', 'aj_portal_service_request_history', 'service_request_id' ),
			array( 'aj_portal_tasks', 'aj_portal_task_statuses', 'task_id' ),
			array( 'aj_portal_tasks', 'aj_portal_task_comments', 'task_id' ),
			array( 'aj_portal_compliance_entities', 'aj_portal_compliance_filings', 'entity_id' ),
			array( 'aj_portal_files', 'aj_portal_file_users', 'file_id' ),
			array( 'aj_portal_files', 'aj_portal_file_tags', 'file_id' ),
			array( 'aj_portal_files', 'aj_storage_objects', 'attachment_id' ),
			array( 'aj_portal_sync_logs', 'aj_portal_sync_log_items', 'log_id' ),
			array( 'aj_leads', 'aj_lead_notes', 'lead_id' ),
			array( 'aj_forms_leads', 'aj_forms_lead_notes', 'lead_id' ),
			array( 'aj_portal_reservation_resources', 'aj_portal_reservations', 'resource_key' ),
		);

		foreach ( $sources as $location => $db ) {
			$like = $db->esc_like( $db->prefix . 'aj_' ) . '%';
			$found = $db->get_col( $db->prepare( 'SHOW TABLES LIKE %s', $like ) );
			foreach ( (array) $found as $full_name ) {
				$logical_name = 0 === strpos( $full_name, $db->prefix ) ? substr( $full_name, strlen( $db->prefix ) ) : $full_name;
				$database   = ! empty( $db->dbname ) ? (string) $db->dbname : DB_NAME;
				$table_key  = $database . '|' . $full_name;
				$tables_by_key[ $table_key ] = array(
					'full_name'    => (string) $full_name,
					'logical_name' => (string) $logical_name,
					'location'     => $location,
					'database'     => $database,
					'purpose'      => isset( $purposes[ $logical_name ] ) ? $purposes[ $logical_name ] : 'AJCore application data',
					'stripe'       => in_array( $logical_name, $stripe_direct, true ) ? 'direct' : ( in_array( $logical_name, $stripe_derived, true ) ? 'derived' : '' ),
					'row_count'    => array_key_exists( $table_key, $saved_counts ) ? absint( $saved_counts[ $table_key ] ) : null,
				);
			}
		}

		if ( isset( $_POST['ajcore_refresh_schema_counts'] ) ) {
			if ( ! current_user_can( 'manage_options' ) ) {
				wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
			}
			check_admin_referer( 'ajcore_refresh_schema_counts', 'ajcore_schema_counts_nonce' );
			$refreshed_counts = array();
			$export_tables     = array();
			foreach ( $tables_by_key as $table_key => $table ) {
				$db         = isset( $sources[ $table['location'] ] ) ? $sources[ $table['location'] ] : null;
				$safe_table = str_replace( '`', '``', $table['full_name'] );
				if ( $db ) {
					$count = $db->get_var( "SELECT COUNT(*) FROM `{$safe_table}`" );
					if ( null !== $count ) {
						$refreshed_counts[ $table_key ] = absint( $count );
						$tables_by_key[ $table_key ]['row_count'] = absint( $count );
					}
					$export_tables[] = array(
						'name'          => $table['full_name'],
						'logical_name'  => $table['logical_name'],
						'location'      => $table['location'],
						'database'      => $table['database'],
						'purpose'       => $table['purpose'],
						'data_source'   => $table['stripe'] ? 'stripe_' . $table['stripe'] : 'ajcore',
						'row_count'     => isset( $refreshed_counts[ $table_key ] ) ? $refreshed_counts[ $table_key ] : null,
						'columns'       => (array) $db->get_results( "DESCRIBE `{$safe_table}`", ARRAY_A ),
						'indexes'       => (array) $db->get_results( "SHOW INDEX FROM `{$safe_table}`", ARRAY_A ),
					);
				}
			}
			$updated_at = current_time( 'mysql' );
			update_option(
				'ajcore_db_schema_row_counts',
				array(
					'updated_at' => $updated_at,
					'counts'     => $refreshed_counts,
				),
				false
			);
			$count_snapshot = array( 'updated_at' => $updated_at, 'counts' => $refreshed_counts );
			$saved_counts   = $refreshed_counts;
			$schema_payload = array(
				'format'       => 'AJCore database schema snapshot',
				'version'      => 1,
				'generated_at' => $updated_at,
				'generated_by' => 'AJCore DB Schema > Update Row Counts',
				'notes'        => array(
					'No table row data or database credentials are included.',
					'Relationships are application-level links and may not be MySQL foreign keys.',
				),
				'relationships' => array_map(
					function ( $relationship ) {
						return array( 'from' => $relationship[0], 'to' => $relationship[1], 'link' => $relationship[2] );
					},
					$relationships
				),
				'tables'       => $export_tables,
			);
			$schema_json = wp_json_encode( $schema_payload, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES );
			$schema_file = AJCORE_PLUGIN_DIR . 'config/ajcore-db-schema.json';
			if ( false === $schema_json || false === @file_put_contents( $schema_file, $schema_json . PHP_EOL, LOCK_EX ) ) {
				$schema_export_error = sprintf( __( 'Counts were saved, but AJCore could not write the schema snapshot to %s.', 'ajforms' ), $schema_file );
			}
			$schema_counts_updated = true;
		}

		$relationship_map = array();
		foreach ( $relationships as $relationship ) {
			$relationship_map[ $relationship[0] ][] = array( 'table' => $relationship[1], 'field' => $relationship[2], 'direction' => 'to' );
			$relationship_map[ $relationship[1] ][] = array( 'table' => $relationship[0], 'field' => $relationship[2], 'direction' => 'from' );
		}
		$tables = array_values( $tables_by_key );
		foreach ( $tables as &$table ) {
			$table['relationships'] = isset( $relationship_map[ $table['logical_name'] ] ) ? $relationship_map[ $table['logical_name'] ] : array();
		}
		unset( $table );
		usort( $tables, function ( $a, $b ) { return strcmp( $a['logical_name'] . $a['location'], $b['logical_name'] . $b['location'] ); } );

		$query_rows    = array();
		$query_columns = array();
		$query_error   = '';
		$query_label   = '';
		$selected      = array();
		$query_sql     = '';
		$query_location = sanitize_title( (string) array_key_first( $sources ) );
		if ( isset( $_POST['ajcore_schema_inspect'] ) ) {
			if ( ! current_user_can( 'manage_options' ) ) {
				wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
			}
			check_admin_referer( 'ajcore_schema_inspect', 'ajcore_schema_inspect_nonce' );
			$action       = isset( $_POST['schema_inspect_action'] ) ? sanitize_key( wp_unslash( $_POST['schema_inspect_action'] ) ) : 'query';
			$selected     = isset( $_POST['schema_tables'] ) ? array_map( 'sanitize_text_field', (array) wp_unslash( $_POST['schema_tables'] ) ) : array();
			$query_sql    = isset( $_POST['schema_query'] ) ? trim( wp_unslash( $_POST['schema_query'] ) ) : '';
			$query_location = isset( $_POST['schema_query_location'] ) ? sanitize_title( wp_unslash( $_POST['schema_query_location'] ) ) : '';
			$target_db    = null;
			$sql          = '';

			if ( 'query' === $action ) {
				foreach ( $sources as $location => $db ) {
					if ( sanitize_title( $location ) === $query_location ) {
						$target_db = $db;
						break;
					}
				}
				$query_sql = rtrim( $query_sql, "; \t\n\r\0\x0B" );
				$is_read_only = preg_match( '/^\s*(SELECT|SHOW|DESCRIBE|DESC|EXPLAIN)\b/i', $query_sql )
					&& false === strpos( $query_sql, ';' )
					&& ! preg_match( '/\b(INSERT|UPDATE|DELETE|DROP|ALTER|TRUNCATE|CREATE|REPLACE|RENAME|GRANT|REVOKE|LOCK|UNLOCK|INTO\s+(OUTFILE|DUMPFILE)|LOAD_FILE|SLEEP|BENCHMARK)\b/i', $query_sql );
				if ( ! $target_db || ! $is_read_only ) {
					$query_error = __( 'Only a single read-only SELECT, SHOW, DESCRIBE, DESC, or EXPLAIN query is allowed.', 'ajforms' );
				} else {
					$sql = $query_sql;
					if ( preg_match( '/^\s*SELECT\b/i', $sql ) && ! preg_match( '/\bLIMIT\s+\d+/i', $sql ) ) {
						$sql .= ' LIMIT 100';
					}
					$query_label = __( 'Query Results', 'ajforms' );
				}
			} elseif ( 1 !== count( $selected ) || ! isset( $tables_by_key[ $selected[0] ] ) ) {
				$query_error = __( 'Select exactly one table for this action.', 'ajforms' );
			} else {
				$table     = $tables_by_key[ $selected[0] ];
				$target_db = isset( $sources[ $table['location'] ] ) ? $sources[ $table['location'] ] : null;
				$safe_table = str_replace( '`', '``', $table['full_name'] );
				if ( 'preview' === $action ) {
					$sql = "SELECT * FROM `{$safe_table}` LIMIT 100";
					$query_label = sprintf( __( 'Preview: %s', 'ajforms' ), $table['full_name'] );
				} elseif ( 'describe' === $action ) {
					$sql = "DESCRIBE `{$safe_table}`";
					$query_label = sprintf( __( 'Columns: %s', 'ajforms' ), $table['full_name'] );
				} elseif ( 'indexes' === $action ) {
					$sql = "SHOW INDEX FROM `{$safe_table}`";
					$query_label = sprintf( __( 'Indexes: %s', 'ajforms' ), $table['full_name'] );
				}
			}
			if ( $sql && $target_db ) {
				$query_rows = $target_db->get_results( $sql, ARRAY_A );
				if ( $target_db->last_error ) {
					$query_error = $target_db->last_error;
					$query_rows  = array();
				} elseif ( ! empty( $query_rows ) ) {
					$query_columns = array_keys( reset( $query_rows ) );
				}
			}
		}
		$schema_group_definitions = array(
			'forms'       => array( 'label' => 'Forms & Leads', 'description' => 'Captures forms, prospects, notes, and follow-up activity.' ),
			'customers'   => array( 'label' => 'Customers & Access', 'description' => 'Connects Stripe customers, portal state, WordPress users, and external entities.' ),
			'billing'     => array( 'label' => 'Stripe & Billing', 'description' => 'Caches Stripe records and derives billing, purchase, and service history.' ),
			'files'       => array( 'label' => 'Files & Storage', 'description' => 'Tracks documents, user assignments, tags, and object-storage locations.' ),
			'compliance'  => array( 'label' => 'Compliance & Tasks', 'description' => 'Tracks compliance entities, filings, tasks, statuses, and comments.' ),
			'services'    => array( 'label' => 'Service Operations', 'description' => 'Handles service requests, status history, mail, and reservations.' ),
			'logs'        => array( 'label' => 'Logs & Synchronization', 'description' => 'Records sync runs, webhooks, emails, and audit events.' ),
			'shared'      => array( 'label' => 'Shared Multi-Site', 'description' => 'Coordinates AJCore settings and connected WordPress sites.' ),
			'other'       => array( 'label' => 'Other AJCore Data', 'description' => 'AJCore tables not yet assigned to a documented functional group.' ),
		);
		$schema_group_members = array(
			'forms'      => array( 'aj_forms', 'aj_forms_forms', 'aj_forms_leads', 'aj_forms_lead_notes', 'aj_leads', 'aj_lead_notes' ),
			'customers'  => array( 'aj_portal_stripe_customers', 'aj_portal_customer_states', 'aj_auth_user_mappings', 'aj_portal_user_mappings', 'aj_portal_entity_mappings', 'aj_portal_partners' ),
			'billing'    => array( 'aj_portal_stripe_products', 'aj_portal_product_catalog', 'aj_portal_stripe_subscriptions', 'aj_portal_stripe_transactions', 'aj_portal_ledger', 'aj_portal_service_snapshots', 'aj_portal_service_states', 'aj_portal_carts' ),
			'files'      => array( 'aj_portal_files', 'aj_portal_file_users', 'aj_portal_file_tags', 'aj_storage_objects' ),
			'compliance' => array( 'aj_portal_tasks', 'aj_portal_task_statuses', 'aj_portal_task_comments', 'aj_portal_compliance_entities', 'aj_portal_compliance_filings' ),
			'services'   => array( 'aj_portal_service_requests', 'aj_portal_service_request_history', 'aj_portal_mail_items', 'aj_portal_reservation_resources', 'aj_portal_reservations' ),
			'logs'       => array( 'aj_portal_sync_logs', 'aj_portal_sync_log_items', 'aj_portal_stripe_events', 'aj_portal_event_log', 'aj_portal_email_log' ),
			'shared'     => array( 'aj_shared_sites', 'aj_shared_settings' ),
		);
		$table_group_lookup = array();
		foreach ( $schema_group_members as $group_key => $members ) {
			foreach ( $members as $member ) {
				$table_group_lookup[ $member ] = $group_key;
			}
		}
		$grouped_tables = array_fill_keys( array_keys( $schema_group_definitions ), array() );
		foreach ( $tables as $table ) {
			$group_key = isset( $table_group_lookup[ $table['logical_name'] ] ) ? $table_group_lookup[ $table['logical_name'] ] : 'other';
			$grouped_tables[ $group_key ][] = $table;
		}
		$data_flows = array(
			array( 'title' => 'Customer onboarding', 'description' => 'A Stripe or local customer becomes an AJCore portal account.', 'steps' => array( 'aj_portal_stripe_customers', 'aj_portal_customer_states', 'aj_auth_user_mappings', 'WordPress portal user' ) ),
			array( 'title' => 'Stripe billing', 'description' => 'Stripe activity is cached and converted into operational billing history.', 'steps' => array( 'Stripe', 'aj_portal_stripe_transactions', 'aj_portal_ledger', 'aj_portal_service_snapshots' ) ),
			array( 'title' => 'Products and subscriptions', 'description' => 'Stripe products and subscriptions become services visible in AJCore.', 'steps' => array( 'aj_portal_stripe_products', 'aj_portal_product_catalog', 'aj_portal_stripe_subscriptions', 'aj_portal_service_states' ) ),
			array( 'title' => 'Client documents', 'description' => 'Uploaded files are stored, assigned to users, and categorized.', 'steps' => array( 'aj_portal_files', 'aj_storage_objects', 'aj_portal_file_users', 'aj_portal_file_tags' ) ),
			array( 'title' => 'Compliance work', 'description' => 'Entities generate filings and customer-specific compliance tasks.', 'steps' => array( 'aj_portal_compliance_entities', 'aj_portal_compliance_filings', 'aj_portal_tasks', 'aj_portal_task_statuses' ) ),
			array( 'title' => 'Service fulfillment', 'description' => 'A purchase or request becomes tracked operational work.', 'steps' => array( 'aj_portal_ledger', 'aj_portal_service_requests', 'aj_portal_service_request_history', 'Customer update' ) ),
		);
		?>
		<style>
			.ajcore-schema-view-tabs{display:flex;gap:8px;flex-wrap:wrap;margin:16px 0}.ajcore-schema-view-tabs .button.is-active{background:#0f172a!important;border-color:#0f172a!important;color:#fff!important}.ajcore-schema-view[hidden]{display:none}.ajcore-schema-map{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:14px}.ajcore-schema-group{padding:18px;border:1px solid #dbe7f3;border-radius:18px;background:linear-gradient(145deg,#fff,#f8fafc)}.ajcore-schema-group h3{margin:0 0 5px!important}.ajcore-schema-group>p{min-height:42px;margin:0 0 12px;color:#64748b}.ajcore-schema-chips{display:flex;gap:7px;flex-wrap:wrap}.ajcore-schema-chip{padding:6px 9px;border:1px solid #cbd5e1;border-radius:10px;background:#fff;color:#334155;font-family:monospace;font-size:12px;cursor:pointer}.ajcore-schema-chip:hover{border-color:#3157ff;color:#1d4ed8}.ajcore-schema-flow-list{display:grid;gap:14px}.ajcore-schema-flow-card{padding:18px;border:1px solid #dbe7f3;border-radius:18px;background:#fff}.ajcore-schema-flow-card h3{margin:0 0 4px!important}.ajcore-schema-flow-card>p{margin:0 0 14px;color:#64748b}.ajcore-schema-flow-steps{display:flex;align-items:stretch;gap:8px;overflow-x:auto;padding-bottom:4px}.ajcore-schema-flow-step{display:flex;align-items:center;min-width:180px;padding:12px;border:1px solid #c7d2fe;border-radius:13px;background:#eef2ff;color:#312e81;font-family:monospace;font-weight:800;overflow-wrap:anywhere}.ajcore-schema-flow-arrow{display:grid;place-items:center;color:#3157ff;font-size:22px;font-weight:900}.ajcore-schema-row-focus td{animation:ajcoreSchemaFocus 2.4s ease}@keyframes ajcoreSchemaFocus{0%,100%{background:inherit}20%,75%{background:#fef3c7}}.ajcore-schema-badge{display:inline-flex;align-items:center;border-radius:999px;padding:4px 9px;font-size:11px;font-weight:800}.ajcore-schema-direct{background:#e0e7ff;color:#3730a3}.ajcore-schema-derived{background:#fef3c7;color:#92400e}.ajcore-schema-local{background:#f1f5f9;color:#475569}.ajcore-schema-query{display:grid;grid-template-columns:170px minmax(280px,1fr) auto;gap:10px;margin:16px 0;padding:14px;border:1px solid #c7d2fe;border-radius:16px;background:#eef2ff}.ajcore-schema-query select,.ajcore-schema-query input{width:100%;min-height:42px}.ajcore-schema-filters{display:grid;grid-template-columns:minmax(220px,2fr) repeat(3,minmax(150px,1fr));gap:10px;margin:16px 0;padding:14px;border:1px solid #dbe7f3;border-radius:16px;background:#f8fafc}.ajcore-schema-filters input,.ajcore-schema-filters select{width:100%;min-height:40px}.ajcore-schema-actions{display:none;align-items:center;gap:8px;flex-wrap:wrap;margin:0 0 12px;padding:10px 12px;border:1px solid #bfdbfe;border-radius:14px;background:#eff6ff}.ajcore-schema-actions.is-visible{display:flex}.ajcore-schema-actions strong{margin-right:4px}.ajcore-schema-table code{white-space:nowrap}.ajcore-schema-table td{vertical-align:top!important}.ajcore-schema-related{display:flex;flex-direction:column;gap:5px;min-width:210px}.ajcore-schema-related code{white-space:normal}.ajcore-schema-empty{display:none;margin:14px 0 0;color:#64748b;font-weight:700}.ajcore-schema-result-modal[hidden]{display:none}.ajcore-schema-result-modal{position:fixed;inset:0;z-index:100110;display:grid;place-items:center;padding:24px;background:rgba(15,23,42,.5)}.ajcore-schema-result-dialog{display:flex;flex-direction:column;width:min(1200px,calc(100vw - 48px));max-height:calc(100vh - 48px);overflow:hidden;border:1px solid #cbd5e1;border-radius:18px;background:#fff;box-shadow:0 28px 80px rgba(15,23,42,.3)}.ajcore-schema-result-head,.ajcore-schema-result-foot{display:flex;align-items:center;justify-content:space-between;gap:14px;padding:18px 22px;border-bottom:1px solid #e2e8f0}.ajcore-schema-result-head h2{margin:0!important;font-size:22px}.ajcore-schema-result-close{display:grid;place-items:center;width:38px;height:38px;padding:0;border:0;background:transparent;color:#64748b;font-size:30px;cursor:pointer}.ajcore-schema-result-body{overflow:auto;padding:20px 22px}.ajcore-schema-results-scroll{max-height:calc(100vh - 210px);overflow:auto;border:1px solid #dbe7f3;border-radius:14px}.ajcore-schema-result-body table{margin:0!important;border:0!important;border-radius:0!important}.ajcore-schema-result-body td{max-width:420px;white-space:pre-wrap;overflow-wrap:anywhere}.ajcore-schema-result-foot{justify-content:flex-end;border-top:1px solid #e2e8f0;border-bottom:0}@media(max-width:1000px){.ajcore-schema-filters{grid-template-columns:1fr 1fr}}@media(max-width:782px){.ajcore-schema-query,.ajcore-schema-filters{grid-template-columns:1fr}.ajcore-schema-table{display:block;overflow-x:auto}.ajcore-schema-result-modal{padding:10px}.ajcore-schema-result-dialog{width:calc(100vw - 20px);max-height:calc(100vh - 20px)}.ajcore-schema-flow-steps{flex-direction:column}.ajcore-schema-flow-arrow{transform:rotate(90deg)}}
		</style>
		<div class="ajforms-settings-card">
			<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'AJCore Database Inventory', 'ajforms' ); ?></h2><p><?php esc_html_e( 'One numbered row per physical table, with a concise purpose, saved row count, data source, and known relationships.', 'ajforms' ); ?></p></div><form method="post" style="margin:0;"><?php wp_nonce_field( 'ajcore_refresh_schema_counts', 'ajcore_schema_counts_nonce' ); ?><button type="submit" class="button" name="ajcore_refresh_schema_counts" value="1"><?php esc_html_e( 'Update Row Counts', 'ajforms' ); ?></button></form></div>
			<?php if ( ! empty( $count_snapshot['updated_at'] ) ) : ?><p style="margin:-4px 0 12px;color:#64748b;"><?php echo esc_html( sprintf( __( 'Row-count snapshot last updated: %s', 'ajforms' ), $count_snapshot['updated_at'] ) ); ?></p><?php else : ?><div class="notice notice-info inline"><p><?php esc_html_e( 'Row counts have not been collected yet. Click Update Row Counts when you want to create the first snapshot.', 'ajforms' ); ?></p></div><?php endif; ?>
			<p style="margin:-4px 0 12px;color:#64748b;"><?php echo esc_html( sprintf( __( 'Shareable schema file: %s', 'ajforms' ), 'config/ajcore-db-schema.json' ) ); ?></p>
			<?php if ( $schema_counts_updated && ! $schema_export_error ) : ?><div class="notice notice-success inline"><p><?php esc_html_e( 'Row counts and the shareable JSON schema snapshot were updated.', 'ajforms' ); ?></p></div><?php endif; ?>
			<?php if ( $schema_export_error ) : ?><div class="notice notice-warning inline"><p><?php echo esc_html( $schema_export_error ); ?></p></div><?php endif; ?>
			<div class="ajcore-schema-view-tabs" role="tablist" aria-label="<?php esc_attr_e( 'Schema views', 'ajforms' ); ?>">
				<button type="button" class="button is-active" data-schema-view="inventory"><?php esc_html_e( 'Inventory', 'ajforms' ); ?></button>
				<button type="button" class="button" data-schema-view="map"><?php esc_html_e( 'System Map', 'ajforms' ); ?></button>
				<button type="button" class="button" data-schema-view="flows"><?php esc_html_e( 'Data Flows', 'ajforms' ); ?></button>
			</div>
