			<?php foreach ( $tables as $table_index => $table ) : ?>
				<tr data-table-key="<?php echo esc_attr( $table['database'] . '|' . $table['full_name'] ); ?>" data-logical-name="<?php echo esc_attr( $table['logical_name'] ); ?>" data-location="<?php echo esc_attr( sanitize_title( $table['location'] ) ); ?>" data-source="<?php echo esc_attr( $table['stripe'] ? $table['stripe'] : 'ajcore' ); ?>" data-rows="<?php echo null === $table['row_count'] ? 'unknown' : esc_attr( $table['row_count'] ); ?>"><td><input type="checkbox" class="ajcore-schema-table-check" name="schema_tables[]" value="<?php echo esc_attr( $table['database'] . '|' . $table['full_name'] ); ?>" form="ajcore-schema-actions-form" <?php checked( in_array( $table['database'] . '|' . $table['full_name'], $selected, true ) ); ?>></td><td><?php echo esc_html( number_format_i18n( $table_index + 1 ) ); ?></td><td><code><?php echo esc_html( $table['full_name'] ); ?></code></td><td><strong><?php echo esc_html( $table['location'] ); ?></strong><br><small><code><?php echo esc_html( $table['database'] ); ?></code></small></td><td><strong><?php echo null === $table['row_count'] ? esc_html__( 'Not counted', 'ajforms' ) : esc_html( number_format_i18n( $table['row_count'] ) ); ?></strong></td><td><?php echo esc_html( $table['purpose'] ); ?></td><td><?php if ( 'direct' === $table['stripe'] ) : ?><span class="ajcore-schema-badge ajcore-schema-direct">Stripe direct</span><?php elseif ( 'derived' === $table['stripe'] ) : ?><span class="ajcore-schema-badge ajcore-schema-derived">Stripe-derived</span><?php else : ?><span class="ajcore-schema-badge ajcore-schema-local">AJCore-managed</span><?php endif; ?></td><td><div class="ajcore-schema-related"><?php foreach ( $table['relationships'] as $related ) : ?><span><?php echo 'to' === $related['direction'] ? '→' : '←'; ?> <code><?php echo esc_html( $related['table'] ); ?></code><small> via <?php echo esc_html( $related['field'] ); ?></small></span><?php endforeach; ?><?php if ( empty( $table['relationships'] ) ) : ?><span>—</span><?php endif; ?></div></td></tr>
			<?php endforeach; ?>
			<?php if ( empty( $tables ) ) : ?><tr><td colspan="8"><?php esc_html_e( 'No AJCore tables were found.', 'ajforms' ); ?></td></tr><?php endif; ?>
