				<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'System Map', 'ajforms' ); ?></h2><p><?php esc_html_e( 'Tables are grouped by the business capability they support. A table may connect to another group without every table being directly linked.', 'ajforms' ); ?></p></div></div>
				<div class="ajcore-schema-map">
					<?php foreach ( $schema_group_definitions as $group_key => $group ) : ?><?php if ( empty( $grouped_tables[ $group_key ] ) ) { continue; } ?><article class="ajcore-schema-group"><h3><?php echo esc_html( $group['label'] ); ?></h3><p><?php echo esc_html( $group['description'] ); ?></p><div class="ajcore-schema-chips"><?php foreach ( $grouped_tables[ $group_key ] as $group_table ) : ?><button type="button" class="ajcore-schema-chip" data-schema-focus-table="<?php echo esc_attr( $group_table['database'] . '|' . $group_table['full_name'] ); ?>"><?php echo esc_html( $group_table['full_name'] ); ?></button><?php endforeach; ?></div></article><?php endforeach; ?>
				</div>
			</section>
			<section class="ajcore-schema-view" data-schema-panel="flows" hidden>
				<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'Data Flows', 'ajforms' ); ?></h2><p><?php esc_html_e( 'These simplified journeys explain how information moves through AJCore. They describe application behavior, not necessarily database foreign keys.', 'ajforms' ); ?></p></div></div>
				<div class="ajcore-schema-flow-list"><?php foreach ( $data_flows as $flow ) : ?><article class="ajcore-schema-flow-card"><h3><?php echo esc_html( $flow['title'] ); ?></h3><p><?php echo esc_html( $flow['description'] ); ?></p><div class="ajcore-schema-flow-steps"><?php foreach ( $flow['steps'] as $step_index => $step ) : ?><?php if ( $step_index ) : ?><span class="ajcore-schema-flow-arrow">→</span><?php endif; ?><?php $step_is_table = isset( $table_group_lookup[ $step ] ); ?><?php if ( $step_is_table ) : ?><button type="button" class="ajcore-schema-flow-step ajcore-schema-chip" data-schema-focus-logical="<?php echo esc_attr( $step ); ?>"><?php echo esc_html( $step ); ?></button><?php else : ?><span class="ajcore-schema-flow-step"><?php echo esc_html( $step ); ?></span><?php endif; ?><?php endforeach; ?></div></article><?php endforeach; ?></div>
			</section>
			<?php if ( $query_error || $query_label ) : ?><div class="ajcore-schema-result-modal" id="ajcore-schema-result-modal" role="dialog" aria-modal="true" aria-labelledby="ajcore-schema-result-title"><div class="ajcore-schema-result-dialog"><div class="ajcore-schema-result-head"><h2 id="ajcore-schema-result-title"><?php echo esc_html( $query_error ? __( 'Query Error', 'ajforms' ) : $query_label ); ?></h2><button type="button" class="ajcore-schema-result-close" data-schema-result-close aria-label="<?php esc_attr_e( 'Close', 'ajforms' ); ?>">&times;</button></div><div class="ajcore-schema-result-body"><?php if ( $query_error ) : ?><div class="notice notice-error inline"><p><?php echo esc_html( $query_error ); ?></p></div><?php elseif ( empty( $query_rows ) ) : ?><p><?php esc_html_e( 'The query completed successfully and returned no rows.', 'ajforms' ); ?></p><?php else : ?><div class="ajcore-schema-results-scroll"><table class="widefat striped"><thead><tr><?php foreach ( $query_columns as $column ) : ?><th><?php echo esc_html( $column ); ?></th><?php endforeach; ?></tr></thead><tbody><?php foreach ( $query_rows as $query_row ) : ?><tr><?php foreach ( $query_columns as $column ) : ?><td><?php $value = isset( $query_row[ $column ] ) ? $query_row[ $column ] : null; echo esc_html( is_scalar( $value ) || null === $value ? (string) $value : wp_json_encode( $value ) ); ?></td><?php endforeach; ?></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div><div class="ajcore-schema-result-foot"><button type="button" class="button button-primary" data-schema-result-close><?php esc_html_e( 'Close', 'ajforms' ); ?></button></div></div></div><?php endif; ?>
		</div>
		<script>
		(function(){
			var inventory=document.getElementById('ajcore-schema-inventory');
			if(!inventory){return;}
			var search=document.getElementById('ajcore-schema-search'),location=document.getElementById('ajcore-schema-location'),source=document.getElementById('ajcore-schema-source'),rows=document.getElementById('ajcore-schema-rows'),empty=document.getElementById('ajcore-schema-empty'),visibleCount=document.getElementById('ajcore-schema-visible-count');
			var entries=Array.prototype.slice.call(inventory.querySelectorAll('tbody tr[data-location]'));
			var checks=Array.prototype.slice.call(inventory.querySelectorAll('.ajcore-schema-table-check')),checkAll=document.getElementById('ajcore-schema-check-all'),actionBar=document.getElementById('ajcore-schema-actions-form'),selectedCount=document.getElementById('ajcore-schema-selected-count'),actionButtons=Array.prototype.slice.call(actionBar.querySelectorAll('button'));
			function updateActions(){var count=checks.filter(function(check){return check.checked;}).length;actionBar.classList.toggle('is-visible',count>0);selectedCount.textContent=count+' selected — choose one table';actionButtons.forEach(function(button){button.disabled=count!==1;});}
			function filter(){var query=(search.value||'').toLowerCase(),visible=0;entries.forEach(function(row){var rawCount=row.getAttribute('data-rows'),count=rawCount==='unknown'?null:parseInt(rawCount,10);var rowMatch=!rows.value||(rows.value==='unknown'?count===null:(rows.value==='empty'?count===0:count!==null&&count>0));var show=(!query||row.textContent.toLowerCase().indexOf(query)!==-1)&&(!location.value||row.getAttribute('data-location')===location.value)&&(!source.value||row.getAttribute('data-source')===source.value)&&rowMatch;row.hidden=!show;if(show){visible++;}});empty.style.display=visible?'none':'block';visibleCount.textContent='Showing '+visible+' of '+entries.length+' physical tables';checkAll.checked=false;}
			[search,location,source,rows].forEach(function(control){control.addEventListener('input',filter);control.addEventListener('change',filter);});
			checks.forEach(function(check){check.addEventListener('change',updateActions);});
			checkAll.addEventListener('change',function(){entries.forEach(function(row){if(!row.hidden){var check=row.querySelector('.ajcore-schema-table-check');if(check){check.checked=checkAll.checked;}}});updateActions();});
			updateActions();
			var viewButtons=Array.prototype.slice.call(document.querySelectorAll('[data-schema-view]')),viewPanels=Array.prototype.slice.call(document.querySelectorAll('[data-schema-panel]'));
			function showView(view){viewButtons.forEach(function(button){button.classList.toggle('is-active',button.getAttribute('data-schema-view')===view);});viewPanels.forEach(function(panel){panel.hidden=panel.getAttribute('data-schema-panel')!==view;});}
			viewButtons.forEach(function(button){button.addEventListener('click',function(){showView(button.getAttribute('data-schema-view'));});});
			function focusInventoryRow(row){if(!row){return;}search.value='';location.value='';source.value='';rows.value='';filter();showView('inventory');row.classList.remove('ajcore-schema-row-focus');void row.offsetWidth;row.classList.add('ajcore-schema-row-focus');row.scrollIntoView({behavior:'smooth',block:'center'});}
			Array.prototype.slice.call(document.querySelectorAll('[data-schema-focus-table]')).forEach(function(button){button.addEventListener('click',function(){var key=button.getAttribute('data-schema-focus-table');focusInventoryRow(entries.find(function(row){return row.getAttribute('data-table-key')===key;}));});});
			Array.prototype.slice.call(document.querySelectorAll('[data-schema-focus-logical]')).forEach(function(button){button.addEventListener('click',function(){var logical=button.getAttribute('data-schema-focus-logical');focusInventoryRow(entries.find(function(row){return row.getAttribute('data-logical-name')===logical;}));});});
			var resultModal=document.getElementById('ajcore-schema-result-modal');
			function closeResultModal(){if(!resultModal){return;}resultModal.hidden=true;document.body.classList.remove('ajcore-modal-open');}
			if(resultModal){
				document.body.classList.add('ajcore-modal-open');
				resultModal.addEventListener('click',function(event){if(event.target===resultModal||event.target.closest('[data-schema-result-close]')){closeResultModal();}});
				document.addEventListener('keydown',function(event){if(event.key==='Escape'&&!resultModal.hidden){closeResultModal();}});
				var closeButton=resultModal.querySelector('[data-schema-result-close]');if(closeButton){closeButton.focus();}
			}
		})();
		</script>
		<?php
	}

	private function handle_portal_file_settings_save() {
		if ( ! current_user_can( 'manage_options' ) || empty( $_POST['ajcore_file_settings_nonce'] ) ) {
			return;
		}
		check_admin_referer( 'ajcore_save_file_settings', 'ajcore_file_settings_nonce' );
		if ( function_exists( 'ajcore_is_multisite_portal_enabled' ) && ajcore_is_multisite_portal_enabled()
			&& function_exists( 'ajcore_is_stripe_sync_owner' ) && ! ajcore_is_stripe_sync_owner() ) {
			wp_die( esc_html__( 'File settings can only be changed on the master site.', 'ajforms' ) );
		}

		$category_lines = preg_split( '/\R/', (string) wp_unslash( $_POST['file_categories'] ?? '' ) );
		$tag_lines      = preg_split( '/\R/', (string) wp_unslash( $_POST['file_tags'] ?? '' ) );
		$categories     = array_values( array_unique( array_filter( array_map( 'sanitize_text_field', $category_lines ) ) ) );
		$tags           = array();
		foreach ( $tag_lines as $line ) {
			$label = ltrim( sanitize_text_field( $line ), '#' );
			$slug  = sanitize_title( $label );
			if ( '' !== $slug ) {
				$tags[ $slug ] = $label;
			}
		}
		$migration_tags = isset( $_POST['migration_tags'] ) && is_array( $_POST['migration_tags'] )
			? array_values( array_intersect( array_map( 'sanitize_key', wp_unslash( $_POST['migration_tags'] ) ), array_keys( $tags ) ) )
			: array();
		$requested_settings = compact( 'categories', 'tags', 'migration_tags' );
		$saved = ajcore_update_portal_file_settings( $requested_settings );
		if ( ! $saved ) {
			$current_settings = ajcore_get_portal_file_settings();
			$saved = $requested_settings === array_intersect_key( $current_settings, $requested_settings );
		}
		wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-cp-settings', 'cp_section' => 'files', $saved ? 'saved' : 'save-error' => 1 ), admin_url( 'admin.php' ) ) );
		exit;
	}

	private function display_portal_file_settings_tab() {
		$settings = ajcore_get_portal_file_settings();
		$locked = function_exists( 'ajcore_is_multisite_portal_enabled' ) && ajcore_is_multisite_portal_enabled()
			&& function_exists( 'ajcore_is_stripe_sync_owner' ) && ! ajcore_is_stripe_sync_owner();
		?>
		<div class="ajforms-settings-card">
			<h2><?php esc_html_e( 'File Settings', 'ajforms' ); ?></h2>
			<p><?php esc_html_e( 'Manage administrator-facing file categories and internal tags. Tags are never shown to portal clients.', 'ajforms' ); ?></p>
			<?php if ( isset( $_GET['saved'] ) ) : ?><div class="notice notice-success inline"><p><?php esc_html_e( 'File categories and internal tags saved.', 'ajforms' ); ?></p></div><?php endif; ?>
			<?php if ( isset( $_GET['save-error'] ) ) : ?><div class="notice notice-error inline"><p><?php esc_html_e( 'File settings could not be saved. Check the shared database connection and try again.', 'ajforms' ); ?></p></div><?php endif; ?>
			<?php if ( $locked ) : ?><div class="notice notice-info"><p><?php esc_html_e( 'These shared settings can only be changed on the master site.', 'ajforms' ); ?></p></div><?php endif; ?>
			<form method="post">
				<?php wp_nonce_field( 'ajcore_save_file_settings', 'ajcore_file_settings_nonce' ); ?>
				<fieldset <?php disabled( $locked ); ?> style="border:0;margin:0;padding:0;<?php echo $locked ? 'opacity:.6;' : ''; ?>">
					<p><label for="file_categories"><strong><?php esc_html_e( 'Categories', 'ajforms' ); ?></strong></label><br>
					<textarea id="file_categories" name="file_categories" rows="7" class="large-text"><?php echo esc_textarea( implode( "\n", $settings['categories'] ) ); ?></textarea><br><span class="description"><?php esc_html_e( 'One category per line.', 'ajforms' ); ?></span></p>
					<p><label for="file_tags"><strong><?php esc_html_e( 'Internal Tags', 'ajforms' ); ?></strong></label><br>
					<textarea id="file_tags" name="file_tags" rows="6" class="large-text"><?php echo esc_textarea( implode( "\n", array_map( function ( $label ) { return '#' . $label; }, $settings['tags'] ) ) ); ?></textarea><br><span class="description"><?php esc_html_e( 'One tag per line. The # prefix is optional.', 'ajforms' ); ?></span></p>
					<p><strong><?php esc_html_e( 'Tags Allowed for Migration', 'ajforms' ); ?></strong></p>
					<?php foreach ( $settings['tags'] as $slug => $label ) : ?>
						<label style="display:block;margin:6px 0;"><input type="checkbox" name="migration_tags[]" value="<?php echo esc_attr( $slug ); ?>" <?php checked( in_array( $slug, $settings['migration_tags'], true ) ); ?>> #<?php echo esc_html( $label ); ?></label>
					<?php endforeach; ?>
					<?php submit_button( __( 'Save File Settings', 'ajforms' ) ); ?>
				</fieldset>
			</form>
		</div>
		<?php
	}


	private function handle_portal_api_settings_save() {
		if ( ! current_user_can( 'manage_options' ) || empty( $_POST['ajcore_api_settings_action'] ) ) {
			return;
		}

		check_admin_referer( 'ajcore_save_api_settings', 'ajcore_api_nonce' );

		$settings = array(
			'enabled'             => ! empty( $_POST['api_enabled'] ) ? '1' : '0',
			'ops_enabled'         => ! empty( $_POST['ops_enabled'] ) ? '1' : '0',
			'portal_enabled'      => ! empty( $_POST['portal_enabled'] ) ? '1' : '0',
			'public_status'       => ! empty( $_POST['public_status'] ) ? '1' : '0',
			'master_only'         => ! empty( $_POST['master_only'] ) ? '1' : '0',
			'portal_master_only'  => ! empty( $_POST['portal_master_only'] ) ? '1' : '0',
			'require_https_notes' => ! empty( $_POST['require_https_notes'] ) ? '1' : '0',
		);

		update_option( 'ajcore_api_settings', $settings, false );

		$this->log_portal_event(
			'api_settings_updated',
			array(
				'source'  => 'api_settings',
				'details' => $settings,
			)
		);

		wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-cp-settings', 'cp_section' => 'api', 'api-settings-saved' => '1' ), admin_url( 'admin.php' ) ) );
		exit;
	}

	private function get_portal_api_settings() {
		if ( class_exists( 'AJCore_REST_API' ) && method_exists( 'AJCore_REST_API', 'get_api_settings' ) ) {
			return AJCore_REST_API::get_api_settings();
		}

		$settings = get_option( 'ajcore_api_settings', array() );
		return wp_parse_args(
			is_array( $settings ) ? $settings : array(),
			array(
				'enabled'             => '1',
				'ops_enabled'         => '1',
				'portal_enabled'      => '1',
				'public_status'       => '1',
				'master_only'         => '1',
				'portal_master_only'  => '0',
				'require_https_notes' => '1',
			)
		);
	}

	private function get_portal_api_endpoint_catalog() {
		if ( class_exists( 'AJCore_REST_API' ) && method_exists( 'AJCore_REST_API', 'get_endpoint_catalog' ) ) {
			return AJCore_REST_API::get_endpoint_catalog();
		}

		return array();
	}

	private function get_api_status_badge( $enabled, $label_on, $label_off ) {
		return '<span class="ajcore-status-pill ' . ( $enabled ? 'active' : 'disabled' ) . '">' . esc_html( $enabled ? $label_on : $label_off ) . '</span>';
	}

