		<script>
		(function() {
			var table   = document.getElementById('ajcore-api-table');
			var search  = document.getElementById('ajcore-api-search');
			var badge   = document.getElementById('ajcore-api-count-badge');
			var noRes   = document.getElementById('ajcore-api-no-results');
			var rows    = Array.from(table.querySelectorAll('tbody tr:not(#ajcore-api-no-results)'));
			var filters = { surface: '', method: '' };
			var sortCol = null, sortDir = 1;

			function applyFilters() {
				var q = search.value.toLowerCase().trim();
				var vis = 0;
				rows.forEach(function(row) {
					var ok = true;
					if (filters.surface && row.dataset.surface !== filters.surface) ok = false;
					if (filters.method  && row.dataset.method  !== filters.method)  ok = false;
					if (ok && q && row.dataset.search.indexOf(q) === -1) ok = false;
					row.style.display = ok ? '' : 'none';
					if (ok) vis++;
				});
				badge.textContent = vis + ' endpoint' + (vis !== 1 ? 's' : '');
				noRes.style.display = vis === 0 ? '' : 'none';
			}

			// Filter pills
			document.querySelectorAll('.ajcore-api-filter-pill').forEach(function(btn) {
				btn.addEventListener('click', function() {
					var ftype = btn.dataset.filter;
					var fval  = btn.dataset.value;
					filters[ftype] = fval;
					document.querySelectorAll('.ajcore-api-filter-pill[data-filter="' + ftype + '"]').forEach(function(b) {
						b.classList.toggle('active', b.dataset.value === fval);
					});
					applyFilters();
				});
			});

			// Search
			search.addEventListener('input', applyFilters);

			// Sort
			var headers = table.querySelectorAll('thead th[data-col]');
			headers.forEach(function(th) {
				th.addEventListener('click', function() {
					var col = th.dataset.col;
					if (sortCol === col) {
						sortDir *= -1;
					} else {
						sortCol = col;
						sortDir = 1;
					}
					headers.forEach(function(h) { h.classList.remove('sort-asc','sort-desc'); });
					th.classList.add(sortDir === 1 ? 'sort-asc' : 'sort-desc');

					var tbody = table.querySelector('tbody');
					rows.slice().sort(function(a, b) {
						var av = (a.dataset[col] || '').toLowerCase();
						var bv = (b.dataset[col] || '').toLowerCase();
						if (av < bv) return -1 * sortDir;
						if (av > bv) return  1 * sortDir;
						return 0;
					}).forEach(function(r) { tbody.insertBefore(r, noRes); });
				});
			});

			// Copy buttons
			table.querySelectorAll('.ajcore-api-copy-btn').forEach(function(btn) {
				btn.addEventListener('click', function() {
					var url = btn.dataset.url;
					if (navigator.clipboard) {
						navigator.clipboard.writeText(url).then(function() {
							btn.textContent = 'copied!';
							btn.classList.add('copied');
							setTimeout(function() { btn.textContent = 'copy'; btn.classList.remove('copied'); }, 1800);
						});
					}
				});
			});
		})();
		</script>
		<?php
	}


	private function get_portal_partners_table() {
		return $this->get_pdb()->prefix . 'aj_portal_partners';
	}

	private function get_portal_partner_billing_mode_labels() {
		return array(
			'fixed_per_account' => __( 'Fixed per account (partner pays us, no invoicing)', 'ajforms' ),
			'invoiced_report'   => __( 'Invoiced via monthly report (we bill the partner)', 'ajforms' ),
		);
	}

	/**
	 * Counts distinct customers with an active/trialing subscription to each of the two core
	 * recurring products — Registered Agent Subscription and Virtual Office Subscription (the
	 * subscription, not the one-time setup). Matched by product name, so F&F / yearly variants
	 * still count toward the same bucket.
	 */
	/** Also returns the customer-id lists (not just counts) so the ops UI can filter the
	 *  customer list down to "has RA" / "has VO" / "no subscription at all". */
	public function get_portal_core_subscription_product_counts() {
		$pdb  = $this->get_pdb();
		$rows = $pdb->get_results( "SELECT stripe_customer_id, items FROM {$this->get_portal_stripe_subscriptions_table()} WHERE status IN ('active','trialing')" );

		$ra_customers  = array();
		$vo_customers  = array();
		$any_customers = array();
		foreach ( (array) $rows as $row ) {
			// Any active/trialing subscription row at all counts as "has a subscription",
			// even if its price doesn't match a known RA/VO product below.
			$any_customers[ (string) $row->stripe_customer_id ] = true;

			$items = json_decode( (string) $row->items, true );
			if ( ! is_array( $items ) ) {
				continue;
			}
			foreach ( $items as $item ) {
				if ( ! is_array( $item ) ) {
					continue;
				}
				$price_id = '';
				if ( ! empty( $item['plan']['id'] ) ) {
					$price_id = (string) $item['plan']['id'];
				} elseif ( ! empty( $item['price']['id'] ) ) {
					$price_id = (string) $item['price']['id'];
				}
				if ( '' === $price_id ) {
					continue;
				}
				$product = $this->get_portal_product_by_price_id( $price_id );
				if ( ! $product ) {
					continue;
				}
				$name = strtolower( ! empty( $product->custom_label ) ? (string) $product->custom_label : (string) $product->name );
				if ( false !== strpos( $name, 'registered agent' ) ) {
					$ra_customers[ (string) $row->stripe_customer_id ] = true;
				} elseif ( false !== strpos( $name, 'virtual office' ) && false === strpos( $name, 'setup' ) ) {
					$vo_customers[ (string) $row->stripe_customer_id ] = true;
				}
			}
		}

		return array(
			'registered_agent_subscription'           => count( $ra_customers ),
			'virtual_office_subscription'              => count( $vo_customers ),
			'registered_agent_subscription_customers' => array_keys( $ra_customers ),
			'virtual_office_subscription_customers'    => array_keys( $vo_customers ),
			'any_subscription_customers'                => array_keys( $any_customers ),
		);
	}

	/** Synced Stripe prices used for partner rates: price_id → label/amount/currency/interval. */
	public function get_partner_price_map() {
		$pdb   = $this->get_pdb();
		$table = $this->get_portal_stripe_products_table();
		$map   = array();
		foreach ( (array) $pdb->get_results( "SELECT stripe_price_id, name, custom_label, price_amount, currency, recurring_interval FROM `{$table}` WHERE active = 1 ORDER BY name ASC, price_amount ASC" ) as $p ) {
			if ( empty( $p->stripe_price_id ) || isset( $map[ $p->stripe_price_id ] ) ) {
				continue;
			}
			$label = ( ! empty( $p->custom_label ) ? $p->custom_label : $p->name )
				. ' — $' . number_format( (float) $p->price_amount, 2 )
				. ( $p->recurring_interval ? '/' . $p->recurring_interval : '' );
			$map[ $p->stripe_price_id ] = array(
				'label'    => $label,
				'amount'   => (float) $p->price_amount,
				'currency' => $p->currency ? $p->currency : 'usd',
				'interval' => (string) $p->recurring_interval,
			);
		}
		return $map;
	}

	/** Effective rate for one partner account: per-account Stripe price → partner Stripe price → manual fallback. */
	public function get_partner_account_rate( $partner, $account, $price_map ) {
		$account_price = isset( $account->partner_price_id ) ? (string) $account->partner_price_id : '';
		if ( '' !== $account_price && isset( $price_map[ $account_price ] ) ) {
			return $price_map[ $account_price ]['amount'];
		}
		$partner_price = isset( $partner->stripe_price_id ) ? (string) $partner->stripe_price_id : '';
		if ( '' !== $partner_price && isset( $price_map[ $partner_price ] ) ) {
			return $price_map[ $partner_price ]['amount'];
		}
		return (float) $partner->per_account_amount;
	}

	/** All Stripe price ids used for partner billing — these prices are hidden from end customers. */
	public function get_partner_reserved_price_ids() {
		$pdb            = $this->get_pdb();
		$partners_table = $this->get_portal_partners_table();
		if ( $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $partners_table ) ) !== $partners_table ) {
			return array();
		}
		$ids = $pdb->get_col( "SELECT stripe_price_id FROM `{$partners_table}` WHERE stripe_price_id <> ''" );
		$customer_table = $this->get_portal_stripe_customers_table();
		if ( $pdb->get_var( "SHOW COLUMNS FROM `{$customer_table}` LIKE 'partner_price_id'" ) ) {
			$ids = array_merge( $ids, (array) $pdb->get_col( "SELECT DISTINCT partner_price_id FROM `{$customer_table}` WHERE partner_price_id <> ''" ) );
		}
		return array_values( array_unique( array_filter( array_map( 'sanitize_text_field', $ids ) ) ) );
	}

	private function display_portal_partners_tab() {
		$pdb   = $this->get_pdb();
		$table = $this->get_portal_partners_table();

		if ( $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $table ) ) !== $table ) {
			echo '<div class="ajforms-settings-card"><p>' . esc_html__( 'Partners table not found yet — it is created automatically on the next plugin upgrade check.', 'ajforms' ) . '</p></div>';
			return;
		}

		// Save partner settings.
		if ( isset( $_POST['ajcore_partner_save_nonce'], $_POST['partner_id'] ) ) {
			check_admin_referer( 'ajcore_partner_save', 'ajcore_partner_save_nonce' );
			$modes = array_keys( $this->get_portal_partner_billing_mode_labels() );
			$mode  = isset( $_POST['partner_billing_mode'] ) ? sanitize_key( wp_unslash( $_POST['partner_billing_mode'] ) ) : '';
			$pdb->update(
				$table,
				array(
					'name'               => isset( $_POST['partner_name'] ) ? sanitize_text_field( wp_unslash( $_POST['partner_name'] ) ) : '',
					'billing_mode'       => in_array( $mode, $modes, true ) ? $mode : 'invoiced_report',
					'stripe_price_id'    => isset( $_POST['partner_stripe_price_id'] ) ? sanitize_text_field( wp_unslash( $_POST['partner_stripe_price_id'] ) ) : '',
					'per_account_amount' => isset( $_POST['partner_rate'] ) ? round( (float) wp_unslash( $_POST['partner_rate'] ), 2 ) : 0,
					'notes'              => isset( $_POST['partner_notes'] ) ? sanitize_textarea_field( wp_unslash( $_POST['partner_notes'] ) ) : '',
					'updated_at'         => current_time( 'mysql' ),
				),
				array( 'id' => absint( $_POST['partner_id'] ) ),
				array( '%s', '%s', '%s', '%f', '%s', '%s' ),
				array( '%d' )
			);
			echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Partner saved.', 'ajforms' ) . '</p></div>';
		}

		// Save a per-account price override.
		if ( isset( $_POST['ajcore_partner_account_price_nonce'], $_POST['account_customer_id'] ) ) {
			check_admin_referer( 'ajcore_partner_account_price', 'ajcore_partner_account_price_nonce' );
			$pdb->update(
				$this->get_portal_stripe_customers_table(),
				array( 'partner_price_id' => isset( $_POST['account_price_id'] ) ? sanitize_text_field( wp_unslash( $_POST['account_price_id'] ) ) : '' ),
				array( 'stripe_customer_id' => sanitize_text_field( wp_unslash( $_POST['account_customer_id'] ) ) ),
				array( '%s' ),
				array( '%s' )
			);
			echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Account rate saved.', 'ajforms' ) . '</p></div>';
		}

		$partners       = $pdb->get_results( "SELECT * FROM `{$table}` ORDER BY name ASC" );
		$customer_table = $this->get_portal_stripe_customers_table();
		$mode_labels    = $this->get_portal_partner_billing_mode_labels();
		$price_map      = $this->get_partner_price_map();
		?>
		<div class="ajforms-settings-card">
			<div class="ajcore-section-head">
				<div>
					<h2><?php esc_html_e( 'Payer / Partner Accounts', 'ajforms' ); ?></h2>
					<p><?php esc_html_e( 'Partners whose end customers we service. Assign customers to a partner from the customer view page. Fixed partners (OPUS) pay a set rate per account; invoiced partners (Alliance VO) are billed from the monthly report below.', 'ajforms' ); ?></p>
				</div>
			</div>

			<?php foreach ( $partners as $partner ) : ?>
				<?php
				$accounts = $pdb->get_results(
					$pdb->prepare(
						"SELECT stripe_customer_id, name, email, portal_status, partner_price_id FROM `{$customer_table}` WHERE partner_key = %s ORDER BY name ASC",
						$partner->partner_key
					)
				);
				$count = count( $accounts );
				$total = 0.0;
				foreach ( $accounts as $account ) {
					$total += $this->get_partner_account_rate( $partner, $account, $price_map );
				}
				$total = round( $total, 2 );
				$partner_default_rate = $this->get_partner_account_rate( $partner, (object) array( 'partner_price_id' => '' ), $price_map );
				?>
				<div class="ajcore-admin-panel" style="margin-bottom:16px;">
					<div class="ajcore-section-head">
						<div>
							<h3 style="margin:0 0 4px;"><?php echo esc_html( $partner->name ); ?> <code><?php echo esc_html( $partner->partner_key ); ?></code></h3>
							<p style="margin:0;"><?php echo esc_html( isset( $mode_labels[ $partner->billing_mode ] ) ? $mode_labels[ $partner->billing_mode ] : $partner->billing_mode ); ?></p>
						</div>
						<span class="ajforms-settings-pill">
							<?php echo esc_html( sprintf( __( '%1$d accounts · %2$s / month', 'ajforms' ), $count, $this->format_portal_money( $total, 'usd' ) ) ); ?>
						</span>
					</div>

					<form method="post" style="display:flex;flex-wrap:wrap;gap:10px;align-items:flex-end;margin:0 0 14px;padding:12px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:12px;">
						<?php wp_nonce_field( 'ajcore_partner_save', 'ajcore_partner_save_nonce' ); ?>
						<input type="hidden" name="partner_id" value="<?php echo esc_attr( (int) $partner->id ); ?>">
						<label><?php esc_html_e( 'Name', 'ajforms' ); ?><br><input type="text" name="partner_name" value="<?php echo esc_attr( $partner->name ); ?>"></label>
						<label><?php esc_html_e( 'Billing mode', 'ajforms' ); ?><br>
							<select name="partner_billing_mode">
								<?php foreach ( $mode_labels as $mode_key => $mode_label ) : ?>
									<option value="<?php echo esc_attr( $mode_key ); ?>" <?php selected( $partner->billing_mode, $mode_key ); ?>><?php echo esc_html( $mode_label ); ?></option>
								<?php endforeach; ?>
							</select>
						</label>
						<label><?php esc_html_e( 'Default rate — Stripe price (synced)', 'ajforms' ); ?><br>
						<select name="partner_stripe_price_id" style="max-width:320px;">
							<option value=""><?php esc_html_e( '— No Stripe price (use manual rate) —', 'ajforms' ); ?></option>
							<?php foreach ( $price_map as $price_id => $price ) : ?>
								<option value="<?php echo esc_attr( $price_id ); ?>" <?php selected( (string) $partner->stripe_price_id, $price_id ); ?>><?php echo esc_html( $price['label'] ); ?></option>
							<?php endforeach; ?>
						</select>
					</label>
					<label><?php esc_html_e( 'Manual fallback rate (USD)', 'ajforms' ); ?><br><input type="number" step="0.01" min="0" name="partner_rate" value="<?php echo esc_attr( number_format( (float) $partner->per_account_amount, 2, '.', '' ) ); ?>" style="width:120px;"></label>
						<label style="flex:1;min-width:240px;"><?php esc_html_e( 'Notes', 'ajforms' ); ?><br><input type="text" name="partner_notes" value="<?php echo esc_attr( (string) $partner->notes ); ?>" style="width:100%;"></label>
						<button type="submit" class="button button-primary"><?php esc_html_e( 'Save', 'ajforms' ); ?></button>
					</form>

					<?php if ( empty( $accounts ) ) : ?>
						<p class="description"><?php esc_html_e( 'No customers assigned yet — open a customer and set their Partner / Payer.', 'ajforms' ); ?></p>
					<?php else : ?>
						<table class="widefat striped">
							<thead>
								<tr>
									<th><?php esc_html_e( 'Customer', 'ajforms' ); ?></th>
									<th><?php esc_html_e( 'Email', 'ajforms' ); ?></th>
									<th><?php esc_html_e( 'Status', 'ajforms' ); ?></th>
									<th><?php esc_html_e( 'Monthly Rate', 'ajforms' ); ?></th>
									<th><?php esc_html_e( 'Rate Override (Stripe price)', 'ajforms' ); ?></th>
								</tr>
							</thead>
							<tbody>
								<?php foreach ( $accounts as $account ) : ?>
									<?php $account_rate = $this->get_partner_account_rate( $partner, $account, $price_map ); ?>
									<tr>
										<td><a href="<?php echo esc_url( $this->get_portal_customer_360_url( $account->stripe_customer_id ) ); ?>"><?php echo esc_html( $account->name ? $account->name : $account->stripe_customer_id ); ?></a></td>
										<td><?php echo esc_html( $account->email ); ?></td>
										<td><?php echo esc_html( $account->portal_status ); ?></td>
										<td>
											<?php echo esc_html( $this->format_portal_money( $account_rate, 'usd' ) ); ?>
											<?php if ( empty( $account->partner_price_id ) ) : ?>
												<span class="description"><?php esc_html_e( '(default)', 'ajforms' ); ?></span>
											<?php endif; ?>
										</td>
										<td>
											<form method="post" style="display:flex;gap:6px;align-items:center;margin:0;">
												<?php wp_nonce_field( 'ajcore_partner_account_price', 'ajcore_partner_account_price_nonce' ); ?>
												<input type="hidden" name="account_customer_id" value="<?php echo esc_attr( $account->stripe_customer_id ); ?>">
												<select name="account_price_id" style="max-width:260px;">
													<option value=""><?php esc_html_e( '— Partner default —', 'ajforms' ); ?></option>
													<?php foreach ( $price_map as $price_id => $price ) : ?>
														<option value="<?php echo esc_attr( $price_id ); ?>" <?php selected( (string) $account->partner_price_id, $price_id ); ?>><?php echo esc_html( $price['label'] ); ?></option>
													<?php endforeach; ?>
												</select>
												<button type="submit" class="button button-small"><?php esc_html_e( 'Save', 'ajforms' ); ?></button>
											</form>
										</td>
									</tr>
								<?php endforeach; ?>
							</tbody>
						</table>
						<?php if ( 'fixed_per_account' === $partner->billing_mode ) : ?>
							<p class="description" style="margin-top:8px;"><?php esc_html_e( 'This partner pays the per-account rate directly — no invoice needed. Upsold services for these accounts are charged separately through their Stripe customer records.', 'ajforms' ); ?></p>
						<?php else : ?>
							<p class="description" style="margin-top:8px;"><?php echo esc_html( sprintf( __( 'Monthly amount to bill this partner: %s. End customers are never billed directly by us.', 'ajforms' ), $this->format_portal_money( $total, 'usd' ) ) ); ?></p>
						<?php endif; ?>
					<?php endif; ?>
				</div>
			<?php endforeach; ?>
		</div>
		<?php
	}

	private function display_portal_emails_tab() {
		global $wpdb;
		$table = $wpdb->prefix . 'aj_portal_email_log';

		if ( $wpdb->get_var( $wpdb->prepare( 'SHOW TABLES LIKE %s', $table ) ) !== $table ) {
			echo '<div class="ajforms-settings-card"><p>' . esc_html__( 'Email log table not found yet — it is created automatically on the next plugin upgrade check.', 'ajforms' ) . '</p></div>';
			return;
		}

		// Delete one / delete all.
		if ( isset( $_POST['ajcore_email_log_delete_nonce'] ) ) {
			check_admin_referer( 'ajcore_email_log_delete', 'ajcore_email_log_delete_nonce' );
			if ( isset( $_POST['delete_all_emails'] ) ) {
				$wpdb->query( "TRUNCATE TABLE `{$table}`" );
				echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'All logged emails deleted.', 'ajforms' ) . '</p></div>';
			} elseif ( isset( $_POST['delete_email_id'] ) ) {
				$wpdb->delete( $table, array( 'id' => absint( $_POST['delete_email_id'] ) ), array( '%d' ) );
				echo '<div class="notice notice-success is-dismissible"><p>' . esc_html__( 'Email deleted from the log.', 'ajforms' ) . '</p></div>';
			}
		}

		$search = isset( $_GET['email_search'] ) ? sanitize_text_field( wp_unslash( $_GET['email_search'] ) ) : '';
		$where  = '1=1';
		$params = array();
		if ( '' !== $search ) {
			$like   = '%' . $wpdb->esc_like( $search ) . '%';
			$where  = '(to_email LIKE %s OR subject LIKE %s)';
			$params = array( $like, $like );
		}

		$sql  = "SELECT id, to_email, subject, status, error_message, message, created_at FROM `{$table}` WHERE {$where} ORDER BY id DESC LIMIT 200";
		$rows = $params ? $wpdb->get_results( $wpdb->prepare( $sql, $params ) ) : $wpdb->get_results( $sql );
		$total = (int) $wpdb->get_var( "SELECT COUNT(*) FROM `{$table}`" );
		?>
		<div class="ajforms-settings-card">
			<div class="ajcore-section-head">
				<div>
					<h2><?php esc_html_e( 'Emails', 'ajforms' ); ?></h2>
					<p><?php esc_html_e( 'Every email sent from this site (welcome emails, password resets, service request updates, form notifications).', 'ajforms' ); ?></p>
				</div>
				<span class="ajforms-settings-pill"><?php echo esc_html( sprintf( __( '%d emails logged', 'ajforms' ), $total ) ); ?></span>
			</div>
			<form method="get" class="ajforms-settings-inline-actions" style="align-items:center;gap:10px;">
				<input type="hidden" name="page" value="ajforms-client-portal">
				<input type="hidden" name="tab" value="emails">
				<input type="search" name="email_search" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php esc_attr_e( 'Search recipient or subject…', 'ajforms' ); ?>" style="min-width:280px;">
				<button class="button"><?php esc_html_e( 'Search', 'ajforms' ); ?></button>
				<a class="button" href="<?php echo esc_url( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'emails' ), admin_url( 'admin.php' ) ) ); ?>"><?php esc_html_e( 'Reset', 'ajforms' ); ?></a>
			</form>
			<form method="post" style="margin:0 0 6px;" onsubmit="return window.confirm('<?php echo esc_js( __( 'Delete ALL logged emails? This cannot be undone.', 'ajforms' ) ); ?>');">
				<?php wp_nonce_field( 'ajcore_email_log_delete', 'ajcore_email_log_delete_nonce' ); ?>
				<button type="submit" name="delete_all_emails" value="1" class="button" style="color:#b91c1c;border-color:#fca5a5;"><?php esc_html_e( 'Delete All Emails', 'ajforms' ); ?></button>
			</form>
			<table class="widefat striped" style="margin-top:14px;">
				<thead>
					<tr>
						<th style="width:170px;"><?php esc_html_e( 'Date', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'To', 'ajforms' ); ?></th>
						<th><?php esc_html_e( 'Subject', 'ajforms' ); ?></th>
						<th style="width:110px;"><?php esc_html_e( 'Status', 'ajforms' ); ?></th>
					</tr>
				</thead>
				<tbody>
					<?php if ( empty( $rows ) ) : ?>
						<tr><td colspan="4"><?php esc_html_e( 'No emails logged yet.', 'ajforms' ); ?></td></tr>
					<?php else : ?>
						<?php foreach ( $rows as $row ) : ?>
							<tr>
								<td><?php echo esc_html( $this->format_portal_date( $row->created_at ) ); ?></td>
								<td><?php echo esc_html( $row->to_email ); ?></td>
								<td>
									<?php echo esc_html( $row->subject ); ?>
									<?php if ( 'failed' === $row->status && ! empty( $row->error_message ) ) : ?>
										<br><span class="description" style="color:#b91c1c;"><?php echo esc_html( $row->error_message ); ?></span>
									<?php endif; ?>
									<?php if ( ! empty( $row->message ) ) : ?>
										<details style="margin-top:6px;">
											<summary style="cursor:pointer;color:#2563eb;"><?php esc_html_e( 'View email', 'ajforms' ); ?></summary>
											<iframe sandbox="" srcdoc="<?php echo esc_attr( $row->message ); ?>" style="width:100%;max-width:720px;height:420px;border:1px solid #e2e8f0;border-radius:10px;background:#fff;margin-top:8px;"></iframe>
										</details>
									<?php endif; ?>
								</td>
								<td>
									<span class="ajcore-status-pill <?php echo 'failed' === $row->status ? 'archived' : 'active'; ?>"><?php echo esc_html( ucfirst( $row->status ) ); ?></span>
									<form method="post" style="margin-top:6px;" onsubmit="return window.confirm('<?php echo esc_js( __( 'Delete this email from the log?', 'ajforms' ) ); ?>');">
										<?php wp_nonce_field( 'ajcore_email_log_delete', 'ajcore_email_log_delete_nonce' ); ?>
										<button type="submit" name="delete_email_id" value="<?php echo esc_attr( (int) $row->id ); ?>" class="button-link" style="color:#b91c1c;cursor:pointer;"><?php esc_html_e( 'Delete', 'ajforms' ); ?></button>
									</form>
								</td>
							</tr>
						<?php endforeach; ?>
					<?php endif; ?>
				</tbody>
			</table>
		</div>
		<?php
	}

	private function display_portal_event_log_tab() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		$wpdb = $this->get_pdb();

		$table = $this->get_portal_event_log_table();
		if ( $wpdb->get_var( $wpdb->prepare( 'SHOW TABLES LIKE %s', $table ) ) !== $table ) {
			echo '<div class="notice notice-warning"><p>' . esc_html__( 'The portal event log table is not available yet. Deactivate and reactivate AJ Core or run the schema check by opening Client Portal again.', 'ajforms' ) . '</p></div>';
			return;
		}

		$event_type         = isset( $_GET['event_type'] ) ? sanitize_key( wp_unslash( $_GET['event_type'] ) ) : '';
		$severity           = isset( $_GET['severity'] ) ? sanitize_key( wp_unslash( $_GET['severity'] ) ) : '';
		$source             = isset( $_GET['source'] ) ? sanitize_key( wp_unslash( $_GET['source'] ) ) : '';
		$stripe_customer_id = isset( $_GET['stripe_customer_id'] ) ? sanitize_text_field( wp_unslash( $_GET['stripe_customer_id'] ) ) : '';
		$search             = isset( $_GET['s'] ) ? sanitize_text_field( wp_unslash( $_GET['s'] ) ) : '';

		$where  = array( '1=1' );
		$params = array();
		if ( '' !== $event_type ) {
			$where[]  = 'event_type = %s';
			$params[] = $event_type;
		}
		if ( '' !== $severity ) {
			$where[]  = 'severity = %s';
			$params[] = $severity;
		}
		if ( '' !== $source ) {
			$where[]  = 'source = %s';
			$params[] = $source;
		}
		if ( '' !== $stripe_customer_id ) {
			$where[]  = 'stripe_customer_id = %s';
			$params[] = $stripe_customer_id;
		}
		if ( '' !== $search ) {
			$like     = '%' . $wpdb->esc_like( $search ) . '%';
			$where[]  = '(event_type LIKE %s OR correlation_id LIKE %s OR stripe_customer_id LIKE %s OR email_before LIKE %s OR email_after LIKE %s OR actor_email LIKE %s OR details LIKE %s)';
			$params[] = $like;
			$params[] = $like;
			$params[] = $like;
			$params[] = $like;
			$params[] = $like;
			$params[] = $like;
			$params[] = $like;
		}

		$sql  = "SELECT * FROM {$table} WHERE " . implode( ' AND ', $where ) . ' ORDER BY created_at DESC, id DESC LIMIT 300';
		$rows = ! empty( $params ) ? $wpdb->get_results( $wpdb->prepare( $sql, $params ) ) : $wpdb->get_results( $sql );

		$event_types = $wpdb->get_col( "SELECT DISTINCT event_type FROM {$table} ORDER BY event_type ASC" );
		$sources     = $wpdb->get_col( "SELECT DISTINCT source FROM {$table} ORDER BY source ASC" );
		$severities  = array( 'debug', 'info', 'warning', 'error', 'critical' );
		$base_url    = add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'event-log' ), admin_url( 'admin.php' ) );
		$retention   = $this->get_portal_event_log_retention_settings();
		$total_rows  = absint( $wpdb->get_var( "SELECT COUNT(*) FROM {$table}" ) );
		$last_purge  = absint( get_option( 'ajcore_portal_event_log_last_auto_purge', 0 ) );
		?>
		<div class="ajforms-settings-card ajcore-event-log-panel">
			<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'Event Log', 'ajforms' ); ?></h2><p><?php esc_html_e( 'Audit trail for portal mapping, roles, lifecycle changes, auth, sync preservation, repair, and provisioning events.', 'ajforms' ); ?></p></div><span class="ajforms-settings-pill"><?php echo esc_html( sprintf( __( '%d rows', 'ajforms' ), $total_rows ) ); ?></span></div>

		<?php if ( isset( $_GET['event-log-settings-saved'] ) ) : ?>
			<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Event log retention settings saved.', 'ajforms' ); ?></p></div>
		<?php endif; ?>
		<?php if ( isset( $_GET['event-log-purged'] ) ) : ?>
			<div class="notice notice-success is-dismissible"><p><?php echo esc_html( sprintf( __( 'Event log purge complete. Deleted %d rows.', 'ajforms' ), absint( $_GET['event-log-purged'] ) ) ); ?></p></div>
		<?php endif; ?>
		<?php if ( isset( $_GET['event-log-error'] ) ) : ?>
			<div class="notice notice-error is-dismissible"><p><?php echo esc_html( sanitize_text_field( wp_unslash( $_GET['event-log-error'] ) ) ); ?></p></div>
		<?php endif; ?>

		<div class="ajforms-settings-card" style="margin:12px 0 16px;padding:16px 18px;border-radius:8px;">
			<h3 style="margin-top:0;"><?php esc_html_e( 'Retention & Purging', 'ajforms' ); ?></h3>
			<p class="description">
				<?php
				echo esc_html(
					sprintf(
						__( 'Current table rows: %1$d. Automatic purge runs at most once per day after a new event is logged.%2$s', 'ajforms' ),
						$total_rows,
						$last_purge ? ' ' . sprintf( __( 'Last auto purge: %s.', 'ajforms' ), wp_date( 'Y-m-d H:i:s', $last_purge ) ) : ''
					)
				);
				?>
			</p>
			<form method="post" style="display:flex;gap:12px;align-items:flex-end;flex-wrap:wrap;margin-top:12px;">
				<?php wp_nonce_field( 'ajcore_event_log_settings', 'ajcore_event_log_nonce' ); ?>
				<input type="hidden" name="ajcore_event_log_action" value="save_retention">
				<label>
					<?php esc_html_e( 'Keep days', 'ajforms' ); ?><br>
					<input type="number" name="portal_event_log_retention_days" min="0" step="1" value="<?php echo esc_attr( $retention['days'] ); ?>" style="width:120px;">
				</label>
				<label>
					<?php esc_html_e( 'Max rows', 'ajforms' ); ?><br>
					<input type="number" name="portal_event_log_max_rows" min="0" step="100" value="<?php echo esc_attr( $retention['max_rows'] ); ?>" style="width:140px;">
				</label>
				<button type="submit" class="button button-secondary"><?php esc_html_e( 'Save Retention', 'ajforms' ); ?></button>
			</form>
			<form method="post" style="margin-top:10px;">
				<?php wp_nonce_field( 'ajcore_event_log_settings', 'ajcore_event_log_nonce' ); ?>
				<input type="hidden" name="ajcore_event_log_action" value="purge_now">
				<button type="submit" class="button button-secondary"><?php esc_html_e( 'Purge Now', 'ajforms' ); ?></button>
				<span class="description"><?php esc_html_e( 'Deletes rows older than the retention window, then trims oldest rows over the max row cap. Set either value to 0 to disable that rule.', 'ajforms' ); ?></span>
			</form>
		</div>

		<form method="get" class="ajcore-filter-bar" style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin:12px 0 16px;">
			<input type="hidden" name="page" value="ajforms-client-portal">
			<input type="hidden" name="tab" value="event-log">
			<select name="event_type">
				<option value=""><?php esc_html_e( 'All events', 'ajforms' ); ?></option>
				<?php foreach ( (array) $event_types as $type ) : ?>
					<option value="<?php echo esc_attr( $type ); ?>" <?php selected( $event_type, $type ); ?>><?php echo esc_html( $type ); ?></option>
				<?php endforeach; ?>
			</select>
			<select name="severity">
				<option value=""><?php esc_html_e( 'All severities', 'ajforms' ); ?></option>
				<?php foreach ( $severities as $level ) : ?>
					<option value="<?php echo esc_attr( $level ); ?>" <?php selected( $severity, $level ); ?>><?php echo esc_html( ucfirst( $level ) ); ?></option>
				<?php endforeach; ?>
			</select>
			<select name="source">
				<option value=""><?php esc_html_e( 'All sources', 'ajforms' ); ?></option>
				<?php foreach ( (array) $sources as $item_source ) : ?>
					<option value="<?php echo esc_attr( $item_source ); ?>" <?php selected( $source, $item_source ); ?>><?php echo esc_html( $item_source ); ?></option>
				<?php endforeach; ?>
			</select>
			<input type="text" name="stripe_customer_id" value="<?php echo esc_attr( $stripe_customer_id ); ?>" placeholder="<?php echo esc_attr__( 'Stripe customer ID', 'ajforms' ); ?>">
			<input type="search" name="s" value="<?php echo esc_attr( $search ); ?>" placeholder="<?php echo esc_attr__( 'Search event log', 'ajforms' ); ?>">
			<button type="submit" class="button"><?php esc_html_e( 'Filter', 'ajforms' ); ?></button>
			<a class="button" href="<?php echo esc_url( $base_url ); ?>"><?php esc_html_e( 'Reset', 'ajforms' ); ?></a>
		</form>

		<table class="widefat striped">
			<thead>
				<tr>
					<th><?php esc_html_e( 'Date', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Event', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Severity', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Customer', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'WP User', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Email', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Portal Status', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Actor', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Source', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Correlation', 'ajforms' ); ?></th>
					<th><?php esc_html_e( 'Details', 'ajforms' ); ?></th>
				</tr>
			</thead>
			<tbody>
				<?php if ( empty( $rows ) ) : ?>
					<tr><td colspan="11"><?php esc_html_e( 'No portal events found.', 'ajforms' ); ?></td></tr>
				<?php else : ?>
					<?php foreach ( $rows as $row ) : ?>
						<?php
						$details = json_decode( (string) $row->details, true );
						$details = is_array( $details ) ? $details : array();
						$json    = wp_json_encode( $details, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES );
						?>
						<tr>
							<td><?php echo esc_html( $row->created_at ); ?></td>
							<td><strong><?php echo esc_html( $row->event_type ); ?></strong></td>
							<td><span class="ajcore-status-pill <?php echo esc_attr( sanitize_html_class( (string) $row->severity ) ); ?>"><?php echo esc_html( ucfirst( (string) $row->severity ) ); ?></span></td>
							<td>
								<?php if ( ! empty( $row->customer_id ) ) : ?>
									#<?php echo esc_html( (int) $row->customer_id ); ?><br>
								<?php endif; ?>
								<code><?php echo esc_html( $row->stripe_customer_id ); ?></code>
							</td>
							<td><?php echo esc_html( (int) $row->wp_user_id_before ); ?> &rarr; <?php echo esc_html( (int) $row->wp_user_id_after ); ?></td>
							<td><?php echo esc_html( $row->email_before ); ?><br>&rarr; <?php echo esc_html( $row->email_after ); ?></td>
							<td><?php echo esc_html( $row->portal_status_before ); ?><br>&rarr; <?php echo esc_html( $row->portal_status_after ); ?></td>
							<td>
								<?php echo esc_html( (int) $row->actor_user_id ); ?>
								<?php if ( ! empty( $row->actor_email ) ) : ?><br><?php echo esc_html( $row->actor_email ); ?><?php endif; ?>
							</td>
							<td><?php echo esc_html( $row->source ); ?><br><code><?php echo esc_html( $row->site_uuid ); ?></code></td>
							<td><code><?php echo esc_html( $row->correlation_id ); ?></code></td>
							<td>
								<?php if ( ! empty( $details ) ) : ?>
									<details>
										<summary><?php esc_html_e( 'View JSON', 'ajforms' ); ?></summary>
										<pre style="white-space:pre-wrap;max-width:360px;overflow:auto;"><?php echo esc_html( $json ); ?></pre>
									</details>
								<?php else : ?>
									-
								<?php endif; ?>
							</td>
						</tr>
					<?php endforeach; ?>
				<?php endif; ?>
			</tbody>
		</table>
		</div>
		<?php
	}

	private function display_portal_customer_detail_page() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		$stripe_customer_id = isset( $_GET['stripe_customer_id'] ) ? sanitize_text_field( wp_unslash( $_GET['stripe_customer_id'] ) ) : '';
		$detail             = $this->get_portal_customer_detail_data( $stripe_customer_id );
		$back_url           = add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'portal-users' ), admin_url( 'admin.php' ) );

		if ( ! $detail ) {
			?>
			<div class="notice notice-error"><p><?php esc_html_e( 'Portal customer was not found in the synced Stripe customer cache.', 'ajforms' ); ?></p></div>
			<p><a class="button" href="<?php echo esc_url( $back_url ); ?>"><?php esc_html_e( 'Back to Customers', 'ajforms' ); ?></a></p>
			<?php
			return;
		}

		$customer     = $detail['customer'];
		$is_local     = 0 === strpos( (string) $customer->stripe_customer_id, 'local_' );
		$user         = $detail['user'];
		$active_services_count = count( $detail['active_recurring_services'] ) + count( $detail['one_time_services'] );
		$portal_status = ! empty( $customer->portal_status ) ? sanitize_key( (string) $customer->portal_status ) : ( ! empty( $customer->enabled_portal ) ? 'active' : 'disabled' );
		$portal_on    = 'active' === $portal_status && ! empty( $customer->enabled_portal ) && $user;
		$display_fields = $this->get_portal_customer_display_fields();
		$is_editing   = isset( $_GET['edit_customer'] ) && '1' === (string) wp_unslash( $_GET['edit_customer'] );
		$addr         = ! empty( $customer->address ) ? ( is_array( $customer->address ) ? $customer->address : json_decode( $customer->address, true ) ) : array();
		$addr         = is_array( $addr ) ? $addr : array();
		$meta_data    = ! empty( $customer->metadata ) ? ( is_array( $customer->metadata ) ? $customer->metadata : json_decode( $customer->metadata, true ) ) : array();
		$meta_data    = is_array( $meta_data ) ? $meta_data : array();
		$subscription_products = $is_local ? array() : $this->api_get_ops_subscription_products();
		$local_ledger_page      = max( 1, isset( $_GET['ledger_page'] ) ? absint( wp_unslash( $_GET['ledger_page'] ) ) : 1 );
		$local_ledger_per_page  = 20;
		$local_ledger_total     = $is_local ? count( $detail['ledger'] ) : 0;
		$local_ledger_pages     = $is_local ? max( 1, (int) ceil( $local_ledger_total / $local_ledger_per_page ) ) : 1;
		$local_ledger_page      = min( $local_ledger_page, $local_ledger_pages );
		$local_ledger_rows      = $is_local ? array_slice( $detail['ledger'], ( $local_ledger_page - 1 ) * $local_ledger_per_page, $local_ledger_per_page ) : $detail['ledger'];
		$local_services_table   = $this->get_pdb()->prefix . 'aj_portal_local_services';
		$local_services         = $is_local ? $this->get_pdb()->get_results( $this->get_pdb()->prepare( "SELECT * FROM `{$local_services_table}` WHERE local_customer_id=%s ORDER BY contract_start_date DESC,id DESC", $customer->stripe_customer_id ) ) : array();
		$file_settings          = ajcore_get_portal_file_settings();
		$local_charge_total     = 0.0;
		$local_payment_total    = 0.0;
		if ( $is_local ) {
			foreach ( $detail['ledger'] as $local_entry ) {
				$local_amount = (float) $local_entry->amount;
				if ( $local_amount < 0 ) $local_charge_total += abs( $local_amount );
				else $local_payment_total += $local_amount;
			}
		}
		$sync_url     = wp_nonce_url(
			add_query_arg(
				array(
					'page'               => 'ajforms-client-portal',
					'tab'                => 'customer',
					'stripe_customer_id' => $customer->stripe_customer_id,
					'customer_action'    => 'sync_customer',
				),
				admin_url( 'admin.php' )
			),
			'ajcore_portal_customer_sync_' . $customer->stripe_customer_id
		);
		?>
		<style>
			.ajcore-customer-360{width:100%;max-width:none;box-sizing:border-box}
			.ajcore-customer-head{display:flex;align-items:flex-start;justify-content:space-between;gap:16px;margin:16px 0 18px}
			.ajcore-customer-head h2{margin:0 0 6px;font-size:24px}
			.ajcore-customer-grid{display:grid;grid-template-columns:repeat(2,minmax(320px,1fr));gap:16px;align-items:start}
			.ajcore-customer-grid.is-local{grid-template-columns:minmax(680px,2fr) minmax(340px,1fr)}
			.ajcore-customer-card{background:#fff;border:1px solid #dcdcde;border-radius:10px;padding:18px;overflow:hidden}
			.ajcore-customer-card h3{margin:0 0 14px;font-size:16px}
			.ajcore-customer-grid.is-local .ajcore-portal-access-card{grid-column:2;grid-row:1;padding:12px 16px}.ajcore-customer-grid.is-local .ajcore-portal-access-card h3{margin-bottom:8px}.ajcore-customer-grid.is-local .ajcore-customer-profile-card{grid-column:2;grid-row:2}.ajcore-customer-grid.is-local .ajcore-local-service-card{grid-column:1;grid-row:1}.ajcore-customer-grid.is-local .ajcore-local-ledger-card{grid-column:1;grid-row:2}.ajcore-customer-grid.is-local .ajcore-portal-access-card .ajcore-customer-meta{grid-template-columns:100px minmax(0,1fr);gap:5px 10px}.ajcore-customer-grid.is-local .ajcore-portal-access-card hr,.ajcore-customer-grid.is-local .ajcore-portal-access-card .ajcore-customer-actions,.ajcore-customer-grid.is-local .ajcore-portal-access-card .ajcore-customer-quick-actions{display:none}
			.ajcore-customer-card-head{display:flex;align-items:center;justify-content:space-between;gap:12px;margin:0 0 14px}
			.ajcore-customer-card-head h3{margin:0}
			.ajcore-customer-summary{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin:0 0 16px}
			.ajcore-customer-summary div{background:#fff;border:1px solid #dcdcde;border-radius:10px;padding:14px}
			.ajcore-customer-summary span{display:block;color:#646970;font-weight:600}
			.ajcore-customer-summary strong{display:block;margin-top:8px;font-size:22px}
			.ajcore-customer-meta{display:grid;grid-template-columns:150px minmax(0,1fr);gap:8px 14px}
			.ajcore-customer-meta dt{font-weight:600;color:#50575e}
