	private function render_portal_field_picker_script() {
		static $printed = false;
		if ( $printed ) {
			return;
		}
		$printed = true;
		?>
		<script>
		(function() {
			function moveToSelected(item, picker) {
				const selected = picker.querySelector('[data-ajcore-selected-fields]');
				const input = item ? item.querySelector('input[type="checkbox"]') : null;
				if (!item || !selected || !input) {
					return;
				}
				input.checked = true;
				item.draggable = true;
				item.style.borderRadius = '999px';
				item.style.cursor = 'grab';
				selected.appendChild(item);
			}

			function moveToAvailable(item, picker) {
				const available = picker.querySelector('[data-ajcore-available-fields]');
				const input = item ? item.querySelector('input[type="checkbox"]') : null;
				if (!item || !available || !input) {
					return;
				}
				input.checked = false;
				item.draggable = false;
				item.style.borderRadius = '6px';
				item.style.cursor = '';
				available.appendChild(item);
			}

			document.querySelectorAll('[data-ajcore-field-picker]').forEach(function(picker) {
				const selected = picker.querySelector('[data-ajcore-selected-fields]');
				const available = picker.querySelector('[data-ajcore-available-fields]');
				let dragged = null;

				picker.addEventListener('change', function(event) {
					if (!event.target.matches('input[type="checkbox"]')) {
						return;
					}
					const item = event.target.closest('li');
					if (event.target.checked) {
						moveToSelected(item, picker);
					} else {
						moveToAvailable(item, picker);
					}
				});

				const selectAll = picker.querySelector('[data-ajcore-select-all-fields]');
				if (selectAll) {
					selectAll.addEventListener('click', function() {
						Array.from(picker.querySelectorAll('li')).forEach(function(item) {
							moveToSelected(item, picker);
						});
					});
				}

				const clear = picker.querySelector('[data-ajcore-clear-fields]');
				if (clear) {
					clear.addEventListener('click', function() {
						Array.from(picker.querySelectorAll('li')).forEach(function(item) {
							moveToAvailable(item, picker);
						});
					});
				}

				if (!selected) {
					return;
				}

				selected.addEventListener('dragstart', function(event) {
					dragged = event.target.closest('li');
					if (dragged) {
						event.dataTransfer.effectAllowed = 'move';
					}
				});

				selected.addEventListener('dragover', function(event) {
					const target = event.target.closest('li');
					if (!dragged || !target || dragged === target || !selected.contains(target)) {
						return;
					}
					event.preventDefault();
					const rect = target.getBoundingClientRect();
					const after = event.clientX > rect.left + rect.width / 2 || event.clientY > rect.top + rect.height / 2;
					selected.insertBefore(dragged, after ? target.nextSibling : target);
				});

				selected.addEventListener('dragend', function() {
					dragged = null;
				});
			});
		})();
		</script>
		<?php
	}

	private function render_portal_dataset_section( $section, $title, $rows, $defaults, $empty_message, $show_field_picker = true ) {
		$section    = sanitize_key( $section );
		$available  = $this->discover_portal_row_scalar_fields( $rows );
		$selected   = array_values( array_intersect( $show_field_picker ? $this->get_portal_detail_display_fields( $section, $defaults ) : $defaults, $available ) );
		$show_subscription_actions = 'active_recurring_services' === $section;
		if ( empty( $selected ) && ! empty( $available ) ) {
			$selected = array_slice( array_values( array_intersect( $defaults, $available ) ), 0, 8 );
		}

		if ( $show_field_picker ) {
			$this->render_portal_field_display_picker(
			array(
				'section'       => $section,
				'title'         => sprintf( __( '%s Fields to Display', 'ajforms' ), $title ),
				'available'     => $available,
				'selected'      => $selected,
				'field_name'    => 'portal_detail_display_fields',
				'nonce_action'  => 'ajcore_save_portal_detail_fields_' . $section,
				'nonce_name'    => 'ajcore_portal_detail_fields_nonce',
				'hidden_inputs' => array(
					'detail_field_section' => $section,
				),
			)
			);
		}

		if ( empty( $rows ) ) {
			echo '<p>' . esc_html( $empty_message ) . '</p>';
			return;
		}

		if ( empty( $selected ) ) {
			echo '<p>' . esc_html__( 'No display fields selected.', 'ajforms' ) . '</p>';
			return;
		}
		?>
		<div class="ajcore-customer-table-wrap">
			<table class="widefat striped">
				<thead>
					<tr>
						<?php foreach ( $selected as $field ) : ?>
							<th><?php echo esc_html( $this->format_portal_customer_field_label( $field ) ); ?></th>
						<?php endforeach; ?>
						<?php if ( $show_subscription_actions ) : ?>
							<th><?php esc_html_e( 'Actions', 'ajforms' ); ?></th>
						<?php endif; ?>
					</tr>
				</thead>
				<tbody>
					<?php foreach ( $rows as $row ) : ?>
						<tr>
							<?php foreach ( $selected as $field ) : ?>
								<td><?php $this->render_portal_customer_field_value( $this->get_portal_row_display_value( $row, $field ) ); ?></td>
							<?php endforeach; ?>
							<?php if ( $show_subscription_actions ) : ?>
								<td><?php $this->render_portal_subscription_row_actions( $row ); ?></td>
							<?php endif; ?>
						</tr>
					<?php endforeach; ?>
				</tbody>
			</table>
		</div>
		<?php if ( $show_subscription_actions ) : ?>
			<script>
			(function() {
				var forms = document.querySelectorAll('.ajcore-subscription-update-form');
				forms.forEach(function(form) {
					var collection = form.querySelector('.ajcore-subscription-update-collection-method');
					var dueDays = form.querySelector('input[name="update_subscription_days_until_due"]');
					if (!collection || !dueDays) {
						return;
					}
					var syncDueDays = function() {
						var method = collection.value || 'send_invoice';
						form.setAttribute('data-collection-method', method);
						dueDays.disabled = method !== 'send_invoice';
					};
					collection.addEventListener('change', syncDueDays);
					syncDueDays();
				});
			})();
			</script>
		<?php endif; ?>
		<?php
	}

	private function render_portal_subscription_row_actions( $row ) {
		$subscription_id = ! empty( $row->stripe_subscription_id ) ? sanitize_text_field( (string) $row->stripe_subscription_id ) : '';
		$customer_id     = ! empty( $row->stripe_customer_id ) ? sanitize_text_field( (string) $row->stripe_customer_id ) : '';
		if ( '' === $subscription_id || '' === $customer_id ) {
			esc_html_e( '-', 'ajforms' );
			return;
		}

		$subscription_item_id = ! empty( $row->stripe_subscription_item_id ) ? sanitize_text_field( (string) $row->stripe_subscription_item_id ) : '';
		$current_price_id     = ! empty( $row->stripe_price_id ) ? sanitize_text_field( (string) $row->stripe_price_id ) : '';
		$current_quantity     = ! empty( $row->quantity ) ? max( 1, absint( $row->quantity ) ) : 1;
		$subscription         = $this->get_cached_portal_subscription_for_customer( $customer_id, $subscription_id );
		$raw                  = $subscription && ! empty( $subscription->raw_data ) ? json_decode( (string) $subscription->raw_data, true ) : array();
		$raw                  = is_array( $raw ) ? $raw : array();
		$collection_method    = ! empty( $raw['collection_method'] ) ? sanitize_key( (string) $raw['collection_method'] ) : 'send_invoice';
		$days_until_due       = ! empty( $raw['days_until_due'] ) ? absint( $raw['days_until_due'] ) : 30;
		$billing_start_date   = ! empty( $raw['billing_cycle_anchor'] ) && is_numeric( $raw['billing_cycle_anchor'] ) ? $this->format_portal_subscription_date_input_value( (int) $raw['billing_cycle_anchor'] ) : '';
		$products             = $this->api_get_ops_subscription_products();
		$product_price_ids    = array_map(
			function ( $product ) {
				return isset( $product->stripe_price_id ) ? sanitize_text_field( (string) $product->stripe_price_id ) : '';
			},
			(array) $products
		);
		?>
