	private function display_portal_users_tab() {
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_die( esc_html__( 'Insufficient permissions.', 'ajforms' ) );
		}

		global $wpdb;
		$pdb = $this->get_pdb();

		$status_filter = isset( $_GET['portal_user_status'] ) ? sanitize_key( wp_unslash( $_GET['portal_user_status'] ) ) : '';
		$allowed_status_filters = array( 'active', 'disabled', 'archived', 'without_login' );
		$status_filter = in_array( $status_filter, $allowed_status_filters, true ) ? $status_filter : '';
		$metric_filter = isset( $_GET['customer_metric'] ) ? sanitize_key( wp_unslash( $_GET['customer_metric'] ) ) : '';
		$product_counts = $this->get_portal_core_subscription_product_counts();

		// Build WHERE against stripe_customers only; without_login is applied in PHP after merging mapping data.
		$where = array( '1=1' );
		if ( 'active' === $status_filter ) {
			$where[] = "c.portal_status = 'active' AND c.enabled_portal = 1";
		} elseif ( 'disabled' === $status_filter ) {
			$where[] = "(c.portal_status = 'disabled' OR c.portal_status = 'without_portal_login' OR (c.enabled_portal = 0 AND (c.portal_status = '' OR c.portal_status IS NULL)))";
		} elseif ( 'archived' === $status_filter ) {
			$where[] = "c.portal_status = 'archived'";
		} elseif ( 'without_login' !== $status_filter ) {
			$where[] = "(c.portal_status IS NULL OR c.portal_status <> 'archived')";
		}

		// Step 1: Fetch stripe_customers from shared DB (or local in single-site mode).
		$customers_raw = $pdb->get_results(
			'SELECT c.* FROM ' . $this->get_portal_stripe_customers_table() . ' c
			WHERE ' . implode( ' AND ', $where ) . '
			ORDER BY c.enabled_portal DESC, c.name ASC, c.email ASC
			LIMIT 300'
		);
		$local_customers_table = $pdb->prefix . 'aj_portal_local_customers';
		if ( $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $local_customers_table ) ) === $local_customers_table ) {
			$local_where = array( '1=1' );
			if ( 'archived' === $status_filter ) {
				$local_where[] = "status = 'archived'";
			} elseif ( 'active' === $status_filter || 'disabled' === $status_filter ) {
				$local_where[] = '1=0'; // These filters describe portal access; local reporting customers have no login.
			} elseif ( 'without_login' !== $status_filter ) {
				$local_where[] = "status <> 'archived'";
			}
			$local_rows = $pdb->get_results( "SELECT id,local_customer_id AS stripe_customer_id,email,name,phone,description,address,metadata,partner_key,status AS portal_status,0 AS enabled_portal,0 AS livemode,created_at,updated_at AS synced_at FROM `{$local_customers_table}` WHERE " . implode( ' AND ', $local_where ) . ' ORDER BY name ASC,email ASC LIMIT 300' );
			$customers_raw = array_merge( (array) $customers_raw, (array) $local_rows );
		}

		// Step 2: Fetch user_mappings for these customers from local DB.
		$mappings_by_cid = array();
		if ( ! empty( $customers_raw ) ) {
			$cids         = array_column( (array) $customers_raw, 'stripe_customer_id' );
			$placeholders = implode( ', ', array_fill( 0, count( $cids ), '%s' ) );
			$mapping_rows = $wpdb->get_results(
				$wpdb->prepare(
					"SELECT m.*, u.ID AS user_exists FROM {$this->get_portal_user_mappings_table()} m
					LEFT JOIN {$wpdb->users} u ON u.ID = m.user_id
					WHERE m.stripe_customer_id IN ({$placeholders})",
					...$cids
				)
			);
			foreach ( (array) $mapping_rows as $mr ) {
				$mappings_by_cid[ $mr->stripe_customer_id ] = $mr;
			}
		}

		// Step 3: Merge mapping data and apply without_login filter in PHP.
		$customers = array();
		foreach ( (array) $customers_raw as $c ) {
			$mr                   = isset( $mappings_by_cid[ $c->stripe_customer_id ] ) ? $mappings_by_cid[ $c->stripe_customer_id ] : null;
			$c->user_id           = $mr ? $mr->user_id : null;
			$c->mapped_email      = $mr ? $mr->customer_email : null;
			$c->portal_user_email = $mr ? $mr->portal_user_email : null;
			$c->mapping_site_uuid = $mr ? $mr->site_uuid : null;
			$c->mapped_at         = $mr ? $mr->updated_at : null;
			if ( 'without_login' === $status_filter && $mr && ! empty( $mr->user_exists ) ) {
				continue;
			}
			$customers[] = $c;
		}
		if ( $metric_filter ) {
			$ra_ids  = array_flip( $product_counts['registered_agent_subscription_customers'] );
			$vo_ids  = array_flip( $product_counts['virtual_office_subscription_customers'] );
			$any_ids = array_flip( $product_counts['any_subscription_customers'] );
			$customers = array_values( array_filter( $customers, function ( $customer ) use ( $metric_filter, $ra_ids, $vo_ids, $any_ids ) {
				$customer_id = (string) $customer->stripe_customer_id;
				if ( 'ra' === $metric_filter ) { return isset( $ra_ids[ $customer_id ] ); }
				if ( 'vo' === $metric_filter ) { return isset( $vo_ids[ $customer_id ] ); }
				if ( 'none' === $metric_filter ) { return ! isset( $any_ids[ $customer_id ] ); }
				if ( 0 === strpos( $metric_filter, 'partner_' ) ) { return (string) $customer->partner_key === substr( $metric_filter, 8 ); }
				return true;
			} ) );
		}

		$local_total = $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $local_customers_table ) ) === $local_customers_table ? (int) $pdb->get_var( "SELECT COUNT(*) FROM `{$local_customers_table}`" ) : 0;
		$total_customers = (int) $pdb->get_var( 'SELECT COUNT(*) FROM ' . $this->get_portal_stripe_customers_table() ) + $local_total;
		$enabled_count   = (int) $pdb->get_var( "SELECT COUNT(*) FROM {$this->get_portal_stripe_customers_table()} WHERE portal_status = 'active' AND enabled_portal = 1" );
		$archived_count  = (int) $pdb->get_var( "SELECT COUNT(*) FROM {$this->get_portal_stripe_customers_table()} WHERE portal_status = 'archived'" );
		$non_archived_ids = (array) $pdb->get_col( "SELECT stripe_customer_id FROM {$this->get_portal_stripe_customers_table()} WHERE portal_status IS NULL OR portal_status <> 'archived'" );
		if ( $local_total ) $non_archived_ids = array_merge( $non_archived_ids, (array) $pdb->get_col( "SELECT local_customer_id FROM `{$local_customers_table}` WHERE status <> 'archived'" ) );
		$no_subscription_count = count( array_diff( $non_archived_ids, $product_counts['any_subscription_customers'] ) );
		$available_fields = $this->discover_portal_customer_scalar_fields( $customers );
		$display_fields   = array_values( array_intersect( $this->get_portal_customer_display_fields(), $available_fields ) );
		if ( empty( $display_fields ) && ! empty( $available_fields ) ) {
			$display_fields = array_slice( array_values( array_intersect( array( 'name', 'email', 'customer_details.name', 'customer_details.email', 'created', 'livemode' ), $available_fields ) ), 0, 6 );
		}
		?>
		<div class="ajforms-settings-card ajcore-customers-panel">
			<div class="ajcore-section-head"><div><h2><?php esc_html_e( 'Customers', 'ajforms' ); ?></h2><p><?php esc_html_e( 'Stripe customer records with portal access, WordPress user links, lifecycle status, and customer view shortcuts.', 'ajforms' ); ?></p></div><a class="button" href="<?php echo esc_url( add_query_arg( array( 'page' => 'ajforms-client-portal', 'tab' => 'sync' ), admin_url( 'admin.php' ) ) ); ?>"><?php esc_html_e( 'Open Sync Center', 'ajforms' ); ?></a></div>

			<?php if ( isset( $_GET['portal-user-enabled'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Stripe customer enabled for portal access.', 'ajforms' ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-user-disabled'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Customer portal access disabled.', 'ajforms' ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-user-archived'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Customer archived. Billing, requests, files, tasks, and history were kept.', 'ajforms' ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-users-deleted'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php echo esc_html( sprintf( __( 'Archived customer records deleted from the local cache: %1$d. Skipped: %2$d.', 'ajforms' ), absint( wp_unslash( $_GET['portal-users-deleted'] ) ), isset( $_GET['portal-bulk-skipped'] ) ? absint( wp_unslash( $_GET['portal-bulk-skipped'] ) ) : 0 ) ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-customer-created'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php echo esc_html( sprintf( __( 'Stripe customer created and synced: %s.', 'ajforms' ), sanitize_text_field( wp_unslash( $_GET['portal-customer-created'] ) ) ) ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-password-reset'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php esc_html_e( 'Password reset email sent.', 'ajforms' ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-bulk-updated'] ) ) : ?>
				<div class="notice notice-success is-dismissible"><p><?php echo esc_html( sprintf( __( 'Bulk action complete. Updated: %1$d. Skipped: %2$d.', 'ajforms' ), absint( wp_unslash( $_GET['portal-bulk-updated'] ) ), isset( $_GET['portal-bulk-skipped'] ) ? absint( wp_unslash( $_GET['portal-bulk-skipped'] ) ) : 0 ) ); ?></p></div>
			<?php endif; ?>
			<?php if ( isset( $_GET['portal-fields-updated'] ) ) : ?>
