		<script>
		(function($) {
			let frame;
			const attachmentInput = $('#ajforms-portal-attachment-id');
			const selectedFile = $('#ajforms-selected-portal-file');
			const titleInput = $('#portal_file_title');

			$('#ajforms-select-portal-file').on('click', function(event) {
				event.preventDefault();

				if (frame) {
					frame.open();
					return;
				}

				frame = wp.media({
					title: '<?php echo esc_js( __( 'Select File', 'ajforms' ) ); ?>',
					button: { text: '<?php echo esc_js( __( 'Use This File', 'ajforms' ) ); ?>' },
					multiple: false
				});

				frame.on('select', function() {
					const attachment = frame.state().get('selection').first().toJSON();
					attachmentInput.val(attachment.id || '');
					selectedFile.text(attachment.filename || attachment.title || attachment.url || '<?php echo esc_js( __( 'File selected.', 'ajforms' ) ); ?>');
					if (!titleInput.val() && attachment.title) {
						titleInput.val(attachment.title);
					}
				});

				frame.open();
			});

			$('#ajforms-clear-portal-file').on('click', function(event) {
				event.preventDefault();
				attachmentInput.val('');
				selectedFile.text('<?php echo esc_js( __( 'No file selected.', 'ajforms' ) ); ?>');
			});

			// Bulk checkbox logic
			const bulkBar    = $('#ajf-file-bulk-bar');
			const selCount   = $('#ajf-file-sel-count');
			const selectAll  = $('#ajf-select-all-files');

			function updateBulkBar() {
				const checked = $('.ajf-file-row-checkbox:checked');
				const n = checked.length;
				if (n > 0) {
					selCount.text(n + ' file' + (n === 1 ? '' : 's') + ' selected');
					bulkBar.css('display', 'flex');
				} else {
					bulkBar.hide();
				}
				selectAll.prop('indeterminate', n > 0 && n < $('.ajf-file-row-checkbox').length);
				selectAll.prop('checked', n > 0 && n === $('.ajf-file-row-checkbox').length);
			}

			selectAll.on('change', function() {
				$('.ajf-file-row-checkbox').prop('checked', $(this).is(':checked'));
				updateBulkBar();
			});

			$(document).on('change', '.ajf-file-row-checkbox', updateBulkBar);

			$('#ajf-file-deselect-all').on('click', function() {
				$('.ajf-file-row-checkbox, #ajf-select-all-files').prop('checked', false);
				bulkBar.hide();
				$('#ajf-file-storage-paths').hide().empty();
			});

			$('#ajf-file-show-storage-path').on('click', function() {
				const panel = $('#ajf-file-storage-paths').empty();
				$('.ajf-file-row-checkbox:checked').each(function() {
					const row = $('<div>').css({marginBottom:'10px'});
					$('<strong>').text($(this).data('file-title') + ' — ' + $(this).data('storage-type')).appendTo(row);
					$('<code>').text($(this).attr('data-storage-path') || '<?php echo esc_js( __( 'Path unavailable', 'ajforms' ) ); ?>').css({display:'block',marginTop:'4px',padding:'7px 9px',background:'#fff',border:'1px solid #e2e8f0',borderRadius:'6px',whiteSpace:'pre-wrap',overflowWrap:'anywhere',userSelect:'all'}).appendTo(row);
					panel.append(row);
				});
				panel.show();
			});
		})(jQuery);
		</script>
		<?php
	}

