		<script>
		(function() {
			// Multi-Site Portal toggle.
			var msToggleBtn = document.getElementById('ajcore-toggle-multisite');
			if ( msToggleBtn ) {
				msToggleBtn.addEventListener('click', function() {
					var resultEl = document.getElementById('ajcore-ms-toggle-result');
					msToggleBtn.disabled = true;
					resultEl.style.display = 'block';
					resultEl.style.color = '';
					resultEl.textContent = '<?php echo esc_js( __( 'Saving…', 'ajforms' ) ); ?>';

					var data = new FormData();
					data.append('action', 'ajcore_toggle_multisite_portal');
					data.append('nonce',  '<?php echo esc_js( wp_create_nonce( 'ajcore_toggle_multisite_portal' ) ); ?>');

					fetch(ajaxurl, { method: 'POST', body: data })
						.then(function(r) { return r.json(); })
						.then(function(res) {
							if (res.success) {
								resultEl.textContent = res.data.message || '<?php echo esc_js( __( 'Saved.', 'ajforms' ) ); ?>';
								resultEl.style.color = '#166534';
								setTimeout(function() { location.reload(); }, 800);
							} else {
								resultEl.textContent = res.data || '<?php echo esc_js( __( 'Failed.', 'ajforms' ) ); ?>';
								resultEl.style.color = '#991b1b';
								msToggleBtn.disabled = false;
							}
						})
						.catch(function() {
							resultEl.textContent = '<?php echo esc_js( __( 'Request failed.', 'ajforms' ) ); ?>';
							resultEl.style.color = '#991b1b';
							msToggleBtn.disabled = false;
						});
				});
			}

			var btn = document.getElementById('ajcore-test-shared-db');
			if ( ! btn ) return;
			btn.addEventListener('click', function() {
				var resultEl = document.getElementById('ajcore-shared-db-test-result');
				var form     = btn.closest('form');
				function val(n) { var el = form.querySelector('[name="' + n + '"]'); return el ? el.value : ''; }

				btn.disabled = true;
				resultEl.textContent = '<?php echo esc_js( __( 'Testing…', 'ajforms' ) ); ?>';
				resultEl.style.color = '';

				var data = new FormData();
				data.append('action',   'ajcore_test_shared_db');
				data.append('nonce',    '<?php echo esc_js( wp_create_nonce( 'ajcore_test_shared_db' ) ); ?>');
				data.append('host',     val('shared_db_host'));
				data.append('name',     val('shared_db_name'));
				data.append('user',     val('shared_db_user'));
				data.append('password', val('shared_db_password'));
				data.append('prefix',   val('shared_db_prefix'));

				fetch(ajaxurl, { method: 'POST', body: data })
					.then(function(r) { return r.json(); })
					.then(function(res) {
						resultEl.textContent = res.data || ( res.success
							? '<?php echo esc_js( __( 'Connected successfully.', 'ajforms' ) ); ?>'
							: '<?php echo esc_js( __( 'Connection failed.', 'ajforms' ) ); ?>' );
						resultEl.style.color = res.success ? '#166534' : '#991b1b';
					})
					.catch(function() {
						resultEl.textContent = '<?php echo esc_js( __( 'Request failed.', 'ajforms' ) ); ?>';
						resultEl.style.color = '#991b1b';
					})
					.finally(function() { btn.disabled = false; });
			});

			function ajcoreMigrationRequest( btnId, direction, confirmMsg ) {
				var triggerBtn = document.getElementById( btnId );
				if ( ! triggerBtn ) return;
				triggerBtn.addEventListener( 'click', function() {
					if ( ! confirm( confirmMsg ) ) return;
					var resultEl = document.getElementById( 'ajcore-migration-result' );
					triggerBtn.disabled = true;
					resultEl.textContent = '<?php echo esc_js( __( 'Working…', 'ajforms' ) ); ?>';
					resultEl.style.color = '';

					var data = new FormData();
					data.append( 'action',    direction ? 'ajcore_migrate_portal_data' : 'ajcore_init_shared_db_schema' );
					data.append( 'nonce',     direction ? '<?php echo esc_js( wp_create_nonce( 'ajcore_migrate_portal_data' ) ); ?>' : '<?php echo esc_js( wp_create_nonce( 'ajcore_init_shared_schema' ) ); ?>' );
					if ( direction ) data.append( 'direction', direction );

					fetch( ajaxurl, { method: 'POST', body: data } )
						.then( function(r) { return r.json(); } )
						.then( function(res) {
							if ( res.success ) {
								resultEl.textContent = ( res.data && res.data.message ) ? res.data.message : res.data;
								resultEl.style.color = '#166534';
								if ( res.data && res.data.errors && res.data.errors.length ) {
									resultEl.textContent += ' (' + res.data.errors.join( '; ' ) + ')';
								}
							} else {
								resultEl.textContent = res.data || '<?php echo esc_js( __( 'Failed.', 'ajforms' ) ); ?>';
								resultEl.style.color = '#991b1b';
							}
						} )
						.catch( function() {
							resultEl.textContent = '<?php echo esc_js( __( 'Request failed.', 'ajforms' ) ); ?>';
							resultEl.style.color = '#991b1b';
						} )
						.finally( function() { triggerBtn.disabled = false; } );
				} );
			}

			ajcoreMigrationRequest(
				'ajcore-init-shared-schema',
				'',
				'<?php echo esc_js( __( 'Create the 19 shared portal tables (including the control table) in the shared DB? Existing data will not be changed.', 'ajforms' ) ); ?>'
			);
			ajcoreMigrationRequest(
				'ajcore-migrate-local-to-shared',
				'local_to_shared',
				'<?php echo esc_js( __( 'Copy all local portal data to the shared DB? This will REPLACE all current shared DB data.', 'ajforms' ) ); ?>'
			);
			ajcoreMigrationRequest(
				'ajcore-migrate-shared-to-local',
				'shared_to_local',
				'<?php echo esc_js( __( 'Copy shared DB portal data to this local DB? This will REPLACE your local portal data.', 'ajforms' ) ); ?>'
			);
		// Set as Master buttons.
		document.querySelectorAll('.ajcore-set-master-btn').forEach(function(masterBtn) {
			masterBtn.addEventListener('click', function() {
				var uuid   = masterBtn.dataset.uuid;
				var domain = masterBtn.dataset.domain;
				if ( ! confirm( '<?php echo esc_js( __( 'Set', 'ajforms' ) ); ?> ' + domain + ' <?php echo esc_js( __( 'as the Stripe Sync Master? All other sites will become read-only for sync.', 'ajforms' ) ); ?>' ) ) return;

				masterBtn.disabled = true;
				var data = new FormData();
				data.append('action',    'ajcore_set_shared_db_master');
				data.append('nonce',     '<?php echo esc_js( wp_create_nonce( 'ajcore_set_shared_master' ) ); ?>');
				data.append('site_uuid', uuid);

				fetch(ajaxurl, { method: 'POST', body: data })
					.then(function(r) { return r.json(); })
					.then(function(res) {
						if (res.success) { location.reload(); }
						else {
							alert(res.data || '<?php echo esc_js( __( 'Failed.', 'ajforms' ) ); ?>');
							masterBtn.disabled = false;
						}
					})
					.catch(function() { masterBtn.disabled = false; });
			});
		});

		})();
		</script>
		<?php
	}

	/** The base table names that belong in the shared DB. */
	private function get_shared_portal_table_bases() {
		return array(
			'aj_portal_stripe_customers',
			'aj_portal_customer_states',
			'aj_portal_stripe_products',
			'aj_portal_product_catalog',
			'aj_portal_stripe_subscriptions',
			'aj_portal_stripe_transactions',
			'aj_portal_service_snapshots',
			'aj_portal_service_states',
			'aj_portal_entity_mappings',
			'aj_portal_tasks',
			'aj_portal_task_statuses',
			'aj_portal_task_comments',
			'aj_portal_compliance_entities',
			'aj_portal_compliance_filings',
			'aj_portal_sync_logs',
			'aj_portal_sync_log_items',
			'aj_portal_ledger',
			'aj_portal_service_requests',
			'aj_portal_event_log',
			'aj_portal_stripe_events',
			'aj_forms_leads',
			'aj_forms_lead_notes',
		);
	}

	public function ajax_init_shared_db_schema() {
		check_ajax_referer( 'ajcore_init_shared_schema', 'nonce' );
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_send_json_error( __( 'Insufficient permissions.', 'ajforms' ) );
		}

		$shared_db = function_exists( 'ajcore_get_shared_db' ) ? ajcore_get_shared_db() : null;
		if ( ! $shared_db ) {
			wp_send_json_error( __( 'Shared DB is not connected. Save and test your credentials first.', 'ajforms' ) );
		}

		require_once AJFORMS_PLUGIN_DIR . 'includes/class-ajforms-activator.php';
		require_once ABSPATH . 'wp-admin/includes/upgrade.php';

		$charset_collate = $shared_db->get_charset_collate();
		$sql             = AJForms_Activator::get_shared_portal_table_sql( $shared_db->prefix, $charset_collate );

		// Temporarily swap global $wpdb so dbDelta writes to the shared DB.
		global $wpdb;
		$original_wpdb = $wpdb;
		$wpdb          = $shared_db;
		dbDelta( $sql );
		$wpdb = $original_wpdb;

		// Report what's now in the shared DB.
		$found = array();
		foreach ( $this->get_shared_portal_table_bases() as $base ) {
			$tbl = $shared_db->prefix . $base;
			if ( $shared_db->get_var( $shared_db->prepare( 'SHOW TABLES LIKE %s', $tbl ) ) === $tbl ) {
				$found[] = $base;
			}
		}

		wp_send_json_success(
			sprintf(
				__( 'Schema ready. %d of 22 shared tables exist in the shared DB.', 'ajforms' ),
				count( $found )
			)
		);
	}

	public function ajax_migrate_portal_data() {
		check_ajax_referer( 'ajcore_migrate_portal_data', 'nonce' );
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_send_json_error( __( 'Insufficient permissions.', 'ajforms' ) );
		}

		$direction = isset( $_POST['direction'] ) ? sanitize_key( wp_unslash( $_POST['direction'] ) ) : '';
		if ( ! in_array( $direction, array( 'local_to_shared', 'shared_to_local' ), true ) ) {
			wp_send_json_error( __( 'Invalid direction.', 'ajforms' ) );
		}

		$shared_db = function_exists( 'ajcore_get_shared_db' ) ? ajcore_get_shared_db() : null;
		if ( ! $shared_db ) {
			wp_send_json_error( __( 'Shared DB is not connected. Save and test your credentials first.', 'ajforms' ) );
		}

		global $wpdb;

		if ( 'local_to_shared' === $direction ) {
			$src_db     = $wpdb;
			$dst_db     = $shared_db;
		} else {
			$src_db     = $shared_db;
			$dst_db     = $wpdb;
		}

		$results = array();
		$errors  = array();

		foreach ( $this->get_shared_portal_table_bases() as $base ) {
			$src_table = $src_db->prefix . $base;
			$dst_table = $dst_db->prefix . $base;

			// Skip if source table doesn't exist.
			if ( $src_db->get_var( $src_db->prepare( 'SHOW TABLES LIKE %s', $src_table ) ) !== $src_table ) {
				$errors[] = $base . ': source table not found';
				continue;
			}
			// Skip if destination table doesn't exist.
			if ( $dst_db->get_var( $dst_db->prepare( 'SHOW TABLES LIKE %s', $dst_table ) ) !== $dst_table ) {
				$errors[] = $base . ': destination table not found (run Initialize Schema first)';
				continue;
			}

			$dst_db->query( "TRUNCATE TABLE `{$dst_table}`" );

			$rows  = $src_db->get_results( "SELECT * FROM `{$src_table}`", ARRAY_A );
			$count = 0;
			foreach ( $rows as $row ) {
				if ( false !== $dst_db->insert( $dst_table, $row ) ) {
					$count++;
				}
			}
			$results[ $base ] = $count;
		}

		$total   = array_sum( $results );
		$message = sprintf(
			'local_to_shared' === $direction
				? __( 'Copied %d rows across %d tables from local → shared DB.', 'ajforms' )
				: __( 'Copied %d rows across %d tables from shared → local DB.', 'ajforms' ),
			$total,
			count( $results )
		);

		wp_send_json_success( array( 'message' => $message, 'tables' => $results, 'errors' => $errors ) );
	}

	public function ajax_set_shared_db_master() {
		check_ajax_referer( 'ajcore_set_shared_master', 'nonce' );
		if ( ! current_user_can( 'manage_options' ) ) {
			wp_send_json_error( __( 'Insufficient permissions.', 'ajforms' ) );
			return;
		}

		$target_uuid = isset( $_POST['site_uuid'] ) ? sanitize_text_field( wp_unslash( $_POST['site_uuid'] ) ) : '';
		if ( '' === $target_uuid ) {
			wp_send_json_error( __( 'Site UUID is required.', 'ajforms' ) );
			return;
		}

		$shared_db = function_exists( 'ajcore_get_shared_db' ) ? ajcore_get_shared_db() : null;
		if ( ! $shared_db ) {
			wp_send_json_error( __( 'Shared DB is not connected.', 'ajforms' ) );
			return;
		}

		$is_master = function_exists( 'ajcore_is_stripe_sync_owner' ) && ajcore_is_stripe_sync_owner();
		if ( ! $is_master ) {
			// Allow action when no site is currently master (recovery from orphaned state).
			$sites_table  = $shared_db->prefix . 'aj_shared_sites';
			$any_master   = (int) $shared_db->get_var( "SELECT COUNT(*) FROM `{$sites_table}` WHERE is_master = 1" );
			if ( $any_master > 0 ) {
				wp_send_json_error( __( 'Only the current Master site can reassign master designation.', 'ajforms' ), 403 );
				return;
			}
		}

		$table = $shared_db->prefix . 'aj_shared_sites';
		$shared_db->query( "UPDATE `{$table}` SET is_master = 0" );
		$shared_db->update( $table, array( 'is_master' => 1 ), array( 'site_uuid' => $target_uuid ), array( '%d' ), array( '%s' ) );

		wp_send_json_success( __( 'Master updated.', 'ajforms' ) );
	}

	public function ajax_toggle_multisite_portal() {
		check_ajax_referer( 'ajcore_toggle_multisite_portal', 'nonce' );

		if ( ! current_user_can( 'manage_options' ) ) {
			wp_send_json_error( __( 'Insufficient permissions.', 'ajforms' ), 403 );
			return;
		}

		if ( defined( 'AJCORE_MULTISITE_PORTAL_ENABLED' ) ) {
			wp_send_json_error( __( 'This setting is locked by the AJCORE_MULTISITE_PORTAL_ENABLED constant.', 'ajforms' ) );
			return;
		}

		$existing   = get_option( 'ajcore_shared_db_settings', array() );
		$existing   = is_array( $existing ) ? $existing : array();
		$new_state  = empty( $existing['ms_enabled'] ) ? 1 : 0;

		$existing['ms_enabled'] = $new_state;
		update_option( 'ajcore_shared_db_settings', $existing, false );

		if ( $new_state && function_exists( 'ajcore_register_site_in_shared_db' ) ) {
			ajcore_register_site_in_shared_db();
		}

		wp_send_json_success( array(
			'ms_enabled' => $new_state,
			'message'    => $new_state
				? __( 'Multi-Site Portal enabled. Portal reads and writes now route through the shared database.', 'ajforms' )
				: __( 'Multi-Site Portal disabled. Portal data will use the local database.', 'ajforms' ),
		) );
	}

	public function ajax_test_shared_db_connection() {
		check_ajax_referer( 'ajcore_test_shared_db', 'nonce' );

		if ( ! current_user_can( 'manage_options' ) ) {
			wp_send_json_error( __( 'Insufficient permissions.', 'ajforms' ) );
		}

		$host   = isset( $_POST['host'] )   ? sanitize_text_field( wp_unslash( $_POST['host'] ) )   : '';
		$name   = isset( $_POST['name'] )   ? sanitize_text_field( wp_unslash( $_POST['name'] ) )   : '';
		$user   = isset( $_POST['user'] )   ? sanitize_text_field( wp_unslash( $_POST['user'] ) )   : '';
		$pass   = isset( $_POST['password'] ) ? (string) wp_unslash( $_POST['password'] )           : '';

		// Fall back to saved/constant password if left blank.
		if ( '' === $pass ) {
			if ( defined( 'AJCORE_SHARED_DB_PASSWORD' ) ) {
				$pass = (string) AJCORE_SHARED_DB_PASSWORD;
			} else {
				$saved = get_option( 'ajcore_shared_db_settings', array() );
				$pass  = ! empty( $saved['password'] ) ? (string) $saved['password'] : '';
			}
		}

		// Use constant values when fields are locked.
		if ( defined( 'AJCORE_SHARED_DB_HOST' ) ) { $host = (string) AJCORE_SHARED_DB_HOST; }
		if ( defined( 'AJCORE_SHARED_DB_NAME' ) ) { $name = (string) AJCORE_SHARED_DB_NAME; }
		if ( defined( 'AJCORE_SHARED_DB_USER' ) ) { $user = (string) AJCORE_SHARED_DB_USER; }

		if ( '' === $host || '' === $name || '' === $user ) {
			wp_send_json_error( __( 'Host, name, and user are required.', 'ajforms' ) );
		}

		if ( ! function_exists( 'mysqli_connect' ) ) {
			wp_send_json_error( __( 'The mysqli PHP extension is not available on this server.', 'ajforms' ) );
		}

		// Parse optional port from "hostname:port" format (wpdb handles this natively;
		// mysqli_connect requires it as a separate argument).
		$port = 3306;
		if ( strpos( $host, ':' ) !== false ) {
			$parts = explode( ':', $host, 2 );
			$host  = $parts[0];
			$port  = (int) $parts[1];
		}

		// phpcs:ignore WordPress.DB.RestrictedFunctions.mysql_mysqli_connect
		$conn = @mysqli_connect( $host, $user, $pass, $name, $port );
		$err  = $conn ? '' : (string) mysqli_connect_error();

		// "localhost" with default port triggers a Unix socket attempt. When that
		// fails, retry with 127.0.0.1 to force TCP.
		if ( ! $conn && 'localhost' === $host && 3306 === $port ) {
			$conn = @mysqli_connect( '127.0.0.1', $user, $pass, $name, 3306 ); // phpcs:ignore
			if ( $conn ) {
				$err = '';
			}
		}

		if ( ! $conn ) {
			$hint = '';
			if ( false !== strpos( $err, 'No such file or directory' ) || false !== strpos( $err, 'Can\'t connect' ) ) {
				$hint = ' ' . __( 'Tip: "localhost" uses a Unix socket. Try your actual hostname, IP address, or — in DDEV — use "db" as the host.', 'ajforms' );
			}
			wp_send_json_error( ( $err ?: __( 'Could not connect to the specified database.', 'ajforms' ) ) . $hint );
		}

		mysqli_close( $conn );
		wp_send_json_success( __( 'Connection successful.', 'ajforms' ) );
	}

