	private function handle_portal_calendar_settings_save() {
		if ( ! current_user_can( 'manage_options' ) ) {
			return;
		}

		if ( ! isset( $_POST['ajcore_calendar_settings_nonce'] ) ) {
			return;
		}

		check_admin_referer( 'ajcore_save_calendar_settings', 'ajcore_calendar_settings_nonce' );

		$ms_enabled = function_exists( 'ajcore_is_multisite_portal_enabled' ) && ajcore_is_multisite_portal_enabled();
		$is_master  = ! $ms_enabled || ( function_exists( 'ajcore_is_stripe_sync_owner' ) && ajcore_is_stripe_sync_owner() );
		if ( ! $is_master ) {
			wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-cp-settings', 'cp_section' => 'calendar' ), admin_url( 'admin.php' ) ) );
			exit;
		}

		$settings = $this->get_plugin_settings();

		$settings['zoho_reservations_enabled']        = ! empty( $_POST['zoho_reservations_enabled'] ) ? '1' : '0';
		$settings['zoho_default_timezone']            = isset( $_POST['zoho_default_timezone'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_default_timezone'] ) ) : 'America/New_York';
		$settings['reservation_resource_name']        = isset( $_POST['reservation_resource_name'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_resource_name'] ) ) : 'Conference Room';
		$settings['reservation_resource_key']         = isset( $_POST['reservation_resource_key'] ) ? sanitize_key( wp_unslash( $_POST['reservation_resource_key'] ) ) : 'conference_room';
		$settings['reservation_menu_label']           = isset( $_POST['reservation_menu_label'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_menu_label'] ) ) : 'Conference Room';
		$settings['reservation_business_hours_label'] = isset( $_POST['reservation_business_hours_label'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_business_hours_label'] ) ) : 'Business Hours (Mon–Fri 9am–5pm)';
		$settings['reservation_after_hours_label']    = isset( $_POST['reservation_after_hours_label'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_after_hours_label'] ) ) : 'After-Hours / Weekend';
		$settings['reservation_business_hours_rate']     = isset( $_POST['reservation_business_hours_rate'] ) ? max( 1, absint( wp_unslash( $_POST['reservation_business_hours_rate'] ) ) ) : 40;
		$settings['reservation_after_hours_rate']        = isset( $_POST['reservation_after_hours_rate'] ) ? max( 1, absint( wp_unslash( $_POST['reservation_after_hours_rate'] ) ) ) : 80;
		$settings['reservation_business_hours_price_id'] = isset( $_POST['reservation_business_hours_price_id'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_business_hours_price_id'] ) ) : ( $settings['reservation_business_hours_price_id'] ?? '' );
		$settings['reservation_after_hours_price_id']    = isset( $_POST['reservation_after_hours_price_id'] ) ? sanitize_text_field( wp_unslash( $_POST['reservation_after_hours_price_id'] ) ) : ( $settings['reservation_after_hours_price_id'] ?? '' );
		$settings['zoho_schedule_appointment_url']    = isset( $_POST['zoho_schedule_appointment_url'] ) ? esc_url_raw( wp_unslash( $_POST['zoho_schedule_appointment_url'] ) ) : '';
		$settings['zoho_calendar_uid']                = isset( $_POST['zoho_calendar_uid'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_calendar_uid'] ) ) : '';
		$settings['zoho_calendar_id']                 = isset( $_POST['zoho_calendar_id'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_calendar_id'] ) ) : '';
		$settings['zoho_calendar_embed_url']          = isset( $_POST['zoho_calendar_embed_url'] ) ? esc_url_raw( wp_unslash( $_POST['zoho_calendar_embed_url'] ) ) : '';
		// ── Zoho OAuth credentials (editable in the form) ─────────────────────
		$_submitted_client_id = isset( $_POST['zoho_client_id'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_client_id'] ) )
			: ( isset( $_POST['zoho_oauth_client_id'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_oauth_client_id'] ) ) : '' );
		$_submitted_secret    = isset( $_POST['zoho_client_secret'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_client_secret'] ) )
			: ( isset( $_POST['zoho_oauth_client_secret'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_oauth_client_secret'] ) ) : '' );

		$settings['zoho_client_id']           = '' !== $_submitted_client_id ? $_submitted_client_id : ( $settings['zoho_client_id'] ?? $settings['zoho_oauth_client_id'] ?? '' );
		$settings['zoho_client_secret']       = '' !== $_submitted_secret    ? $_submitted_secret    : ( $settings['zoho_client_secret'] ?? $settings['zoho_oauth_client_secret'] ?? '' );
		$settings['zoho_availability_source'] = isset( $_POST['zoho_availability_source'] )
			? sanitize_key( wp_unslash( $_POST['zoho_availability_source'] ) ) : ( $settings['zoho_availability_source'] ?? 'calendar_events' );

		$_submitted_failure_mode = isset( $_POST['zoho_availability_failure_mode'] ) ? sanitize_key( wp_unslash( $_POST['zoho_availability_failure_mode'] ) ) : '';
		$settings['zoho_availability_failure_mode'] = in_array( $_submitted_failure_mode, array( 'strict', 'lenient' ), true )
			? $_submitted_failure_mode : ( $settings['zoho_availability_failure_mode'] ?? 'strict' );

		// ── Zoho OAuth tokens — managed exclusively by AJAX, never from form POST ──
		// Migrate old key names to new ones on first save; preserve if already set.
		$settings['zoho_refresh_token']    = $settings['zoho_refresh_token']    ?? '';
		$settings['zoho_access_token']     = $settings['zoho_access_token']     ?? ( $settings['zoho_api_token'] ?? '' );
		$settings['zoho_token_expires_at'] = $settings['zoho_token_expires_at'] ?? ( $settings['zoho_api_token_expires_at'] ?? '' );
		$settings['zoho_api_domain']       = $settings['zoho_api_domain']       ?? ( $settings['zoho_oauth_api_domain'] ?? '' );

		// Backward-compat aliases so older code paths still work without changes.
		$settings['zoho_oauth_client_id']      = $settings['zoho_client_id'];
		$settings['zoho_oauth_client_secret']  = $settings['zoho_client_secret'];
		$settings['zoho_api_token']            = $settings['zoho_access_token'];
		$settings['zoho_api_token_expires_at'] = $settings['zoho_token_expires_at'];
		$settings['zoho_oauth_api_domain']     = $settings['zoho_api_domain'];
		unset( $settings['zoho_oauth_authorization_code'] );
		$settings['zoho_resource_uid']                = isset( $_POST['zoho_resource_uid'] ) ? sanitize_text_field( wp_unslash( $_POST['zoho_resource_uid'] ) ) : '';
		$settings['zoho_resource_freebusy_url']       = isset( $_POST['zoho_resource_freebusy_url'] ) && '' !== trim( (string) wp_unslash( $_POST['zoho_resource_freebusy_url'] ) )
			? sanitize_text_field( wp_unslash( $_POST['zoho_resource_freebusy_url'] ) )
			: 'https://calendar.zoho.com/api/v1/resources/{resourceuid}/freebusy';
		// Preserve auth mode for compatibility with older installs.
		if ( ! isset( $settings['zoho_api_auth_mode'] ) )       { $settings['zoho_api_auth_mode']       = 'bearer_token'; }

		update_option( 'ajforms_settings', $settings, false );

		if ( function_exists( 'ajcore_write_shared_calendar_settings' ) ) {
			ajcore_write_shared_calendar_settings( $settings );
		}

		$this->upsert_reservation_resource_from_settings( $settings );

		$this->log_portal_event(
			'calendar_settings_updated',
			array(
				'source'                   => 'calendar_settings',
				'zoho_reservations_enabled' => $settings['zoho_reservations_enabled'],
				'reservation_resource_key'  => $settings['reservation_resource_key'],
			)
		);

		wp_safe_redirect( add_query_arg( array( 'page' => 'ajforms-cp-settings', 'cp_section' => 'calendar', 'calendar-settings-saved' => '1' ), admin_url( 'admin.php' ) ) );
		exit;
	}

	private function upsert_reservation_resource_from_settings( $settings ) {
		if ( ! class_exists( 'AJCore_Reservations' ) ) {
			return;
		}
		$resource_key = sanitize_key( (string) ( $settings['reservation_resource_key'] ?? 'conference_room' ) );
		if ( '' === $resource_key ) {
			return;
		}

		$pdb   = AJCore_Reservations::get_pdb();
		$table = AJCore_Reservations::get_resources_table();

		if ( $pdb->get_var( $pdb->prepare( 'SHOW TABLES LIKE %s', $table ) ) !== $table ) {
			return;
		}

		$data = array(
			'resource_name'           => sanitize_text_field( (string) ( $settings['reservation_resource_name'] ?? 'Conference Room' ) ),
			'zoho_calendar_uid'       => sanitize_text_field( (string) ( $settings['zoho_calendar_uid'] ?? '' ) ),
			'zoho_calendar_id'        => sanitize_text_field( (string) ( $settings['zoho_calendar_id'] ?? '' ) ),
			'zoho_resource_uid'       => sanitize_text_field( (string) ( $settings['zoho_resource_uid'] ?? '' ) ),
			'zoho_schedule_url'       => sanitize_text_field( (string) ( $settings['zoho_schedule_appointment_url'] ?? '' ) ),
			'zoho_freebusy_url'       => sanitize_text_field( (string) ( $settings['zoho_resource_freebusy_url'] ?? '' ) ),
			'business_hours_price_id' => sanitize_text_field( (string) ( $settings['reservation_business_hours_price_id'] ?? '' ) ),
			'after_hours_price_id'    => sanitize_text_field( (string) ( $settings['reservation_after_hours_price_id'] ?? '' ) ),
			'active'                  => 1,
			'updated_at'              => current_time( 'mysql' ),
		);

		$existing_id = $pdb->get_var( $pdb->prepare( "SELECT id FROM `{$table}` WHERE resource_key = %s LIMIT 1", $resource_key ) );

		if ( $existing_id ) {
			$pdb->update( $table, $data, array( 'resource_key' => $resource_key ) );
		} else {
			$data['resource_key'] = $resource_key;
			$data['created_at']   = current_time( 'mysql' );
			$pdb->insert( $table, $data );
		}
	}

